#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, but n >= 2) and preserves the set of adjacent sums.
    // The sums for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The sums for p_reversed are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These are the same set of sums, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // Since n >= 2, p and p_reversed are different unless p is a palindrome.
    // However, the problem asks for *any* different permutation with the same fingerprint.
    // Reversing the permutation is a simple and effective strategy.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

