#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long min_val = a[0];
    long long operations = 0;

    // We can only add a[0] to other piles.
    // For each other pile a[j] (j > 0), we can add a[0] to it
    // as many times as possible without exceeding k.
    for (int j = 1; j < n; ++j) {
        // The current pile is a[j]. We want to add min_val to it.
        // Each addition increases a[j] by min_val.
        // The maximum value a[j] can reach is k.
        // So, a[j] + count * min_val <= k
        // count * min_val <= k - a[j]
        // count <= (k - a[j]) / min_val
        // Since count must be an integer, count = floor((k - a[j]) / min_val)

        if (min_val == 0) { // Should not happen based on constraints (a_i >= 1)
            // If min_val is 0, we can add it infinitely without changing other piles.
            // But problem constraints say a_i >= 1.
            // If it could be 0, this would be an infinite loop or special case.
            // Given a_i >= 1, min_val >= 1.
        } else {
            operations += (k - a[j]) / min_val;
        }
    }

    std::cout << operations << std::endl;
}

