        diff %= 5;

        // Remaining diff is 0, 1, 2, 3, 4
        if (diff == 0) {
            // No additional presses needed
        } else if (diff == 1) {
            // Can be 1 (+1) or 2 (-2, +1, +1) or 2 (-5, +2, +2)
            // Optimal for 1 is 1 press (+1 or -1)
            count += 1;
        } else if (diff == 2) {
            // Optimal for 2 is 1 press (+2 or -2)
