            // Optimal for 3 is 2 presses (+1, +2 or -2, -1)
            // Can be 3 (+1, +1, +1) or 2 (+5, -2)
            count += 2;
        } else if (diff == 4) {
            // Optimal for 4 is 2 presses (+2, +2 or -1, -1, -1, -1)
