void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i; // 0-indexed pile_idx
        long long distance = pile_idx; // days to move one haybale to pile 0

        if (d <= 0) {
            break; // No more days left
        }

        if (a[i] == 0) {
            continue; // No haybales in this pile
        }

        // Calculate how many haybales can be moved from pile i to pile 0
        // Each haybale costs 'distance' days.
        // We have 'd' days remaining.
        long long max_haybales_from_this_pile = d / distance;

        long long haybales_to_move = std::min(a[i], max_haybales_from_this_pile);

        current_a1 += haybales_to_move;
        d -= haybales_to_move * distance;
    }

    std::cout << current_a1 << std::endl;
}

