    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_positive_balance = 0;
        long long coins_spent = 0;
        for (int i = 0; i < n; ++i) {
            long long val;
            std::cin >> val;
            if (val > 0) {
                current_positive_balance += val;
            } else { // val <= 0
                // We need to fulfill -val units.
                // We can use current_positive_balance for free operations (i < j).
                // If -val is greater than current_positive_balance,
                // the remaining deficit must be fulfilled by elements to the left (i > j),
                // which costs coins.
                long long deficit = -val;
                if (deficit > current_positive_balance) {
                    coins_spent += (deficit - current_positive_balance);
                    current_positive_balance = 0; // All positive balance used up
                } else {
                    current_positive_balance -= deficit; // Use positive balance to cover deficit
                }
            }
        }
        std::cout << coins_spent << "\n";
    }
    return 0;
}

