#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number that satisfies the conditions.
        // A common strategy is to use digits that are not 2, 3, 5, 7, 9
        // or to make the number not divisible by small primes.
        //
        // Consider the number starting with '2' and ending with '3',
        // and filling the middle with '4's.
        // Example: 24...43
        //
        // Digits used: 2, 3, 4. None are 0.
        //
        // Divisibility checks:
        // - By 2: The number ends in 3, so it's not divisible by 2.
        // - By 3: The sum of digits is 2 + (n-2)*4 + 3 = 5 + 4n - 8 = 4n - 3.
        //   If 4n - 3 is divisible by 3, then 4n is divisible by 3. Since 4 and 3 are coprime,
        //   n must be divisible by 3.
        //   If n is divisible by 3, then 4n - 3 is divisible by 3.
        //   In this case, we need a different construction.
        //
        // Let's try a simpler construction:
        // Start with '2' and fill the rest with '3's.
        // Example: 233...3
        // Digits: 2, 3. None are 0.
        //
        // Divisibility checks:
        // - By 2: Ends in 3, so not divisible by 2.
        // - By 3: Sum of digits = 2 + (n-1)*3.
        //   This sum is always divisible by 3 (since 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1).
        //   Wait, 3n - 1 is NOT always divisible by 3.
        //   3n - 1 % 3 = -1 % 3 = 2. So it's never divisible by 3.
        //   This construction works!
        //
        // So, for n >= 2, print '2' followed by (n-1) '3's.
        //
        // Let's double check the example n=2: 23.
        // Digits: 2, 3.
        // 23 % 2 != 0
        // 23 % 3 != 0
        // This works.
        //
        // Example n=3: 233.
        // Digits: 2, 3.
        // 233 % 2 != 0
        // 233 % 3 != 0 (2+3+3 = 8, 8%3 != 0)
        // This works.
        //
        // This construction seems robust for all n >= 2.
        // The problem asks for *any* such integer.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

