    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    int color_for_half_T = 0; // Alternates between 0 and 1 for elements equal to T/2

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (2 * a[i] < T) {
            p[i] = 0; // Smaller than T/2, assign to color 0
        } else if (2 * a[i] > T) {
            p[i] = 1; // Larger than T/2, assign to color 1
        } else { // 2 * a[i] == T, i.e., a[i] == T/2
            p[i] = color_for_half_T;
            color_for_half_T = 1 - color_for_half_T; // Alternate color for next T/2 element
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

