int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = 0; // Represents the position of the last 'R' or the starting point 0.
                            // The frog can always jump from 0.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at index i (cell i+1),
                // the gap between this 'R' and the previous 'R' (or 0) is (i+1) - last_R_pos.
                // The frog must be able to jump this distance.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current cell (i+1)
            }
        }

        // After iterating through the string, we need to consider the gap
        // from the last 'R' (or 0 if no 'R's) to the target n+1.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last element

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        // If the current price is greater than the minimum price found so far in the suffix
        // then it's a bad price.
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If the current price is not greater than min_suffix_price,
            // it means a[i] is less than or equal to min_suffix_price.
            // This a[i] now becomes the new minimum for the suffix starting at i.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

