#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_stair_cost = 1; // Cost for n=1 staircase
        long long sum_of_powers_of_2 = 1; // 2^0

        while (true) {
            if (x >= current_stair_cost) {
                x -= current_stair_cost;
                count++;
            } else {
                break;
            }

            // Calculate cost for the next nice staircase
            // The number of stairs for the next nice staircase is 2 * (current_n) + 1
            // The cost for a nice staircase with n stairs is (2^k - 1) * (2^k) / 2, where n = 2^k - 1
            // The next nice staircase will have n' = 2 * n + 1 stairs.
            // Its cost will be sum of costs of squares: 1^2 + 2^2 + 4^2 + ... + (2*sum_of_powers_of_2)^2
            // This is equivalent to sum_of_powers_of_2 * (2 * sum_of_powers_of_2 + 1)
            // Or, more simply, the cost of the next staircase is 2 * current_stair_cost + sum_of_powers_of_2 * 2
            // Let's use the formula: cost(2^k - 1) = (2^k - 1) * (2^k) / 2
            // The next one is cost(2^(k+1) - 1) = (2^(k+1) - 1) * (2^(k+1)) / 2
            // This is current_stair_cost + (2^k)^2 + (2^k)^2 * 2
            // No, this is not right.
            // The cost of a staircase with n = 2^k - 1 stairs is sum_{i=0}^{k-1} (2^i)^2 = sum_{i=0}^{k-1} 4^i.
            // This is (4^k - 1) / (4 - 1) = (4^k - 1) / 3.
            // Let's verify:
            // k=1, n=1: cost = (4^1 - 1)/3 = 1. Correct.
            // k=2, n=3: cost = (4^2 - 1)/3 = (16 - 1)/3 = 5. Correct.
            // k=3, n=7: cost = (4^3 - 1)/3 = (64 - 1)/3 = 21. Correct.

            // So, current_stair_cost is (4^k - 1) / 3.
            // The next cost will be (4^(k+1) - 1) / 3.
            // (4^(k+1) - 1) / 3 = (4 * 4^k - 1) / 3 = (4 * (3 * current_stair_cost + 1) - 1) / 3
            // = (12 * current_stair_cost + 4 - 1) / 3 = (12 * current_stair_cost + 3) / 3
            // = 4 * current_stair_cost + 1.

            // This formula is much simpler and avoids large intermediate values of 4^k.
            // It also avoids issues with sum_of_powers_of_2.

            if (current_stair_cost > (4611686018427387903LL - 1) / 4) { // Check for overflow before multiplication
                // 4611686018427387903LL is approximately LLONG_MAX / 2, to be safe.
                // LLONG_MAX is 9223372036854775807.
                // (LLONG_MAX - 1) / 4 is 2305843009213693951.
                // If current_stair_cost > (LLONG_MAX - 1) / 4, then 4 * current_stair_cost + 1 will overflow.
                break; 
            }
            current_stair_cost = 4 * current_stair_cost + 1;
        }
        std::cout << count << "\n";
    }
    return 0;
}

