int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used for the first k differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers.
    // The sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // Example: k=4. left=1, right=5.
    // 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1. All 4 distinct differences.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            p[i] = left;
            left++;
        } else { // Odd index, take from right
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers are n, n-1, ..., k+2 (if k+1 was the largest used)
    // or k+1, k+2, ..., n (if k+1 was the largest used and we need to continue from there)
    // The numbers used so far are 1, 2, ..., (k+1)/2 and (k+1), k, ..., (k+1)/2 + 1
    // In essence, we've used numbers from 1 to k+1.
    // The remaining numbers are k+2, k+3, ..., n.
    // To ensure no new distinct differences are introduced, we append them in increasing order.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

