void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of the suffix that is non-increasing
    // This is the first element from the right that breaks the non-increasing property
    // i.e., a[i] > a[i+1]
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // After this loop, a[p...n-1] is non-increasing.
    // If p=0, the whole array is non-increasing.

    // Find the rightmost peak of the suffix that is non-decreasing
    // This is the first element from the right that breaks the non-decreasing property
    // i.e., a[i] < a[i+1]
    int q = p; // Start search from p, as elements to the right of p are already non-increasing
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }
    // After this loop, a[q...p] is non-decreasing.
    // If q=0, the whole array is non-decreasing up to p.

    std::cout << q << std::endl;
}

