        }

        long long k = n / m; // Number of multiples of m up to n

        // Calculate the sum of last digits for one cycle (10 multiples of m)
        // (m*1)%10, (m*2)%10, ..., (m*10)%10
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (m * i) % 10;
        }

        // Number of full cycles
        long long num_full_cycles = k / 10;

        // Sum from full cycles
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining multiples after full cycles
        long long remaining_multiples = k % 10;

        // Sum from remaining multiples
        for (int i = 1; i <= remaining_multiples; ++i) {
            total_sum += (m * i) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. min_idx=pos[1], max_idx=pos[1].
        // Length is 1. Max value is 1.
        // For m > 1, we consider the number m.
        // The segment must contain 1, 2, ..., m.
        // This means the segment must span from min(pos[1...m]) to max(pos[1...m]).
        // We maintain current_min_idx and current_max_idx for numbers 1 to m-1.
        // When we consider m, we update these to include pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The length of the subsegment must be m.
        //    (current_max_idx - current_min_idx + 1 == m)
        // 2. The maximum value in the subsegment must be m.
        //    (This is implicitly handled by how current_max_idx and current_min_idx are updated.
        //     Since we are only considering numbers 1 to m, and we are expanding the range
        //     to cover all of them, the maximum value in p[current_min_idx ... current_max_idx]
        //     will be m, and the minimum will be 1, if the length condition holds.)

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

