int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (from sorted 'a')
    int right_ptr = 0; // Pointer for positions in the original array (from sorted 'a')

    while (right_ptr < n) {
        // We are trying to place a[left_ptr] into a position originally occupied by a[right_ptr].
        // To satisfy a[left_ptr] > a[right_ptr], we need a[left_ptr] to be strictly greater.
        // Since both arrays are sorted, if a[left_ptr] > a[right_ptr],
        // then a[left_ptr+1] will also be >= a[left_ptr] and a[right_ptr+1] will be >= a[right_ptr].
        // This greedy strategy works: try to match the smallest available element (a[left_ptr])
        // with the smallest possible position (a[right_ptr]) such that a[left_ptr] > a[right_ptr].
        // If a[left_ptr] is not greater than a[right_ptr], it means a[left_ptr] is too small
        // for this position. We must try a larger element for this position, or move to the next position.
        // Since we want to maximize matches, we should try to use smaller elements first.
        // If a[left_ptr] <= a[right_ptr], then a[left_ptr] cannot be placed at position right_ptr.
        // Also, a[left_ptr] cannot be placed at any position k < right_ptr because a[k] <= a[right_ptr].
        // So, we must try a larger element for position right_ptr.
        // This means we increment left_ptr to consider the next available element.
        if (a[left_ptr] > a[right_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // a[left_ptr] <= a[right_ptr]. This element a[left_ptr] cannot be placed
            // at position right_ptr to satisfy the condition.
            // We need a larger element for position right_ptr.
            // So, we advance left_ptr to find a suitable element.
            left_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

