struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<Element> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(A.begin(), A.end(), compareElements);

    // Sort B in descending order
    std::sort(B.begin(), B.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    std::vector<long long> result(m);
    for (int i = 0; i < m; ++i) {
        // A[i].value is the i-th smallest value from original A
        // B[i].value is the i-th largest value from original B
        // We want to assign A[i].value to the position corresponding to B[i].original_index
        result[B[i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Check prefixes
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    int distinct_count_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max possible value is n-1
            break;
        }
        seen_prefix[a[i]] = true;
        distinct_count_prefix++;
        max_val_prefix = std::max(max_val_prefix, a[i]);
        if (distinct_count_prefix == i + 1 && max_val_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Check suffixes
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    int distinct_count_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || seen_suffix[a[i]]) { // a[i] > n is an optimization, max possible value is n-1
            break;
        }
        seen_suffix[a[i]] = true;
        distinct_count_suffix++;
        max_val_suffix = std::max(max_val_suffix, a[i]);
        if (distinct_count_suffix == n - i && max_val_suffix == n - i) {
            is_suffix_perm[n - i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

