int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<long long, int> x_counts;
    std::map<long long, int> y_counts;
    std::map<std::pair<long long, long long>, int> xy_counts;

    for (int i = 0; i < n; ++i) {
        long long x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += static_cast<long long>(count) * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += static_cast<long long>(count) * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., are identical points)
    // These pairs were counted twice: once for same x, once for same y.
    // They should only be counted once.
    for (auto const& [point, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= static_cast<long long>(count) * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append elements b1, b2, b3 such that
        // (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)

        // Strategy: Append two elements.
        // Let b1 = current_xor_sum.
        // New XOR sum X' = current_xor_sum ^ b1 = current_xor_sum ^ current_xor_sum = 0.
        // New sum S' = current_sum + b1 = current_sum + current_xor_sum.
        // We want S' = 2 * X', which means current_sum + current_xor_sum = 2 * 0 = 0.
        // This is generally not true.

        // Let's try to make the final XOR sum X_final be some value, say X_target.
        // And the final sum S_final = 2 * X_target.

        // Consider appending two elements: X and S_target.
        // Let the first appended element be X_val = current_xor_sum.
        // After appending X_val, the new XOR sum is current_xor_sum ^ X_val = 0.
        // The new sum is current_sum + X_val.
        // Now we need to append one more element, say Y, such that:
        // (current_sum + X_val + Y) = 2 * (0 ^ Y)
        // (current_sum + X_val + Y) = 2 * Y
        // current_sum + X_val = Y
        // So, Y = current_sum + current_xor_sum.

        // The two elements to append are:
        // b1 = current_xor_sum
        // b2 = current_sum + current_xor_sum

        // Let's verify this:
        // Original sum = current_sum
        // Original XOR sum = current_xor_sum
        // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum
        // New total sum S_final = current_sum + b1 + b2
        // S_final = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S_final = 2 * (current_sum + current_xor_sum)

        // New total XOR sum X_final = current_xor_sum ^ b1 ^ b2
        // X_final = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X_final = 0 ^ (current_sum + current_xor_sum)
        // X_final = current_sum + current_xor_sum

        // Check condition: S_final = 2 * X_final
        // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
        // This holds true.

        // The problem guarantees that a solution always exists by appending at most 3 elements.
        // This strategy uses 2 elements.
        // The values can be large, up to 10^9 for initial elements, sum can be 10^5 * 10^9 = 10^14.
        // current_xor_sum is at most 2^30 (approx 10^9).
        // b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << std::endl;
        std::cout << b1 << " " << b2 << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually have to pass this 'b'.
            // When an 'a' passes a 'b', it effectively doubles the number of 'b's
            // that 'a' will need to pass in the future (from 1 'b' to 2 'b's).
            // So, the number of 'a's that need to pass 'b's effectively doubles.
            // This is equivalent to saying that each 'b' encountered
            // doubles the "potential" for future 'a's to generate steps.
            // The 'count_a' variable represents the number of 'a's that are
            // currently "active" and need to pass 'b's.
            // When a 'b' is encountered, each active 'a' will generate a step
            // by passing this 'b'. After passing, the 'a' is now to the right
            // of two 'b's (the original 'b' and the new 'b' from 'bba').
            // This means the 'a' effectively "carries" two 'b's for future 'a's.
            // So, the number of 'a's that need to pass future 'b's effectively doubles.
            // This is why `count_a = (count_a * 2) % mod;`
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it needs to pass all 'b's to its right.
            // The number of 'b's it needs to pass is represented by `count_a`.
            // Each 'b' it passes generates one step.
            // So, `total_steps += count_a;`
            total_steps = (total_steps + count_a) % mod;

            // After this 'a' has passed all 'b's to its right, it is now
            // effectively "done" with its current set of 'b's.
            // However, this 'a' itself becomes a 'b' (or rather, it contributes
            // to the 'b' count for 'a's further to its left).
            // When 'ab' -> 'bba', the 'a' moves past the 'b'.
            // The 'a' itself doesn't disappear. It's still an 'a'.
            // The `count_a` variable should represent the number of 'a's that
            // are currently "active" and need to pass 'b's.
            // When we encounter an 'a', it means this 'a' is now active
            // and needs to pass any 'b's to its left.
            // So, we increment `count_a` by 1.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

