// Function to convert a number to its parity pattern string
// Example: 241 -> "101" (1 is odd, 4 is even, 2 is even, but we read from right to left)
// 1 (odd) -> 1
// 4 (even) -> 0
// 2 (even) -> 0
// So, 241 becomes "001" if we pad to 3 digits.
// The problem states "parity of the i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
// This means we should generate the pattern from right to left.
// For 241:
// 1 % 2 = 1 (odd)
// 4 % 2 = 0 (even)
// 2 % 2 = 0 (even)
// Resulting pattern string: "001" (padded to 18 digits with leading zeros)
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with leading zeros to a fixed length (e.g., 18, max length of long long)
    // This simplifies matching as all patterns will be of the same length.
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left.
    // Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we should normalize both to a common length by padding with '0's.
    // Since the max length of a pattern is 18, and max value of a_i is < 10^18 (18 digits),
    // padding to 18 characters is appropriate.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get standard left-to-right representation
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each normalized parity pattern string
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with leading zeros to match the fixed length
            // of the stored patterns (18 characters).
            std::string query_pattern = s;
            while (query_pattern.length() < 18) {
                query_pattern = '0' + query_pattern;
            }
            std::cout << pattern_counts[query_pattern] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s_i is '0', then both w_{i-x} and w_{i+x} must be '0'.
    // Use this to set '0's in our candidate w.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if this candidate w can produce the given s.
    // Construct s_prime from w and compare with s.
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

