    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n - i' items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[i-1]
        if (i > 0) {
            current_energy += (prefix_sum[i] - prefix_sum[0]) * l;
        }

        // Energy for items taken from the right
        // These are w[n-(n-i)]...w[n-1]
        // Which means w[i]...w[n-1] if i items are taken from left
        // No, these are w[n-1], w[n-2], ..., w[n-(n-i)]
        // The sum of weights for items taken from right is (prefix_sum[n] - prefix_sum[i])
        int j = n - i; // Number of items taken from the right
        if (j > 0) {
            current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;
        }

        // Add penalty for consecutive actions
        if (i > j) { // More items taken from left than right
            // The last 'i - j - 1' items taken from the left will incur Ql penalty
            // This happens if we take i items from left and j items from right,
            // and the last item taken was from the left, and there are more left items than right items.
            // The difference is i - j. If i - j = 1, no extra penalty.
            // If i - j = 2, one extra penalty.
            // So, (i - j - 1) * Ql
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items taken from right than left
            // The last 'j - i - 1' items taken from the right will incur Qr penalty
            current_energy += (j - i - 1) * Qr;
        }
        // If i == j, no extra penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

