    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
