// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means x must not be divisible by q.
        // To make x not divisible by q, we must remove at least one prime factor of q from p,
        // or reduce its exponent sufficiently.
        // We want to remove the minimum possible "amount" from p to make it not divisible by q.
        // This means we should try to remove factors related to q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by 'factor'
            // or until current_p is no longer divisible by q.
            // The goal is to find the largest divisor of p that is not divisible by q.
            // For each prime factor 'f' of q, we can try to construct an x by dividing p by 'f'
            // until p is no longer divisible by q.
            // Specifically, we want to find the largest x = p / (f^k) such that x % q != 0.
            // We need to find the smallest k such that (p / f^k) % q != 0.
            // This means p / f^k must not have enough factors of f to be divisible by q.

            // Let's find the highest power of 'factor' that divides q.
            long long temp_q = q;
            long long q_factor_power = 0;
            while (temp_q > 0 && temp_q % factor == 0) {
                q_factor_power++;
                temp_q /= factor;
            }

            // Now, find the highest power of 'factor' that divides p.
            long long p_factor_power = 0;
            long long temp_p_for_power = p;
            while (temp_p_for_power > 0 && temp_p_for_power % factor == 0) {
                p_factor_power++;
                temp_p_for_power /= factor;
            }

            // We need to reduce the power of 'factor' in p such that it's less than q_factor_power.
            // The smallest power of 'factor' in p that makes p not divisible by q (with respect to this factor)
            // is p_factor_power - q_factor_power + 1.
            // So we need to divide p by factor^(p_factor_power - q_factor_power + 1).
            long long current_x = p;
            for (int i = 0; i < p_factor_power - q_factor_power + 1; ++i) {
                current_x /= factor;
            }
            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

