                // But since both play optimally, they will always try to maximize their own.
                // The "take N/2 if even, take 1 if odd" strategy is the standard greedy approach for this type of game.

                // The only exception to taking N/2 when N is even is if N=2.
                // If N=2, taking N/2=1. Chanek gets 1. N=1. Opponent takes 1. Chanek total 1.
                // If N=2, taking 1. Chanek gets 1. N=1. Opponent takes 1. Chanek total 1.
                // Both are same. So N/2 is fine.

                // The only time taking 1 is better than N/2 is if N/2 is 1.
                // If N=2, N/2=1.
                // If N=2, Chanek takes 1. N=1. Opponent takes 1. Chanek gets 1.
                // If N=2, Chanek takes 2/2=1. N=1. Opponent takes 1. Chanek gets 1.
                // So for N=2, it doesn't matter.

                // The strategy is:
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2, take N/2.
                //   If N is even but not a power of 2, take N/2.
                // This simplifies to: if N is odd, take 1. If N is even, take N/2.

                // Let's implement this strategy.
                // The loop will run until N becomes 0.
                // The number of turns can be up to log2(10^18) * 2 (roughly 60 * 2 = 120 turns).
                // This is efficient enough.

                // Check if N is a power of 2.
                // A number N is a power of 2 if N > 0 and (N & (N - 1)) == 0.
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    // For N=2^k, Chanek gets (2^(k+1) - 1) / 3 if k is odd.
                    //                 Chanek gets (2^(k+1) + 1) / 3 if k is even.
                    // This can be simplified.
                    // Let's find k.
                    long long temp_n = n;
                    int k = 0;
                    while (temp_n > 1) {
                        temp_n /= 2;
                        k++;
                    }
                    if (k % 2 != 0) { // k is odd
                        chanek_coins += (n * 2 - 1) / 3;
                    } else { // k is even
                        chanek_coins += (n * 2 + 1) / 3;
                    }
                    n = 0; // Game ends
                } else { // N is even but not a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    // Opponent takes N/2.
                    // The remaining coins will be N/2.
                    // The game will continue with Chanek getting the next N/4, etc.
                    // This is already handled by the power of 2 logic for Chanek.
                    // So we just need to reduce N.
                    n = 0; // Game ends for this branch, as Chanek's coins are already calculated.
                } else { // N is even but not a power of 2
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

