        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string keyboard_layout = "";
    std::set<char> visited_in_layout;
    char current_char = '\0';

    // Find a starting character for the layout.
    // It should be a character with only one required neighbor (an endpoint of a chain).
    // Or, if all characters in s form a cycle, any character from s.
    // Or, if s is just one character, that character.
    if (!s.empty()) {
        bool found_start = false;
        for (char c : s) {
            if (adj[c].size() <= 1) { // <= 1 because if s has one char, adj[c] is empty
                current_char = c;
                found_start = true;
                break;
            }
        }
        if (!found_start) { // All chars in s have 2 neighbors, implies a cycle
            current_char = s[0];
        }
    }

    if (current_char != '\0') { // If s was not empty
        keyboard_layout += current_char;
        visited_in_layout.insert(current_char);
        char prev_char = '\0'; // To keep track of the previous character in the layout

        while (true) {
            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }

            if (next_char != '\0') {
                if (visited_in_layout.count(next_char)) {
                    // This means we found a cycle that includes a character already visited
                    // and it's not just going back and forth.
                    // This implies a structure like A-B-C-A, which is fine if it's the only path.
                    // But if it's A-B-C-D-B, then B has 3 neighbors (A,C,D), which is already checked.
                    // The only way to reach here is if we have a cycle like A-B-C-A and we started at A,
                    // went A->B->C, and then C's neighbor is A.
                    // If we started at A, and went A->B, then B's neighbors are A and C.
                    // If we pick C, then C's neighbors are B and A.
                    // If we pick A, then A is already visited.
                    // This means we have completed a chain/cycle of required characters.
                    // We should break and add remaining characters.
                    break;
                }
                keyboard_layout += next_char;
                visited_in_layout.insert(next_char);
                prev_char = current_char;
                current_char = next_char;
            } else {
                break; // End of a chain
            }
        }
    }

    // Add all remaining unvisited characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited_in_layout.count(c)) {
            keyboard_layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << keyboard_layout << "\n";
}

