int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r = (b * (b - 1) / 2) % MOD
    // We need to handle division by 2.
    // Since MOD is prime (10^9 + 7), we can use modular inverse for division by 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = (b % MOD * ((b - 1) % MOD)) % MOD;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum of (k * b + 1) from k=1 to a
    // This is sum_{k=1 to a} (k*b + 1)
    // = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a + 1) / 2) + a
    // This is sum_k = (b * (a * (a + 1) / 2) + a) % MOD
    long long sum_k_term_part1 = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * inv2) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * (b % MOD)) % MOD;

    long long sum_k_term_part2 = a % MOD;

    long long sum_k_term = (sum_k_term_part1 + sum_k_term_part2) % MOD;

    // Total sum = (sum_r_term * sum_k_term) % MOD
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

