#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_probability = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char first_char_t = s[k_actual]; // t[0] = s[k_actual]

        // Vasya knows first_char_t.
        // This means k must be one of the indices where s has first_char_t.
        const std::vector<int>& possible_k_values = char_indices[first_char_t - 'a'];

        if (possible_k_values.size() == 1) {
            // If only one k matches t[0], Vasya wins immediately.
            total_win_probability += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal position p to query t[p].
        // He wants to maximize the probability of winning for this specific first_char_t.
        double max_win_prob_for_char = 0.0;

        // Iterate over all possible positions p (0 to N-1)
        for (int p = 0; p < n; ++p) {
            // For a fixed p, count how many k's from possible_k_values
            // would be uniquely determined.

            // Group possible_k_values by the character s[(p+k)%N]
            // and count how many groups have size 1.
            std::map<char, std::vector<int>> groups;
            for (int k_cand : possible_k_values) {
                char char_at_p = s[(p + k_cand) % n];
                groups[char_at_p].push_back(k_cand);
            }

            int unique_count = 0;
            for (const auto& pair : groups) {
                if (pair.second.size() == 1) {
                    unique_count++;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, (double)unique_count / possible_k_values.size());
        }
        total_win_probability += max_win_prob_for_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_probability / n << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute positions of '1's
    std::vector<int> ones_pos;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_pos.push_back(i);
        }
    }

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Case 1: s[l] is '0'
        if (s[l] == '0') {
            // Find the first '1' at or after l.
            // If no '1' exists, all subsequent substrings starting with '0' will have value 0.
            // The only good substring would be "0" if its length is 0, which is impossible.
            // So, if s[l] is '0', we need to find the first '1' to form a non-zero value.
            // If there's no '1' after l, then all substrings starting at l are '0's.
            // Their value is 0. Length is always >= 1. So no good substrings.

            // Find the first '1' at or after index l.
            auto it = std::lower_bound(ones_pos.begin(), ones_pos.end(), l);
            if (it == ones_pos.end()) {
                // No '1' found at or after l. All remaining characters are '0'.
                // Substrings like "0", "00", "000" have value 0. Length is >= 1.
                // So, no good substrings can start with '0' if there are no '1's after it.
                continue; 
            }
            int first_one_idx = *it;

            // The substring must contain this '1' to have a non-zero value.
            // The actual binary value starts from this '1'.
            // The length of the substring is r - l + 1.
            // The value is f(s_l...s_r).
            // If s_l...s_r starts with '0's, these are leading zeros.
            // The effective binary string for value calculation starts at first_one_idx.
            // Let k be the number of leading zeros: k = first_one_idx - l.
            // The value of s_l...s_r is f(s_{first_one_idx}...s_r).
            // We need r - l + 1 = f(s_{first_one_idx}...s_r).
            // This means r - l + 1 = (s_{first_one_idx} - '0')*2^(r - first_one_idx) + ... + (s_r - '0')*2^0.
            // The maximum possible length is N. The maximum value is N.
            // The maximum number of bits for N is around 18 (2^17 < 2e5 < 2^18).
            // So, the effective binary string s_{first_one_idx}...s_r can have at most 18 bits.
            // This means r - first_one_idx + 1 <= 18.
            // So, r <= first_one_idx + 17.

            for (int r = first_one_idx; r < std::min(n, first_one_idx + 18); ++r) {
                long long current_val = 0;
                for (int i = first_one_idx; i <= r; ++i) {
                    current_val = current_val * 2 + (s[i] - '0');
                }
                if (current_val == (long long)(r - l + 1)) {
                    good_substrings_count++;
                }
            }
        } else { // Case 2: s[l] is '1'
            long long current_val = 0;
            // The maximum length of a substring is N.
            // The maximum value is N.
            // The maximum number of bits for N is around 18.
            // So, the effective binary string s_l...s_r can have at most 18 bits.
            // This means r - l + 1 <= 18.
            // So, r <= l + 17.
            for (int r = l; r < std::min(n, l + 18); ++r) {
                current_val = current_val * 2 + (s[r] - '0');
                if (current_val == (long long)(r - l + 1)) {
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

