    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for differences (1 for strawberry, -1 for blueberry)
    // Left side: indices n-1 down to 0
    // Right side: indices n up to 2n-1

    // diff_L[k] = sum of (a[n-1]...a[n-k]) where 1->1, 2->-1
    // diff_R[k] = sum of (a[n]...a[n+k-1]) where 1->1, 2->-1

    std::vector<int> diff_L(n + 1, 0); // diff_L[k] is diff after emptying k jars from left
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[n - 1 - i] == 1 ? 1 : -1);
    }

    std::vector<int> diff_R(n + 1, 0); // diff_R[k] is diff after emptying k jars from right
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[n + i] == 1 ? 1 : -1);
    }

    // Calculate initial total difference
    int initial_diff = 0;
    for (int x : a) {
        initial_diff += (x == 1 ? 1 : -1);
    }

    // Map to store the minimum k_L for a given diff_L value
    std::map<int, int> min_kL_for_diff;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff_L = diff_L[k_L];
        if (min_kL_for_diff.find(current_diff_L) == min_kL_for_diff.end()) {
            min_kL_for_diff[current_diff_L] = k_L;
        }
    }

    int min_jars_emptied = 2 * n; // Max possible jars emptied

    // Iterate through all possible k_R (number of jars emptied from right)
    for (int k_R = 0; k_R <= n; ++k_R) {
        // The difference of remaining jars on the right side is initial_diff_R - diff_R[k_R]
