        // Which means diff_L[k_L] = initial_diff - diff_R[k_R]

        int target_diff_L = initial_diff - diff_R[k_R];

        if (min_kL_for_diff.count(target_diff_L)) {
            int k_L = min_kL_for_diff[target_diff_L];
            min_jars_emptied = std::min(min_jars_emptied, k_L + k_R);
        }
    }

    std::cout << min_jars_emptied << std::endl;
}

