#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0; // The value of b_{i-1} in the non-decreasing sequence
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];
        long long current_b;

        // Case 1: a_i is not incremented (or incremented by 0)
        // Then b_i = a_i. We need a_i >= prev_b.
        // If a_i < prev_b, then we must increment a_i.
        if (current_a >= prev_b) {
            // If a_i >= prev_b, then b_i can be a_i.
            // We also need to check if a_i can be obtained by incrementing up to x times.
            // The maximum value a_i can become is (a_i + x) % m.
            // If (a_i + x) % m < prev_b, it means even with max increments, it's too small.
            // This happens if a_i + x wraps around m and becomes smaller than prev_b.
            // Specifically, if a_i + x >= m and (a_i + x) % m < prev_b.
            // This is equivalent to saying that the interval [a_i, (a_i + x) % m] (circularly)
            // does not contain prev_b.
            // More simply, if a_i + x < m, then (a_i + x) % m = a_i + x.
            // If a_i + x >= m, then (a_i + x) % m = a_i + x - m.
            // We need to ensure that if we choose b_i = a_i, it's valid.
            // It is valid if a_i >= prev_b.
            // If we choose b_i = a_i, then the number of increments is 0.
            // This is always <= x.
            // So, if a_i >= prev_b, we can potentially set b_i = a_i.
            current_b = current_a;
        } else { // current_a < prev_b
            // We must increment a_i.
            // The smallest possible value for b_i is prev_b.
            // Can we reach prev_b from current_a by incrementing at most x times?
            // The number of increments needed is (prev_b - current_a + m) % m.
            // If prev_b >= current_a, increments needed = prev_b - current_a.
            // If prev_b < current_a, increments needed = prev_b - current_a + m.
            // This is equivalent to (prev_b - current_a + m) % m.
            // Let inc_needed = (prev_b - current_a + m) % m.
            // If inc_needed <= x, then we can set b_i = prev_b.
            // Otherwise, we cannot reach prev_b, so it's impossible.
            long long inc_needed = (prev_b - current_a + m) % m;
            if (inc_needed <= x) {
                current_b = prev_b;
            } else {
                return false; // Cannot make a_i >= prev_b with at most x increments
            }
        }
        prev_b = current_b;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2: uncomputed, -1: infinite loop, >=0: final y
    std::vector<int> dp_x(n + 1, 0);     // 0: uncomputed, -1: infinite loop, >0: final x

    for (int i = 1; i <= n; ++i) {
        if (dp_y[i] != -2) continue;

        std::vector<int> path;
        int current_x = i;
        long long current_y_offset = 0; // y accumulated in this path segment

        while (current_x >= 1 && current_x <= n) {
            if (dp_y[current_x] != -2) { // Hit a state that's already computed or in a cycle
                if (dp_y[current_x] == -1) { // Hit an infinite loop
                    for (int node : path) {
                        dp_y[node] = -1;
                        dp_x[node] = -1;
                    }
                } else { // Hit a computed state
                    for (int node : path) {
                        dp_y[node] = current_y_offset + dp_y[current_x];
                        dp_x[node] = dp_x[current_x];
                    }
                }
                break;
            }

            // Mark current_x as part of the current path (potential cycle)
            dp_y[current_x] = -1; // Temporarily mark as -1 to detect cycles
            dp_x[current_x] = -1;
            path.push_back(current_x);

            long long val_a_x = a[current_x];
            current_y_offset += val_a_x;
            int next_x_step1 = current_x + val_a_x;

            if (next_x_step1 <= 0 || next_x_step1 > n) { // Terminate after step 2
                for (int node : path) {
                    dp_y[node] = current_y_offset;
                    dp_x[node] = next_x_step1;
                }
                break;
            }

            val_a_x = a[next_x_step1]; // Use a[next_x_step1] for step 3
            current_y_offset += val_a_x;
            int next_x_step2 = next_x_step1 - val_a_x;
            current_x = next_x_step2;

            if (current_x <= 0 || current_x > n) { // Terminate after step 3
                for (int node : path) {
                    dp_y[node] = current_y_offset;
                    dp_x[node] = current_x;
                }
                break;
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i;
        long long initial_val_a1 = a[1];
        long long y_val = initial_val_a1;
        int x_after_step2 = 1 + initial_val_a1;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            std::cout << y_val << "\n";
        } else {
            long long val_a_x_after_step2 = a[x_after_step2];
            y_val += val_a_x_after_step2;
            int x_after_step3 = x_after_step2 - val_a_x_after_step2;

            if (x_after_step3 <= 0 || x_after_step3 > n) {
                std::cout << y_val << "\n";
            } else {
                if (dp_y[x_after_step3] == -1) {
                    std::cout << -1 << "\n";
                } else {
                    std::cout << y_val + dp_y[x_after_step3] << "\n";
                }
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Calculate initial_delta[j] for each j
    // initial_delta[j] stores the sum of 'd' values from type 1 operations
    // that affect index j *before* any type 2 operation constraints are applied.
    // This is used to determine the lower bound for a_0[j].
    std::vector<long long> initial_delta(n, 0);
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                initial_delta[j] += op.val;
            }
        }
    }

    // Initialize a_0[j] based on type 2 operations
    // a_0[j] represents the initial value of the j-th element.
    // We want to find the largest possible a_0[j] that satisfies all constraints.
    // For a type 2 operation (l, r, m), we know that for any j in [l, r],
    // a_0[j] + current_delta[j] <= m.
    // So, a_0[j] <= m - current_delta[j].
    // We initialize a_0[j] to a very large value (effectively infinity)
    // and then take the minimum of these upper bounds.
    std::vector<long long> a0(n, 2000000000LL); // Max possible value for a_0[j] is 10^9,
                                                // but m can be 5*10^7 and delta can be 5000*10^4 = 5*10^7.
                                                // So m - delta can be 0, or even negative.
                                                // A safe upper bound for a_0[j] is 10^9.
                                                // Let's use 2*10^9 to be safe, as 10^9 is the limit for |a_i|.
                                                // The problem states |a_i| <= 10^9, which means a_i can be -10^9.
                                                // So a_0[j] can be -10^9.
                                                // The upper bound for a_0[j] is 10^9.
                                                // The lower bound for a_0[j] is -10^9.
                                                // We initialize a0 with a value larger than 10^9.

    std::vector<long long> current_delta(n, 0); // current_delta[j] accumulates 'd' values up to the current operation.
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // op.type == 2
            for (int j = op.l; j <= op.r; ++j) {
                a0[j] = std::min(a0[j], op.val - current_delta[j]);
            }
        }
    }

    // After processing all operations, a0[j] contains the maximum possible initial value
    // for each element j that satisfies all type 2 constraints.
    // If a0[j] is still 2*10^9, it means no type 2 operation constrained it.
    // In this case, we can set it to 10^9 (or 0, or any value within [-10^9, 10^9]).
    // Let's set it to 10^9 to maximize the chance of satisfying future checks.
    for (int j = 0; j < n; ++j) {
        if (a0[j] == 2000000000LL) {
            a0[j] = 1000000000LL; // Default to max allowed if not constrained
        }
        // Ensure a0[j] is within [-10^9, 10^9]
        a0[j] = std::min(a0[j], 1000000000LL);
        a0[j] = std::max(a0[j], -1000000000LL);
    }

    // Verify the constructed a0 array
    // Simulate all operations with the chosen a0 and check consistency.
    current_delta.assign(n, 0); // Reset current_delta for verification
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // op.type == 2
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, a0[j] + current_delta[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

