// Function to calculate parity of a 01-string
char calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return (ones_count % 2 == 1) ? '1' : '0';
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of a
    char current_parity_a = calculate_parity(a);

    // We can generate all possible strings that can be formed from 'a'
    // by first removing characters from the front, and then appending parities.
    // The key observation is that if we can form 'b', then 'b' must be a prefix
    // of some string 's' that can be generated from 'a'.
    // And 's' itself must be a suffix of the original 'a' followed by some parities.

    // Let's consider the string 'a' and its parities.
    // We can generate a sequence of parities:
    // P_0 = parity(a)
    // P_1 = parity(a + P_0)
    // P_2 = parity(a + P_0 + P_1)
    // ...
    // This sequence of parities is periodic. The maximum length of the period is 2.
    // Example: 0 -> 00 -> 000 -> ... (parity is always 0)
    // Example: 1 -> 11 -> 110 -> 1101 -> 11010 -> 110101 -> ... (parity sequence 1,0,1,0,...)
    // So, we only need to generate a few parities to cover all possibilities.
    // A string of length |a| + |b| is sufficient to check if 'b' can be formed.
    // If 'b' can be formed, it must be a prefix of some string 'a_suffix + generated_parities'.
    // The maximum length of such a string we need to consider is |a| + |b| - 1.
    // If 'b' is longer than 'a', we need to append parities to 'a'.
    // If 'b' is shorter than 'a', we need to remove characters from 'a' and then potentially append parities.

    // The strategy:
    // 1. Iterate through all possible suffixes of 'a'. Let this suffix be `current_a`.
    // 2. For each `current_a`, generate a string by appending parities until its length is at least `|b|`.
    // 3. Check if `b` is a prefix of this generated string.

    for (int i = 0; i < a.length(); ++i) {
        std::string current_a = a.substr(i);
        std::string generated_string = current_a;

        // Append parities until generated_string is at least as long as b
        // We need to append at most |b| characters.
        // The maximum length of generated_string will be |a| + |b| - 1.
        // This is safe because if b is a prefix of a string of length L,
        // it's also a prefix of any string of length > L that starts with the same L characters.
        // So we only need to generate up to length |b| + |a| - 1.
        // If current_a is already longer than b, we don't need to append anything.
        while (generated_string.length() < b.length() + 2) { // +2 to be safe, covers cases like b is longer than a
            generated_string += calculate_parity(generated_string);
        }

        // Check if b is a prefix of the generated string
        if (generated_string.length() >= b.length() && generated_string.substr(0, b.length()) == b) {
            std::cout << "YES\n";
            return 0;
        }
    }

    std::cout << "NO\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to doctor

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0; // Accumulates d_j from children leaving due to low confidence

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_effect from previous children who left
            children[j].p -= total_d_effect;

            // Apply v_effect from child i going to doctor
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].in_line = false; // Child j leaves
                total_d_effect += children[j].d; // Add d_j to total_d_effect for subsequent children
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits are 1 initially
    int current_or_mask = 0;    // All bits are 0 initially
    int current_xor_mask = 0;   // All bits are 0 initially

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    // Now we have the combined effect of all operations on an initial state of (0, 0, 0)
    // and (1, 1, 1) for each bit.
    // Let's denote the final state of a bit that was initially 0 as `f0`
    // and the final state of a bit that was initially 1 as `f1`.
    //
    // For each bit `b`:
    // If initial bit is 0:
    //   `f0_b = (0 & current_and_mask_b) | current_or_mask_b ^ current_xor_mask_b`
    //   This simplifies to `f0_b = current_or_mask_b ^ current_xor_mask_b`
    //
    // If initial bit is 1:
    //   `f1_b = (1 & current_and_mask_b) | current_or_mask_b ^ current_xor_mask_b`
    //   This simplifies to `f1_b = current_and_mask_b | current_or_mask_b ^ current_xor_mask_b`
    //
    // We need to find a sequence of at most 5 operations (AND, OR, XOR)
    // that transforms an input `x` to `(x & A) | B ^ C`.
    //
    // Let's determine the effective A, B, C for our simplified program.
    //
    // For each bit `b`:
    // If `f0_b == 0` and `f1_b == 0`: The bit is always 0.
    //   This means `(x_b & A_b) | B_b ^ C_b` must be 0 for both `x_b=0` and `x_b=1`.
    //   If `x_b=0`: `(0 & A_b) | B_b ^ C_b = B_b ^ C_b = 0`. So `B_b = C_b`.
    //   If `x_b=1`: `(1 & A_b) | B_b ^ C_b = A_b | B_b ^ C_b = 0`.
    //     Since `B_b = C_b`, this means `A_b | 0 = 0`, so `A_b = 0`.
    //     Thus, `A_b=0, B_b=0, C_b=0` or `A_b=0, B_b=1, C_b=1`.
    //     The simplest way to force a bit to 0 is `& 0`.
    //
    // If `f0_b == 1` and `f1_b == 1`: The bit is always 1.
    //   This means `(x_b & A_b) | B_b ^ C_b` must be 1 for both `x_b=0` and `x_b=1`.
    //   If `x_b=0`: `B_b ^ C_b = 1`. So `B_b != C_b`.
    //   If `x_b=1`: `A_b | B_b ^ C_b = 1`.
    //     Since `B_b ^ C_b = 1`, this is `A_b | 1 = 1`, which is always true.
    //     Thus, we need `B_b != C_b`.
    //     The simplest way to force a bit to 1 is `| 1`.
    //
    // If `f0_b == 0` and `f1_b == 1`: The bit is `x_b`. (Identity)
    //   This means `(x_b & A_b) | B_b ^ C_b` must be `x_b`.
    //   If `x_b=0`: `B_b ^ C_b = 0`. So `B_b = C_b`.
    //   If `x_b=1`: `A_b | B_b ^ C_b = 1`.
    //     Since `B_b = C_b`, this is `A_b | 0 = 1`, so `A_b = 1`.
    //     Thus, `A_b=1, B_b=0, C_b=0` or `A_b=1, B_b=1, C_b=1`.
    //     The simplest way to keep a bit as `x_b` is `& 1` (or no op).
    //
    // If `f0_b == 1` and `f1_b == 0`: The bit is `~x_b`. (Flip)
    //   This means `(x_b & A_b) | B_b ^ C_b` must be `~x_b`.
    //   If `x_b=0`: `B_b ^ C_b = 1`. So `B_b != C_b`.
    //   If `x_b=1`: `A_b | B_b ^ C_b = 0`.
    //     Since `B_b != C_b`, `B_b ^ C_b = 1`.
    //     So `A_b | 1 = 0`, which is impossible.
    //     This means the form `(x & A) | B ^ C` cannot directly represent `~x_b` for all bits.
    //     However, we can achieve `~x_b` with `^ 1`.
    //
    // Let's define the target values for A, B, C for each bit based on `f0_b` and `f1_b`.
    //
    // `A_b`: If `f0_b == f1_b`, then `A_b` doesn't matter for the `&` part, as the bit will be forced anyway.
    //        If `f0_b != f1_b`, then `A_b` determines if `x_b` or `~x_b` is passed through.
    //        Specifically, if `f0_b=0, f1_b=1` (identity), we need `A_b=1`.
    //        If `f0_b=1, f1_b=0` (flip), we need `A_b=1` to pass `x_b` through, then flip it with XOR.
    //        So, `A_b` should be 1 if `f0_b != f1_b`. Otherwise, `A_b` can be 0 or 1.
    //        Let's try to set `A_b = 1` if `f0_b != f1_b`, and `A_b = 0` if `f0_b == f1_b`.
    //        This means `A_b = f0_b ^ f1_b`.
    //
    // `B_b ^ C_b`: This is the value when `x_b=0`. So `B_b ^ C_b = f0_b`.
    //
    // Let's try to construct the final operations.
    // We want to find `final_and`, `final_or`, `final_xor` such that
    // `((x & final_and) | final_or) ^ final_xor` matches the behavior.
    //
    // For each bit `b`:
    // Let `x_b` be the input bit.
    // The output bit `y_b` is determined by `f0_b` and `f1_b`.
    //
    // Case 1: `f0_b = 0, f1_b = 0` (always 0)
    //   We need `((x_b & A_b) | B_b) ^ C_b = 0`.
    //   If `x_b=0`: `(0 | B_b) ^ C_b = B_b ^ C_b = 0`. So `B_b = C_b`.
    //   If `x_b=1`: `(A_b | B_b) ^ C_b = 0`.
    //     Since `B_b = C_b`, this means `A_b | B_b ^ B_b = A_b | 0 = A_b = 0`.
    //   So, for this bit, we need `A_b=0, B_b=0, C_b=0` or `A_b=0, B_b=1, C_b=1`.
