// Function to check if all tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for tracks to be read (p)
    int h_idx = 0; // Current index for heads (h)

    while (p_idx < m) {
        // If we run out of heads but still have tracks to cover, it's impossible
        if (h_idx >= n) {
            return false;
        }

        // Find the first head h[h_idx] that can potentially cover p[p_idx]
        // A head h[h_idx] can cover p[p_idx] if p[p_idx] is within [h[h_idx] - T, h[h_idx] + T]
        // This means h[h_idx] - T <= p[p_idx] <= h[h_idx] + T
        // Or, equivalently, p[p_idx] - T <= h[h_idx] <= p[p_idx] + T
        // Since h is sorted, we can skip heads that are too far to the left.
        // If h[h_idx] + T < p[p_idx], this head cannot reach p[p_idx] or any p_k > p[p_idx].
        // So, we must advance h_idx.
        while (h_idx < n && h[h_idx] + T < p[p_idx]) {
            h_idx++;
        }

        // If we skipped all heads and ran out, it's impossible
        if (h_idx >= n) {
            return false;
        }

        // At this point, h[h_idx] is the first head that *might* be able to cover p[p_idx].
        // Specifically, h[h_idx] + T >= p[p_idx].
        // We need to check if h[h_idx] - T <= p[p_idx].
        // If h[h_idx] - T > p[p_idx], then h[h_idx] is too far to the right to cover p[p_idx].
        // In this case, no head h[k] for k >= h_idx can cover p[p_idx] because h[k] >= h[h_idx]
        // implies h[k] - T >= h[h_idx] - T > p[p_idx].
        // So, if h[h_idx] - T > p[p_idx], it's impossible.
        if (h[h_idx] - T > p[p_idx]) {
            return false;
        }

        // If we reach here, h[h_idx] can cover p[p_idx].
        // The head h[h_idx] can cover the range [h[h_idx] - T, h[h_idx] + T].
        // We greedily use this head to cover as many subsequent tracks p_k as possible.
        // The rightmost track this head can cover is min(p_m-1, h[h_idx] + T).
        long long current_head_reach = h[h_idx] + T;

        // Advance p_idx past all tracks that can be covered by the current head h[h_idx]
        while (p_idx < m && p[p_idx] <= current_head_reach) {
            p_idx++;
        }

        // Move to the next head for the remaining tracks
        h_idx++;
    }

    // All tracks p_j have been covered
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    // Binary search for the minimum time T
    long long low = 0;
    // Max possible distance is between p_m-1 and h_0, or p_0 and h_n-1.
    // Max value of p_i or h_i is 10^10. So max diff is 10^10.
    // T can be up to 10^10.
    long long high = 2e10; // A sufficiently large upper bound for T
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

