        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of a permutation has the same set of adjacent sums.
        // For example, if p = [p1, p2, p3, p4], sums are [p1+p2, p2+p3, p3+p4].
        // If p' = [p4, p3, p2, p1], sums are [p4+p3, p3+p2, p2+p1].
        // These two sets of sums are identical, so their sorted versions (fingerprints) will be identical.
        // The reversed permutation is different from the original unless n=1 (not possible here, n>=2)
        // or the permutation is a palindrome (e.g., [1,2,1] not a permutation, [1,2,3,2,1] not a permutation).
        // A permutation of distinct elements from 1 to n cannot be a palindrome unless n=1.
        // For n >= 2, p_1 != p_n (unless n=1), so reversing always produces a different permutation.
        // Example: [1,2] -> [2,1]. F([1,2])=[3], F([2,1])=[3].
        // Example: [2,1,6,5,4,3] -> [3,4,5,6,1,2].
        // The problem statement guarantees a solution exists. Reversing is the simplest.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
