int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, but sum of a_i * (i-1) can exceed int
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            if (a[i] == 0) {
                continue; // No haybales to move from this pile
            }

            long long cost_per_haybale = i; // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 is i days

            if (d >= cost_per_haybale) {
                // Calculate how many haybales can be moved from pile i
                long long max_haybales_from_this_pile = d / cost_per_haybale;

                // We can move at most a[i] haybales from this pile
                long long haybales_to_move = std::min((long long)a[i], max_haybales_from_this_pile);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
