int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from stdio and prevents flushing cout before cin.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices for each day
        }

        if (n == 0) { // Handle edge case for n=0, though constraints say n >= 1
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_price_suffix with the last price, as it's the minimum
        // for the suffix starting at n-1.
        int min_price_suffix = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // The last day (a[n-1]) can never be a bad price because there are no later days.
        for (int i = n - 2; i >= 0; --i) {
            // If the current price a[i] is greater than the minimum price
            // found in any subsequent day (min_price_suffix), then a[i] is a bad price.
            if (a[i] > min_price_suffix) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_price_suffix, it means a[i]
                // is either equal to or less than the current minimum.
                // In this case, a[i] becomes the new minimum for the suffix
                // starting at day i.
                min_price_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

