        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1.
        // If no 'R' was found, last_R_pos remains -1, and the jump is from 0 to n+1.
        // If 'R's were found, last_R_pos is the index of the last 'R' (0-indexed string, so cell last_R_pos+1).
        // The distance to n+1 is (n+1) - (last_R_pos + 1) = n - last_R_pos.
        max_dist = std::max(max_dist, (int)s.length() - last_R_pos);
        std::cout << max_dist << "\n";
    }
    return 0;
}

