int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Cost of a nice staircase with k stairs is k * (k + 1) / 2
            // The sequence of k for nice staircases is 1, 3, 7, 15, ... which is 2^m - 1
            // So, the cost is (2^m - 1) * (2^m) / 2
            // Let's use the formula for the cost directly:
            // Cost for a nice staircase with k stairs is (k * (k + 1)) / 2
            // The sequence of k values for nice staircases is 1, 3, 7, 15, 31, ...
            // This is 2^m - 1 for m = 1, 2, 3, ...
            // So, the cost for the m-th nice staircase (in terms of increasing k) is
            // ( (2^m - 1) * (2^m - 1 + 1) ) / 2 = ( (2^m - 1) * 2^m ) / 2 = (2^m - 1) * 2^(m-1)

            // Let's calculate the cost for the current k
            long long cost_for_k = k * (k + 1) / 2;

            if (current_cost + cost_for_k <= x) {
                current_cost += cost_for_k;
                count++;
                // Calculate the next k. The sequence is k_new = 2 * k_old + 1
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

