    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // Only add ')' if it can be matched by an already added '('
            // and we still need closing brackets.
            // The condition `result.length() - (k/2 - open_needed) > 0`
            // checks if the number of '(' in result is greater than the number of ')' in result.
            // `result.length()` is the total length of `result`.
            // `k/2 - open_needed` is the number of '(' already added.
            // `result.length() - (k/2 - open_needed)` is the number of ')' already added.
            // So, we need `(k/2 - open_needed) > (result.length() - (k/2 - open_needed))`
            // which simplifies to `2 * (k/2 - open_needed) > result.length()`.
            // Or, more simply, the balance of `(` minus `)` must be positive.
            // The balance is `(k/2 - open_needed) - (result.length() - (k/2 - open_needed))`.
            // This is equivalent to `2 * (k/2 - open_needed) - result.length()`.
            // We need this balance to be > 0.
            // A simpler way to think about it:
            // The number of '(' added so far is `k/2 - open_needed`.
            // The number of ')' added so far is `result.length() - (k/2 - open_needed)`.
            // We can add ')' if `(k/2 - open_needed) > (result.length() - (k/2 - open_needed))`
            // and `close_needed > 0`.
            // This is equivalent to `result.length() < 2 * (k/2 - open_needed)`
            // or `result.length() < k - 2 * open_needed`.
            // This condition ensures that we don't add ')' if it would make the prefix invalid.
            // Since we are guaranteed a solution exists, and we prioritize '(',
            // this greedy choice should work.
            // The balance check is implicitly handled by the fact that we add ')' only if `close_needed > 0`
            // and we have already added enough '(' to potentially match it.
            // The problem guarantees a solution exists, and `s` is a regular bracket sequence.
            // A simpler greedy approach: just take `k/2` opening and `k/2` closing brackets.
            // The order of selection from `s` will maintain the relative order.
            // The key is to ensure the resulting sequence is regular.
            // The most straightforward way to ensure regularity is to take `k/2` opening brackets
            // and then `k/2` closing brackets, but this might not be a subsequence.
            // A better greedy approach: take `(` if `open_needed > 0`.
            // Take `)` if `close_needed > 0` AND the current balance allows it.
            // The balance is `(count of '(' in result) - (count of ')' in result)`.
            // `count of '(' in result` is `k/2 - open_needed`.
            // `count of ')' in result` is `result.length() - (k/2 - open_needed)`.
            // So, we can add ')' if `(k/2 - open_needed) > (result.length() - (k/2 - open_needed))`.
            // This simplifies to `2 * (k/2 - open_needed) > result.length()`.
            // Or, `k - 2 * open_needed > result.length()`.
            // This is the correct balance check.
            if (close_needed > 0 && (k / 2 - open_needed) > (result.length() - (k / 2 - open_needed))) {
                result += ')';
                close_needed--;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

