        // Check if the expanded range satisfies the condition for 'm'.
        // The length of the subsegment is (current_max_idx - current_min_idx + 1).
        // For 'm' to be beautiful, this length must be equal to 'm'.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << std::endl;
