    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2;

    // Operations for the median element itself
    operations += std::abs(a[mid_idx] - s);

    // Operations for elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Operations for elements to the right of the median
    // These elements must be >= s
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // ending at index i, such that a[j] >= j for 0 <= j <= i.
    // This is equivalent to checking if a[j] can be made to be j.
    // More precisely, a[j] must be at least j.
    // Let's call this `left_reach[i]`.
    // `left_reach[i]` is true if a[0] can be 0, a[1] can be 1, ..., a[i] can be i.
    // This means a[j] >= j for all j from 0 to i.
    // We can compute the maximum `i` such that `a[i] >= i`.
    int max_left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            max_left_len = i + 1;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // starting at index i, such that a[j] >= (n-1-j) for i <= j <= n-1.
    // This is equivalent to checking if a[j] can be made to be (n-1-j).
    // More precisely, a[j] must be at least (n-1-j).
    // Let's call this `right_reach[i]`.
    // `right_reach[i]` is true if a[i] can be (n-1-i), ..., a[n-1] can be 0.
    // This means a[j] >= (n-1-j) for all j from i to n-1.
    // We can compute the maximum `i` such that `a[i] >= (n-1-i)`.
    int max_right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            max_right_len = n - i;
        } else {
            break;
        }
    }

    // An array can be sharpened if there exists a peak k (0-indexed)
    // such that the prefix up to k can be made strictly increasing
    // and the suffix from k can be made strictly decreasing.
    //
    // The condition for the prefix a[0] < ... < a[k] to be achievable is
    // that for all j from 0 to k, a[j] >= j.
    // The condition for the suffix a[k] > ... > a[n-1] to be achievable is
    // that for all j from k to n-1, a[j] >= (n-1-j).
    //
    // We need to find if there is any k such that both conditions hold.
    // This means we need to find if there is an index k such that:
    // (k+1) <= max_left_len  AND  (n-k) <= max_right_len
    //
    // The first condition means k < max_left_len.
    // The second condition means k >= n - max_right_len.
    //
    // So we need to check if there exists a k such that:
    // n - max_right_len <= k < max_left_len
    // This is equivalent to checking if (n - max_right_len) < max_left_len.
    // Or, max_left_len + max_right_len > n.

    if (max_left_len + max_right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

