#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Total number of toys
    long long total_toys = A + B + C + D;

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Box 1: (-inf, -1]
    // Can it be the special box?
    // Final product must be negative and <= -1.
    // This requires an odd number of negative factors.
    // The magnitude must be >= 1.
    //
    // Scenario 1: Final product is negative.
    // This means (A+B) must be odd.
    // If A+B is odd, we can always make the final product negative.
    //
    // Scenario 2: Final product magnitude >= 1.
    // This requires at least one toy from Box 1 or Box 4, OR
    // a sequence of multiplications that eventually produces a value >= 1 or <= -1.
    //
    // If A+B is odd:
    //   If A+D >= 1 (at least one toy with magnitude >= 1):
    //     We can potentially make the final product <= -1.
    //     Example: (-2) * (0.5) * (0.5) = -0.5 (Box 2)
    //     Example: (-2) * (3) * (0.5) = -3 (Box 1)
    //     If A+D >= 1, we can always ensure the magnitude is >= 1.
    //     If A+D == 0, then all initial toys are in B or C.
    //       If A+B is odd, then B must be odd.
    //       If A+D == 0, then A=0, D=0. So B is odd.
    //       All toys are in B or C. All products will be in (0,1) or (-1,0).
    //       So, if A+D == 0, Box 1 is impossible.
    //
    // So, for Box 1: (A+B) is odd AND (A+D >= 1 OR (A+D == 0 AND B+C > 0 AND B is odd))
    // The condition (A+D >= 1 OR (A+D == 0 AND B+C > 0 AND B is odd)) simplifies.
    // If A+D == 0, then A=0, D=0. All toys are in B or C.
    //   If B is odd, the final product is negative.
    //   All products of toys from B and C will be in (-1, 1).
    //   So, if A+D == 0, the final product cannot be <= -1.
    // Therefore, A+D must be >= 1 for Box 1 to be possible.
    //
    // Simplified condition for Box 1: (A + B) % 2 == 1 && (A + D >= 1)
    if ((A + B) % 2 == 1 && (A + D >= 1)) {
        ans1 = "Ya";
    }

    // Box 2: (-1, 0)
    // Final product must be negative and between -1 and 0.
    // This requires an odd number of negative factors.
    // The magnitude must be < 1.
    //
    // Scenario 1: Final product is negative.
    // This means (A+B) must be odd.
    //
    // Scenario 2: Final product magnitude < 1.
    // This requires that we can make the final product magnitude < 1.
    // This is always possible if there are toys in B or C.
    // If A+D >= 1, we can always multiply by a small number from B or C to reduce magnitude.
    // If A+D == 0, then all toys are in B or C. All products will be in (-1, 1).
    //
    // So, for Box 2: (A + B) % 2 == 1
    // This is always possible if A+B is odd.
    if ((A + B) % 2 == 1) {
        ans2 = "Ya";
    }

    // Box 3: (0, 1)
    // Final product must be positive and between 0 and 1.
    // This requires an even number of negative factors.
    // The magnitude must be < 1.
    //
    // Scenario 1: Final product is positive.
    // This means (A+B) must be even.
    //
    // Scenario 2: Final product magnitude < 1.
    // This is always possible if there are toys in B or C.
    // If A+D >= 1, we can always multiply by a small number from B or C to reduce magnitude.
    // If A+D == 0, then all toys are in B or C. All products will be in (-1, 1).
    //
    // So, for Box 3: (A + B) % 2 == 0
    // This is always possible if A+B is even.
    if ((A + B) % 2 == 0) {
        ans3 = "Ya";
    }

    // Box 4: [1, inf)
    // Final product must be positive and >= 1.
    // This requires an even number of negative factors.
    // The magnitude must be >= 1.
    //
    // Scenario 1: Final product is positive.
    // This means (A+B) must be even.
    //
    // Scenario 2: Final product magnitude >= 1.
    // This requires at least one toy from Box 1 or Box 4, OR
    // a sequence of multiplications that eventually produces a value >= 1 or <= -1.
    //
    // If A+D >= 1, we can always ensure the magnitude is >= 1.
    // If A+D == 0, then all initial toys are in B or C.
    //   All products of toys from B and C will be in (-1, 1).
    //   So, if A+D == 0, Box 4 is impossible.
    //
    // So, for Box 4: (A + B) % 2 == 0 && (A + D >= 1)
    if ((A + B) % 2 == 0 && (A + D >= 1)) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

