struct Element {
    long long val;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.val < b.val;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].val;
        b_elements[i].original_index = i;
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B elements based on their values in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The i-th smallest B value (b_elements[i].val) should be paired with
    // the i-th largest A value (a[m-1-i]) to maximize F(A', B)
    // because F(n, k) = n / (k+1) is an increasing function of n.
    std::vector<long long> a_prime(m);
    for (int i = 0; i < m; ++i) {
        // b_elements[i] is the i-th smallest B value (0-indexed)
        // a[m - 1 - i] is the i-th largest A value (0-indexed)
        // We place a[m - 1 - i] at the original position of b_elements[i]
        a_prime[b_elements[i].original_index] = a[m - 1 - i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

