int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can be paired with any 'a' to its left.
            // Each such 'a' will eventually move past this 'b'.
            // The number of steps for this 'b' to move past all 'a's to its left
            // is equal to the current 'a_count'.
            // When an 'a' moves past a 'b', it becomes 'bba'.
            // The 'a' effectively moves to the right of the 'b'.
            // The 'b' stays in place, but a new 'b' is inserted.
            // The key insight is that an 'a' to the left of a 'b' will eventually
            // contribute to the total steps.
            // When we process a 'b', it means all 'a's to its right have already been processed.
            // Any 'a's to its left will eventually interact with this 'b'.
            // Each 'a' to the left of this 'b' will cause an "ab" -> "bba" operation.
            // The number of steps for this 'b' to be "cleared" of 'a's to its left
            // is `a_count`.
            // After these `a_count` operations, this 'b' will be followed by `a_count` 'a's.
            // Each of these operations also doubles the number of 'a's that are "active"
            // for future 'b's to its left.
            // More precisely, if we have `k` 'a's to the left of a 'b',
            // this 'b' will be involved in `k` operations.
            // After these `k` operations, the `k` 'a's are now to the right of this 'b'.
            // The crucial part is that each "ab" -> "bba" operation effectively
            // doubles the number of 'a's that are "available" to interact with
            // subsequent 'b's to their left.
            // Let `a_count` be the number of 'a's encountered so far (to the right of the current 'b').
            // When we see a 'b', it will interact with all `a_count` 'a's that are currently
            // "active" (meaning they are to the left of some 'b' that hasn't been fully processed yet).
            // Each such 'a' will cause an operation. So, `a_count` steps are added.
            // After these `a_count` steps, these `a_count` 'a's are now to the right of this 'b'.
            // But also, each of these `a_count` 'a's effectively doubles the number of 'a's
            // that are "active" for the next 'b' to the left.
            // So, the new `a_count` for the next 'b' will be `(a_count * 2) % mod`.

            total_steps = (total_steps + a_count) % mod;
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are available to interact with 'b's to its left.
            a_count = (a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

