// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    std::reverse(pattern.begin(), pattern.end()); // Digits were processed from right to left
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Using a map to store counts of each 18-digit parity pattern.
    // The key will be the 18-character string representing the pattern.
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            // Pad with leading zeros to make it 18 characters long
            pattern = std::string(18 - pattern.length(), '0') + pattern;
            counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            // Pad with leading zeros to make it 18 characters long
            pattern = std::string(18 - pattern.length(), '0') + pattern;
            counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with leading zeros to make it 18 characters long
            // This ensures it matches the format of keys in the map.
            s = std::string(18 - s.length(), '0') + s;
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

