int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left (i)
    // The number of items taken from the right will be n - i
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for imbalance
        if (i > j) { // More items from left than right
            // The last item taken was from the left.
            // If j items were taken from the right, and i items from the left,
            // then i-j items were taken from the left after the right items ran out.
            // The number of "extra" left items is i - j - 1.
            // This is equivalent to (i - j) - 1 if we consider the last item taken.
            // The problem states "If the previous action was the same (left-hand), then the robot spends extra Q_l energy units".
            // This means if we take L, L, L, R, L, L, L.
            // The first L has no penalty. The second L has Ql. The third L has Ql.
            // The R has no penalty. The next L has no penalty. The next L has Ql. The next L has Ql.
            // The interpretation of the problem is that if we take `i` items from left and `j` items from right,
            // and `i > j`, it means we took `i-j` more items from the left.
            // These `i-j` items must have been taken consecutively from the left after all `j` right items were taken.
            // So, `i-j-1` of these `i-j` items will incur a `Ql` penalty.
            // Example: n=3, i=3, j=0. LLL. Cost: w1*l + w2*l + Ql + w3*l + Ql.
            // Here i=3, j=0. i-j = 3. Penalty is (3-0-1)*Ql = 2*Ql.
            // Example: n=3, i=2, j=1. LLR. Cost: w1*l + w2*l + Ql + w3*r.
            // Here i=2, j=1. i-j = 1. Penalty is (2-1-1)*Ql = 0*Ql.
            // The number of "extra" items from the side with more items, that are taken consecutively after the other side is exhausted.
            // If i > j, then (i - j - 1) items from the left are "extra" and incur Ql.
            // This is equivalent to (i - j) items from the left, where the first one doesn't incur penalty, and the rest (i-j-1) do.
            // This applies if the last item taken was from the left.
            // The problem is about the *total* number of items taken from each side.
            // If i > j, it means we took i items from left and j items from right.
            // The difference is i-j.
            // If the last item taken was from the left, and we have i items from left and j items from right,
            // and i > j, then there are i-j "excess" left items.
            // The first i-j-1 of these will incur Ql penalty.
            // This is the case where the last item taken was from the left.
            // The number of "extra" items from the left is i - j.
            // If i - j > 0, then (i - j - 1) * Ql penalty.
            // This is for the case where the last item taken was from the left.
            // The problem statement is a bit ambiguous. "If the previous action was the same (left-hand)".
            // This implies a sequence of actions.
            // The common interpretation for this type of problem is that if you take `k` items from one side,
            // and `k'` items from the other, and `k > k'`, then `k-k'` items from the first side were taken
            // after the second side was exhausted.
            // The first of these `k-k'` items doesn't incur a penalty, but the subsequent `k-k'-1` items do.
            // So, if `i > j`, we add `(i - j - 1) * Ql`.
            // If `j > i`, we add `(j - i - 1) * Qr`.
            // This is the standard interpretation for this type of problem.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

