#include <iostream>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 0 means cannot move left (x-1). So, target X must be >= current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 0 means cannot move right (x+1). So, target X must be <= current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 0 means cannot move down (y-1). So, target Y must be >= current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 0 means cannot move up (y+1). So, target Y must be <= current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
            // Our calculated min_x, max_x, min_y, max_y might be outside this range,
            // but any point within [min_x, max_x] x [min_y, max_y] is valid.
            // We can just pick min_x and min_y, and clamp them to the guaranteed range if needed,
            // but the problem statement implies we don't need to clamp for output.
            // The coordinates can be up to 10^5 by absolute value.
            // The initial bounds for min/max are set to be very large/small.
            // The actual coordinates x_i, y_i are within [-10^5, 10^5].
            // So min_x and max_x will be within this range if a solution exists.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    long long sum_r = (b - 1);
    sum_r = (sum_r * b) % MOD;

    // Modular inverse of 2
    // Since MOD is prime (10^9 + 7), inv(2) = (MOD + 1) / 2
    long long inv2 = (MOD + 1) / 2;
    sum_r = (sum_r * inv2) % MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a
    long long sum_kb_plus_1 = (a * (a + 1)) % MOD;
    sum_kb_plus_1 = (sum_kb_plus_1 * inv2) % MOD; // (a * (a+1) / 2)
    sum_kb_plus_1 = (sum_kb_plus_1 * b) % MOD;    // b * (a * (a+1) / 2)
    sum_kb_plus_1 = (sum_kb_plus_1 + a) % MOD;    // + a

    long long total_sum = (sum_r * sum_kb_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

