void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    bool possible = true;
    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::set<char> visited;
    char start_char = '\0';

    // Find a starting point for the layout (a character with only one adjacency)
    for (const auto& pair : adj) {
        if (pair.second.size() == 1) {
            start_char = pair.first;
            break;
        }
    }

    // If all characters in the password have two adjacencies (e.g., 'abacaba' -> 'a' connected to 'b' and 'c'),
    // or if the password is a single character, pick the first character of the password.
    if (start_char == '\0' && !s.empty()) {
        start_char = s[0];
    }

    // If password is empty (not possible by constraints, but for completeness)
    if (start_char == '\0') {
        for (char c = 'a'; c <= 'z'; ++c) {
            layout += c;
        }
        std::cout << "YES\n" << layout << "\n";
        return;
    }

    // Build the core layout from the password's adjacencies
    char current_char = start_char;
    char prev_char = '\0'; // Sentinel for the first step

    while (current_char != '\0' && visited.find(current_char) == visited.end()) {
        layout += current_char;
        visited.insert(current_char);

        char next_char = '\0';
        if (adj.count(current_char)) {
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
        }
        prev_char = current_char;
        current_char = next_char;
    }

    // Add remaining characters not in the password
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n" << layout << "\n";
}

