    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    if (k * k < n) {
        k++;
    }

    // The optimal construction strategy is to divide the numbers into blocks of size k
    // and reverse each block.
    // For example, if n=4, k=2: [2,1, 4,3]
    // If n=5, k=3: [3,2,1, 5,4]
    // If n=6, k=3: [3,2,1, 6,5,4]
    // If n=7, k=3: [3,2,1, 6,5,4, 7]
    // If n=8, k=3: [3,2,1, 6,5,4, 8,7]
    // If n=9, k=3: [3,2,1, 6,5,4, 9,8,7]

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_idx = i;
        int block_end_idx = std::min(i + k, n);

        // Fill the block in decreasing order
        for (int j = block_end_idx - 1; j >= block_start_idx; --j) {
            p[j] = current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char c1 = s[k_actual]; // t[0] for this k_actual

        // Find all possible k' values that would result in the same t[0]
        const std::vector<int>& possible_k_values = char_indices[c1 - 'a'];

        if (possible_k_values.size() == 1) {
            // If only one k' results in this c1, Vasya wins immediately.
            // This k_actual is uniquely determined.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose a position p (1-indexed) to maximize win probability.
        // p can range from 2 to n. (p-1 from 1 to n-1)
        // For each possible p, calculate how many k' values are uniquely determined.
        int max_wins_for_this_c1 = 0;

        // Iterate over all possible positions p-1 (0-indexed) that Vasya can choose.
        // p-1 ranges from 1 to n-1.
        for (int p_minus_1 = 1; p_minus_1 < n; ++p_minus_1) {
            std::map<char, std::vector<int>> candidates_by_c2;
            for (int k_prime : possible_k_values) {
                char c2 = s[(p_minus_1 + k_prime) % n];
                candidates_by_c2[c2].push_back(k_prime);
            }

            int current_p_wins = 0;
            for (const auto& pair : candidates_by_c2) {
                if (pair.second.size() == 1) {
                    current_p_wins++;
                }
            }
            max_wins_for_this_c1 = std::max(max_wins_for_this_c1, current_p_wins);
        }
        total_win_prob += static_cast<double>(max_wins_for_this_c1) / possible_k_values.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val0 = 0;    // Result if input is 0
    int current_val1 = 1023; // Result if input is 1023 (all 1s for 10 bits)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val0 &= x;
            current_val1 &= x;
        } else if (op_char == '|') {
            current_val0 |= x;
            current_val1 |= x;
        } else if (op_char == '^') {
            current_val0 ^= x;
            current_val1 ^= x;
        }
    }

    // Now we have current_val0 and current_val1.
    // For each bit position j (0 to 9):
    // If input bit is 0, output bit is (current_val0 >> j) & 1
    // If input bit is 1, output bit is (current_val1 >> j) & 1

    // We need to find A, B, C such that:
    // (x & A | B) ^ C
    // or (x | B) ^ C & A
    // or (x ^ C) & A | B
    // ...
    // The general form is (x & A_and | A_or) ^ A_xor

    int final_and_mask = 1023; // A_and
    int final_or_mask = 0;    // A_or
    int final_xor_mask = 0;   // A_xor

    for (int j = 0; j < 10; ++j) {
        int bit0_result = (current_val0 >> j) & 1;
        int bit1_result = (current_val1 >> j) & 1;

        if (bit0_result == 0 && bit1_result == 0) {
            // Input 0 -> Output 0
            // Input 1 -> Output 0
            // This means the bit is always 0, regardless of input.
            // To achieve this:
            // (x & 0 | 0) ^ 0 = 0
            // (x & 1 | 0) ^ 1 = 0
            // (x & 0 | 1) ^ 1 = 0
            // (x & 1 | 1) ^ 1 = 0
            // Simplest: force to 0.
            // Set A_and's j-th bit to 0.
            final_and_mask &= ~(1 << j);
            // A_or's j-th bit is 0.
            // A_xor's j-th bit is 0.
        } else if (bit0_result == 0 && bit1_result == 1) {
            // Input 0 -> Output 0
            // Input 1 -> Output 1
            // This means the bit is unchanged (identity).
            // To achieve this:
            // (x & 1 | 0) ^ 0 = x
            // Set A_and's j-th bit to 1.
            // A_or's j-th bit is 0.
            // A_xor's j-th bit is 0.
        } else if (bit0_result == 1 && bit1_result == 0) {
            // Input 0 -> Output 1
            // Input 1 -> Output 0
            // This means the bit is flipped (NOT).
            // To achieve this:
            // (x & 1 | 0) ^ 1 = ~x
            // Set A_and's j-th bit to 1.
            // A_or's j-th bit is 0.
            // Set A_xor's j-th bit to 1.
            final_xor_mask |= (1 << j);
        } else { // bit0_result == 1 && bit1_result == 1
            // Input 0 -> Output 1
            // Input 1 -> Output 1
            // This means the bit is always 1, regardless of input.
            // To achieve this:
            // (x & 0 | 1) ^ 0 = 1
            // (x & 1 | 1) ^ 0 = 1
            // Simplest: force to 1.
            // A_and's j-th bit is 0 or 1.
            // Set A_or's j-th bit to 1.
            // A_xor's j-th bit is 0.
            final_or_mask |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> simplified_ops;
    if (final_and_mask != 1023) { // If A_and is not all 1s
        simplified_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If A_or is not all 0s
        simplified_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If A_xor is not all 0s
        simplified_ops.push_back({'^', final_xor_mask});
    }

    std::cout << simplified_ops.size() << std::endl;
    for (const auto& op : simplified_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int initial_diff = initial_s - initial_b;

    // Calculate prefix sums for the left half (jars 0 to n-1)
    // diff_L[i] = (count of 1s - count of 2s) in jars 0 to i-1
    // diff_L[0] = 0
    // diff_L[i] = (count of 1s - count of 2s) in jars 0 to i-1
    // This means if we keep jars from index i to n-1, the eaten jars are 0 to i-1.
    // The difference for eaten jars is diff_L[i].
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right half (jars n to 2n-1)
    // diff_R[i] = (count of 1s - count of 2s) in jars i to 2n-1
    // This means if we keep jars from index n to i-1, the eaten jars are i to 2n-1.
    // The difference for eaten jars is diff_R[i].
    // We want to store the difference for the *eaten* jars.
    // Let's define diff_R_eaten[k] as the difference (S-B) for the first k jars eaten from the right.
    // These are jars 2n-1, 2n-2, ..., 2n-k.
    // Or, if we consider jars n, n+1, ..., 2n-1.
    // If we eat k jars from the right, we eat jars 2n-1, 2n-2, ..., 2n-k.
    // The remaining jars are n, ..., 2n-k-1.
    // Let's use a map to store the minimum number of jars eaten from the right to achieve a certain difference.
    // The difference is (S-B) for the jars *eaten* from the right.
    std::map<int, int> min_eaten_R_for_diff;
    min_eaten_R_for_diff[0] = 0; // 0 jars eaten from right, diff is 0
    int current_diff_R_eaten = 0;
    for (int k = 1; k <= n; ++k) {
        // Jar 2n-k is the k-th jar from the right end (0-indexed)
        // Or, jar n+k-1 is the k-th jar from the start of the right half (0-indexed relative to right half)
        // We are eating jars from the right: 2n-1, 2n-2, ..., 2n-k.
        // The difference for these k jars.
        current_diff_R_eaten += (a[2 * n - k] == 1 ? 1 : -1);
        if (min_eaten_R_for_diff.find(current_diff_R_eaten) == min_eaten_R_for_diff.end()) {
            min_eaten_R_for_diff[current_diff_R_eaten] = k;
        }
    }

    int min_total_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possibilities of eating jars from the left side.
    // k_L is the number of jars eaten from the left (0 to n).
    // These are jars 0, ..., k_L-1.
    for (int k_L = 0; k_L <= n; ++k_L) {
        int diff_L_eaten = diff_L[k_L]; // (S-B) for jars 0 to k_L-1

        // The remaining jars have an initial difference of initial_diff.
        // If we eat k_L jars from left and k_R jars from right,
        // the difference of remaining jars will be:
        // initial_diff - diff_L_eaten - diff_R_eaten = 0
        // So, diff_R_eaten must be equal to initial_diff - diff_L_eaten.
        int target_diff_R_eaten = initial_diff - diff_L_eaten;

        if (min_eaten_R_for_diff.count(target_diff_R_eaten)) {
            int k_R = min_eaten_R_for_diff[target_diff_R_eaten];
            min_total_eaten = std::min(min_total_eaten, k_L + k_R);
        }
    }

    std::cout << min_total_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        long long good_substrings_count = 0;

        // Max length for which 2^len-1 <= N is log2(N+1).
        // For N = 2e5, log2(2e5+1) is approx 17.6. So max_k is 17.
        // We can safely check up to k=18 or k=19 to be sure.
        // Let's use 19 as a safe upper bound for k.
        const int MAX_K = 19; 

        // Iterate through all possible starting positions l
        for (int l = 0; l < n; ++l) {
            long long current_val = 0;
            // Iterate through possible ending positions r, forming substrings s[l...r]
            // We only need to check substrings where s[l] is '1' for small lengths,
            // or where s[l] is '0' and we count leading zeros.
            // The problem definition f(t) allows leading zeros.
            // Example: f(011) = 3. Length is 3. So 011 is good.
            // Example: f(000) = 0. Length is 3. Not good.
            // Example: f(000100) = 4. Length is 6. Not good.

            // For substrings starting with '0', we need to handle them carefully.
            // The value `current_val` will be 0 until a '1' is encountered.
            // If s[l] is '0', then current_val will be 0 for s[l...l].
            // If s[l...r] consists only of '0's, current_val will be 0.
            // In this case, length = r - l + 1. If length == 0, it's good.
            // But length is always >= 1. So a substring of all '0's is never good.
            // This means we only need to consider substrings where current_val > 0.
            // Or, more precisely, if current_val == 0, then length must be 0, which is impossible.
            // So we only care about substrings whose binary value is positive.

            // Let's re-evaluate the logic for `current_val`.
            // `current_val` is the decimal value of `s[l...r]`.
            // `len` is `r - l + 1`.
            // We need `len == current_val`.

            // For each `l`, we can iterate `r` up to `l + MAX_K - 1`.
            // For these short substrings, we calculate `current_val` directly.
            for (int r = l; r < n; ++r) {
                int len = r - l + 1;
                if (len > MAX_K) { // Optimization: if length is too large, current_val will be too large.
                                   // If s[l] is '1', current_val will be at least 2^(len-1).
                                   // If len > MAX_K, then 2^(len-1) > 2^(MAX_K-1).
                                   // MAX_K is 19, so 2^(18) = 262144.
                                   // N is 2e5. So if len > MAX_K, current_val will be much larger than N.
                                   // Thus, current_val cannot equal len.
                                   // This optimization is only valid if s[l] is '1'.
                                   // If s[l] is '0', current_val can still be small.
                                   // So we need to be careful.

                    // If s[l] is '0', we can potentially have a long string of leading zeros
                    // followed by a '1'.
                    // Example: 00000000000000000101 (length 20, value 5).
                    // This is why we need to iterate r further.
                    // The maximum possible value for `len` is `n`.
                    // The maximum possible value for `current_val` is `2^n - 1`.
                    // We are looking for `len == current_val`.
                    // This implies `current_val <= n`.
                    // If `current_val` exceeds `n`, we can stop extending `r` for this `l`.
                    // `n` is up to 2e5. `2^18` is 262144. `2^17` is 131072.
                    // So `current_val` can be at most `n`, which means it can be at most `2^17` or `2^18`.
                    // This means the length of the binary string `s[l...r]` that represents `current_val`
                    // can be at most 18 or 19 bits.
                    // So `r - l + 1` can be at most `n`.
                    // The number of bits required to represent `current_val` is `floor(log2(current_val)) + 1`.
                    // If `current_val` is `len`, then `len` must be representable by `len` bits.
                    // This is always true.
                    // The key is that `current_val` cannot exceed `n`.
                    // If `current_val` exceeds `n`, then `current_val` cannot be equal to `len` (since `len <= n`).
                    // So we can stop extending `r` if `current_val > n`.

                    // Update current_val:
                    // current_val = current_val * 2 + (s[r] - '0');
                    // If current_val becomes greater than n, then it can never be equal to len (since len <= n).
                    // So we can break.
                    // This check should be inside the loop, after updating current_val.
                }

                current_val = current_val * 2 + (s[r] - '0');

                // If current_val exceeds n, it can never be equal to len (since len <= n).
                // So we can break from the inner loop for this `l`.
                if (current_val > n) {
                    break;
                }

                if (current_val == len) {
                    good_substrings_count++;
                }
            }
        }
        std::cout << good_substrings_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply one step of median smoothing
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    std::vector<int> b(n);
    if (n == 0) return b;

    b[0] = a[0];
    if (n > 1) {
        b[n - 1] = a[n - 1];
    }

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        b[i] = (sum >= 2) ? 1 : 0;
    }
    return b;
}

// Function to check if a sequence is stable
bool is_stable(const std::vector<int>& a) {
    int n = a.size();
    if (n <= 2) return true; // Sequences of length 1 or 2 are always stable by definition

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        int median_val = (sum >= 2) ? 1 : 0;
        if (median_val != a[i]) {
            return false;
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Find the first 0-1 block and 1-0 block
    int first_01 = -1; // Index of '0' in the first '01' pattern
    int first_10 = -1; // Index of '1' in the first '10' pattern
    int last_01 = -1;  // Index of '0' in the last '01' pattern
    int last_10 = -1;  // Index of '1' in the last '10' pattern

    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 0 && a[i + 1] == 1) {
            if (first_01 == -1) first_01 = i;
            last_01 = i;
        } else if (a[i] == 1 && a[i + 1] == 0) {
            if (first_10 == -1) first_10 = i;
            last_10 = i;
        }
    }

    if (first_01 == -1 && first_10 == -1) { // Sequence is already stable (all 0s or all 1s)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Calculate steps to stability
    int steps = 0;
    if (first_01 != -1) { // There is at least one 01 pattern
        steps = std::max(steps, (first_01 + 1) / 2);
        steps = std::max(steps, (n - 1 - last_01) / 2);
    }
    if (first_10 != -1) { // There is at least one 10 pattern
        steps = std::max(steps, (first_10 + 1) / 2);
        steps = std::max(steps, (n - 1 - last_10) / 2);
    }

    // Construct the stable sequence
    std::vector<int> stable_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (i <= steps - 1) { // Left part becomes a[0]
            stable_a[i] = a[0];
        } else if (i >= n - steps) { // Right part becomes a[n-1]
            stable_a[i] = a[n - 1];
        } else { // Middle part
            // If a[i-1] and a[i+1] are different, it means it's a 0...01...1 or 1...10...0 pattern
            // The middle part will be determined by the closest stable boundary
            // If a[i] is 0 and a[i+1] is 1, and i is far from boundaries, it will become 0
            // If a[i] is 1 and a[i-1] is 0, and i is far from boundaries, it will become 1
            // This logic is simplified by the observation that the stable sequence is formed by
            // extending a[0] from left and a[n-1] from right, and the middle part is 0 if a[0]=0, a[n-1]=0
            // or 1 if a[0]=1, a[n-1]=1. If a[0]!=a[n-1], then it's 0...01...1 or 1...10...0.
            // The actual stable sequence is a[0] repeated up to first_01+steps, then a[n-1] repeated from last_10-steps.
            // The core idea is that 0s propagate right and 1s propagate left.
            // A 0 at index `k` will turn `k+1` into 0 if `a[k+1]` is 1 and `a[k+2]` is 0.
            // A 1 at index `k` will turn `k-1` into 1 if `a[k-1]` is 0 and `a[k-2]` is 1.
            // The stable sequence is effectively `a[0]` for `i < first_10 + steps` and `a[n-1]` for `i > last_01 - steps`.
            // This is equivalent to:
            // If `i` is closer to `a[0]`'s influence (left side) than `a[n-1]`'s influence (right side), it takes `a[0]`.
            // Otherwise, it takes `a[n-1]`.
            // The "middle" point where it switches is `(first_10 + last_01 + 1) / 2` if `a[0]=0, a[n-1]=1`.
            // Or `(first_01 + last_10 + 1) / 2` if `a[0]=1, a[n-1]=0`.
            // A simpler way: if `i` is within `steps` distance from `a[0]`'s original position, it becomes `a[0]`.
            // If `i` is within `steps` distance from `a[n-1]`'s original position, it becomes `a[n-1]`.
            // If `a[0] == a[n-1]`, then the whole sequence becomes `a[0]`.
            // If `a[0] != a[n-1]`, then it becomes `a[0]` up to some point, then `a[n-1]` from that point.
            // The transition point is `(first_10 + last_01 + 1) / 2` if `a[0]=0, a[n-1]=1`.
            // The transition point is `(first_01 + last_10 + 1) / 2` if `a[0]=1, a[n-1]=0`.
            // The stable sequence is `a[0]` for `i <= first_10 + steps` and `a[n-1]` for `i >= last_01 - steps`.
            // This is equivalent to:
            if (i < first_10 + steps + 1) { // If a[0] is 0, this is the rightmost 0 that can be formed from the left.
                stable_a[i] = a[0];
            } else if (i > last_01 - steps - 1) { // If a[n-1] is 1, this is the leftmost 1 that can be formed from the right.
                stable_a[i] = a[n - 1];
            } else {
                // This case should not be reached if the logic for steps is correct and the sequence stabilizes.
                // It implies a region that is not influenced by boundaries within `steps` iterations.
                // For binary sequences, if a[0] != a[n-1], the middle will be a transition.
                // If a[0] == a[n-1], the whole sequence becomes a[0].
                stable_a[i] = a[0]; // Default to a[0] if it's not covered by the above.
            }
