    }

    // The actual stable sequence is simpler:
    // If a[0] == a[n-1], the whole sequence becomes a[0].
    // If a[0] != a[n-1]:
    //   If a[0] == 0 and a[n-1] == 1:
    //     The sequence becomes 0...01...1. The transition point is `first_10 + steps`.
    //     All elements `i` such that `i <= first_10 + steps` become 0.
    //     All elements `i` such that `i >= last_01 - steps` become 1.
