    //     The sequence becomes 1...10...0. The transition point is `first_01 + steps`.
    //     All elements `i` such that `i <= first_01 + steps` become 1.
    //     All elements `i` such that `i >= last_10 - steps` become 0.

    // Re-calculate stable_a based on this simpler logic
    if (a[0] == a[n - 1]) {
        std::fill(stable_a.begin(), stable_a.end(), a[0]);
    } else {
        if (a[0] == 0 && a[n - 1] == 1) { // 0...01...1
            int transition_idx = first_10 + steps;
            for (int i = 0; i < n; ++i) {
                stable_a[i] = (i <= transition_idx) ? 0 : 1;
            }
        } else { // a[0] == 1 && a[n-1] == 0, so 1...10...0
            int transition_idx = first_01 + steps;
            for (int i = 0; i < n; ++i) {
                stable_a[i] = (i <= transition_idx) ? 1 : 0;
            }
        }
    }

    std::cout << steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << stable_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, 0);
    std::vector<long long> current_delta(n, 0);

    // Initialize initial_a with maximum possible values based on type 2 operations
    // For each type 2 operation (l, r, m), for all j in [l, r], a_j + current_delta[j] <= m.
    // This means a_j <= m - current_delta[j].
    // We want to find the largest possible initial_a[j] that satisfies all constraints.
    // So, initial_a[j] = min(m - current_delta[j]) over all type 2 operations covering j.
    // Since we don't know current_delta[j] yet for future operations, we can iterate backwards.
    // However, the problem asks for *any* suitable array.
    // A simpler approach is to initialize initial_a[j] to a very large value,
    // and then for each type 2 operation, update initial_a[j] = min(initial_a[j], m - current_delta[j])
    // for all j in [l, r]. This is incorrect because current_delta[j] changes.

    // Correct approach:
    // For each element a_i, its value at any point is a_i_initial + sum_of_deltas_applied_to_i.
    // Let a_i_initial be x_i.
    // For a type 2 query (l, r, m), we know that for all j in [l, r], x_j + sum_of_deltas_applied_to_j_at_this_point <= m.
    // This means x_j <= m - sum_of_deltas_applied_to_j_at_this_point.
    // To satisfy all such constraints, x_j must be less than or equal to the minimum of (m - sum_of_deltas_applied_to_j_at_this_point)
    // over all type 2 queries that cover j.
    // Let's define `b[j]` as the initial value of `a[j]`.
    // We want to find `b[j]` such that `b[j] + current_delta[j] <= m` for all type 2 operations.
    // So, `b[j] <= m - current_delta[j]`.
    // We can initialize `b[j]` to a very large value (e.g., 10^9).
    // Then, iterate through operations. If it's type 1, update `current_delta`.
    // If it's type 2, for each `j` in `[l, r]`, update `b[j] = min(b[j], m - current_delta[j])`.
    // This gives us the maximum possible `b[j]` values that satisfy all upper bound constraints.

    std::vector<long long> b(n, 1000000000LL); // Initialize b[j] to max allowed initial value
    std::fill(current_delta.begin(), current_delta.end(), 0LL);

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // type 2
            for (int j = op.l; j <= op.r; ++j) {
                b[j] = std::min(b[j], op.val - current_delta[j]);
            }
        }
    }

    // Now we have a candidate array `b`. We need to verify if it works.
    // Apply all operations to `b` and check if type 2 constraints are met.
    std::fill(current_delta.begin(), current_delta.end(), 0LL);
    bool possible = true;

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = op.l; j <= op.r; ++j) {
                max_val_in_range = std::max(max_val_in_range, b[j] + current_delta[j]);
            }
            if (max_val_in_range != op.val) {
                possible = false;
                break;
            }
        }
    }

    if (possible) {
        std::cout << "YES\n";
        for (int i = 0; i < n; ++i) {
            std::cout << b[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

