struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line; // To mark if child has left

    Child(long long v_val, long long d_val, long long p_val, int idx)
        : v(v_val), d(d_val), p(p_val), original_idx(idx), in_line(true) {}
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children_data;
    children_data.reserve(n);
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_data.emplace_back(v_val, d_val, p_val, i + 1);
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children_data[i].in_line) {
            continue; // This child has already left
        }

        // Child i goes to the doctor
        cured_children_indices.push_back(children_data[i].original_idx);
        children_data[i].in_line = false; // Mark as cured

        long long current_v_effect = children_data[i].v;
        long long total_d_effect_from_chain = 0;

        // Apply effects to children after child i
        for (int j = i + 1; j < n; ++j) {
            if (!children_data[j].in_line) {
                continue;
            }

            // Apply crying from child i
            if (current_v_effect > 0) {
                children_data[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Apply accumulated d_effect from chain reaction
            children_data[j].p -= total_d_effect_from_chain;

            // Check for chain reaction
            if (children_data[j].p < 0 && children_data[j].in_line) {
                children_data[j].in_line = false; // Child j leaves
                total_d_effect_from_chain += children_data[j].d; // Add its d_effect to subsequent children
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

