int N;

long long solve(int current_x) {
    if (current_x <= 0 || current_x > N) {
        return 0; // Base case: terminated, no further y accumulation
    }

    if (memo[current_x] != 0) {
        if (memo[current_x] == -1) {
            return -2; // Cycle detected
        }
        return memo[current_x];
    }

    memo[current_x] = -1; // Mark as currently visiting

    long long val1 = a_full[current_x];

    // Step 2: x_new = current_x + val1, y_add = val1
    int x_after_step2 = current_x + val1;
    long long y_add_step2 = val1;

    if (x_after_step2 <= 0 || x_after_step2 > N) {
        memo[current_x] = y_add_step2; // Terminates after step 2
        return y_add_step2;
    }

    long long val2 = a_full[x_after_step2];

    // Step 3: x_new = x_after_step2 - val2, y_add = y_add_step2 + val2
    int x_after_step3 = x_after_step2 - val2;
    long long y_add_step3 = y_add_step2 + val2;

    // Now recursively call solve for x_after_step3
    long long res_from_next_state = solve(x_after_step3);

    if (res_from_next_state == -2) {
        memo[current_x] = -2; // Propagate infinite loop
        return -2;
    }

    memo[current_x] = y_add_step3 + res_from_next_state;
    return memo[current_x];
}


