#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // All f values are a_i + a_j.
    // min_f = min_a + elements[1].value
    // max_f = max_a + elements[n-2].value
    // Goodness = (max_a + elements[n-2].value) - (min_a + elements[1].value)
    long long goodness1 = (max_a + elements[n - 2].value) - (min_a + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: All elements in different subsequences (e.g., subsequence 2).
    // This is identical to Case 1 in terms of goodness.
    // Goodness = (max_a + elements[n-2].value) - (min_a + elements[1].value)
    // partition2 is all 2s.

    // Case 3: Partition into two non-empty subsequences.
    // This case is more complex.
    // The minimum possible f value is min_a + elements[1].value (if they are in the same group)
    // or min_a + elements[1].value + h (if they are in different groups).
    // The maximum possible f value is max_a + elements[n-2].value (if they are in the same group)
    // or max_a + elements[n-2].value + h (if they are in different groups).

    // Consider the minimum possible f value:
    // It must be min_a + elements[1].value (if elements[0] and elements[1] are in the same group)
    // OR min_a + elements[0].value + h (if elements[0] and elements[0] are in different groups, which is not possible)
    // OR min_a + elements[1].value + h (if elements[0] and elements[1] are in different groups)
    // The smallest possible sum is A_1 + A_2.
    // The smallest possible f value is A_1 + A_2.
    // The largest possible f value is A_{n-1} + A_n + h.

    // Let's analyze the range of f values.
    // The smallest possible sum of two elements is elements[0].value + elements[1].value.
    // The largest possible sum of two elements is elements[n-1].value + elements[n-2].value.

    // If we put elements[0] in group 1 and elements[n-1] in group 2:
    // min_f could be elements[0].value + elements[1].value (if elements[1] is in group 1)
    // or elements[0].value + elements[n-1].value + h (if elements[0] and elements[n-1] are in different groups)
    // max_f could be elements[n-1].value + elements[n-2].value (if elements[n-2] is in group 2)
    // or elements[n-1].value + elements[0].value + h (if elements[n-1] and elements[0] are in different groups)

    // The crucial observation is that to minimize max_f - min_f, we want to make the range of f values as small as possible.
    // The values `a_i + a_j` are in `[min_a + elements[1].value, max_a + elements[n-2].value]`.
    // The values `a_i + a_j + h` are in `[min_a + elements[1].value + h, max_a + elements[n-2].value + h]`.

    // If h is very large, it's usually better to put all elements in one group to avoid the `+h` term.
    // This is covered by Case 1.

    // What if h is small enough that `min_a + elements[1].value + h` is not much larger than `min_a + elements[1].value`?
    // Consider a partition where elements[0] is in group 1, and elements[n-1] is in group 2.
    // All other elements can be in either group.
    // The minimum possible f value will be `min_a + elements[1].value` (if elements[1] is in group 1)
    // OR `min_a + elements[0].value + h` (if elements[0] is in group 1 and elements[0] is in group 2, not possible)
    // OR `min_a + elements[1].value + h` (if elements[0] is in group 1 and elements[1] is in group 2)
    // The smallest possible sum is `elements[0].value + elements[1].value`.
    // The largest possible sum is `elements[n-1].value + elements[n-2].value`.

    // Let's consider a specific partition:
    // Put elements[0] in group 1.
    // Put elements[n-1] in group 2.
    // Put all other elements (elements[1] to elements[n-2]) in group 1.
    // Subsequence 1: {elements[0], elements[1], ..., elements[n-2]}
    // Subsequence 2: {elements[n-1]}
    //
    // Pairs within Subsequence 1:
    // Min sum: elements[0].value + elements[1].value
    // Max sum: elements[n-2].value + elements[n-3].value (if n-3 >= 0, i.e., n >= 3)
    // If n=2, Subsequence 1 is {elements[0]}, no pairs.
    //
    // Pairs within Subsequence 2:
    // No pairs if only one element.
    //
    // Pairs between Subsequence 1 and Subsequence 2:
    // All pairs (elements[i], elements[n-1]) for i from 0 to n-2.
    // Min sum: elements[0].value + elements[n-1].value + h
    // Max sum: elements[n-2].value + elements[n-1].value + h

    // Let's simplify.
    // The minimum possible value of `a_i + a_j` is `elements[0].value + elements[1].value`.
    // The maximum possible value of `a_i + a_j` is `elements[n-1].value + elements[n-2].value`.

    // Option A: All elements in one group (e.g., group 1).
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    // This is `goodness1` calculated above.

    // Option B: Put elements[0] in group 1, and all other elements in group 2.
    // Subsequence 1: {elements[0]}
    // Subsequence 2: {elements[1], ..., elements[n-1]}
    //
    // Pairs within Subsequence 1: None.
    // Pairs within Subsequence 2:
    //   Min sum: elements[1].value + elements[2].value (if n >= 3)
    //   Max sum: elements[n-1].value + elements[n-2].value (if n >= 3)
    // Pairs between Subsequence 1 and Subsequence 2:
    //   All pairs (elements[0], elements[j]) for j from 1 to n-1.
    //   Min sum: elements[0].value + elements[1].value + h
    //   Max sum: elements[0].value + elements[n-1].value + h
    //
    // Overall min_f:
    //   If n=2: only (elements[0], elements[1]) pair, different groups. min_f = elements[0].value + elements[1].value + h.
    //   If n >= 3: min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // Overall max_f:
    //   If n=2: max_f = elements[0].value + elements[1].value + h.
    //   If n >= 3: max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // Goodness for Option B:
    // min_f_B = elements[0].value + elements[1].value + h; // This is the smallest possible f value if elements[0] and elements[1] are in different groups.
    // max_f_B = elements[n-1].value + elements[n-2].value; // This is the largest possible f value if elements[n-1] and elements[n-2] are in the same group.
    //
    // This is not quite right. We need to consider all f values.
    // Let's define `min_sum_same = elements[0].value + elements[1].value`
    // Let `max_sum_same = elements[n-1].value + elements[n-2].value`
    //
    // For Option B (elements[0] in group 1, rest in group 2):
    // All pairs (elements[0], elements[j]) for j > 0 are `elements[0].value + elements[j].value + h`.
    // All pairs (elements[i], elements[j]) for i,j > 0 are `elements[i].value + elements[j].value`.
    //
    // min_f_B = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h); (if n >= 3)
    // If n=2, min_f_B = elements[0].value + elements[1].value + h.
    //
    // max_f_B = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h); (if n >= 3)
    // If n=2, max_f_B = elements[0].value + elements[1].value + h.
    //
    // Let's consider the specific partition where elements[0] is in group 1, and all other elements are in group 2.
    // This is a candidate for optimal solution when h is large.
    //
    // min_f_candidate_B:
    // If n=2: elements[0].value + elements[1].value + h
    // If n > 2: std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //
    // max_f_candidate_B:
    // If n=2: elements[0].value + elements[1].value + h
    // If n > 2: std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // Goodness_B = max_f_candidate_B - min_f_candidate_B.
    //
    // Let's calculate this goodness.
    long long min_f_B, max_f_B;
    if (n == 2) {
        min_f_B = elements[0].value + elements[1].value + h;
        max_f_B = elements[0].value + elements[1].value + h;
    } else {
        min_f_B = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        max_f_B = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
    }
    long long goodness_B = max_f_B - min_f_B;
    std::vector<int> partition_B(n);
    partition_B[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_B[elements[i].original_index] = 2;
    }

    // Compare goodness1 and goodness_B
    long long min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    if (goodness_B < min_goodness) {
        min_goodness = goodness_B;
        best_partition = partition_B;
    }

    // There is one more critical case:
    // Put elements[0] and elements[1] in group 1.
    // Put all other elements (elements[2] to elements[n-1]) in group 2.
    // This is relevant if h is small.
    //
    // Subsequence 1: {elements[0], elements[1]}
    // Subsequence 2: {elements[2], ..., elements[n-1]}
    //
    // Pairs within Subsequence 1:
    // Only (elements[0], elements[1]). Sum: elements[0].value + elements[1].value.
    //
    // Pairs within Subsequence 2:
    // Min sum: elements[2].value + elements[3].value (if n >= 4)
    // Max sum: elements[n-1].value + elements[n-2].value (if n >= 4)
    //
    // Pairs between Subsequence 1 and Subsequence 2:
    // All pairs (elements[i], elements[j]) where i in {0,1} and j in {2,...,n-1}.
    // Min sum: elements[0].value + elements[2].value + h
    // Max sum: elements[1].value + elements[n-1].value + h
    //
    // This partition is only possible if n >= 2.
    // If n=2: Subsequence 1: {elements[0], elements[1]}, Subsequence 2: {}. This is Case 1.
    // If n=3: Subsequence 1: {elements[0], elements[1]}, Subsequence 2: {elements[2]}
    //   min_f = elements[0].value + elements[1].value
    //   max_f = elements[1].value + elements[2].value + h
    //   Goodness = (elements[1].value + elements[2].value + h) - (elements[0].value + elements[1].value)
    //            = elements[2].value - elements[0].value + h
    //
    // Let's calculate goodness for this partition (elements[0], elements[1] in group 1, rest in group 2)
    // This partition is only distinct from Case 1 if n >= 3.
    if (n >= 3) {
        long long min_f_C, max_f_C;
        min_f_C = elements[0].value + elements[1].value; // From (elements[0], elements[1])

        if (n == 3) {
            max_f_C = elements[1].value + elements[2].value + h; // From (elements[1], elements[2])
        } else { // n >= 4
            max_f_C = std::max({elements[n-1].value + elements[n-2].value, // From within group 2
                                elements[1].value + elements[n-1].value + h}); // From between groups
        }

        long long goodness_C = max_f_C - min_f_C;

        if (goodness_C < min_goodness) {
            min_goodness = goodness_C;
            best_partition.assign(n, 2); // Initialize all to group 2
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 1;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

