// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int len_a = a.length();
    int len_b = b.length();

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // The maximum number of '1's we can have in 'a' after appending parities
    // If current parity is 0, we append '0', count of '1's doesn't change.
    // If current parity is 1, we append '1', count of '1's increases by 1.
    // So, the count of '1's can only increase if the current parity is 1.
    // The maximum possible count of '1's in 'a' after any number of operations
    // is its initial count of '1's plus the number of '0's in 'a'.
    // This is because each '0' could potentially be replaced by a '1' if we
    // append '1's until the string becomes long enough, and then remove
    // characters from the front.
    // A simpler way to think about it:
    // The number of '1's in 'a' can only increase if we append a '1'.
    // This happens when parity is 1.
    // If we append '0', the number of '1's doesn't change.
    // The maximum number of '1's in any string derived from 'a' that has length L_a'
    // is the initial count of '1's in 'a' plus the number of '1's we could
    // append.
    // The number of '1's we can append is at most the number of times we append '1'.
    // The total number of '1's in 'a' can be at most its current length.
    // The maximum number of '1's in 'a' after any number of operations
    // (including appending parities) is the initial count of '1's in 'a'
    // plus the number of '0's in 'a'. This is equivalent to saying that
    // all '0's in the original string `a` could eventually become '1's
    // if we keep appending '1's and shifting.
    // More precisely, the maximum number of '1's in any string derived from 'a'
    // that has length L_a' is `count_ones(a) + (L_a' - L_a)` if all appended
    // characters were '1's.
