    // Let s_prefix = s.substr(0, n/2), s_suffix = s.substr(n - n/2).
    // s_middle = s.substr(n/2, n % 2).
    // s_prime = s_suffix + s_middle + s_prefix.
    // Since s is a palindrome, s_prefix is reverse(s_suffix).
    // s_prime is a palindrome.
    // If s_prime == s, then s_suffix + s_middle + s_prefix == s_prefix + s_middle + s_suffix.
    // This implies s_suffix == s_prefix.
    // Since s_prefix is reverse(s_suffix), this means s_prefix == reverse(s_prefix).
    // So s_prefix must be a palindrome.
    // If s_prefix is a palindrome, and not all characters in s are the same,
    // then s must be of the form "abccba" where "abc" is a palindrome.
    // Example: "abccba". s_prefix="abc". This is not a palindrome.
    // Example: "racecar". s_prefix="rac". Not a palindrome.
    // Example: "madam". s_prefix="ma". Not a palindrome.
    // Example: "kinnikkinnik". n=12. s_prefix="kinnik". This is a palindrome.
    // In this case, s_prefix == s_suffix.
    // So "kinnikkinnik" -> "kinnik" + "" + "kinnik" (if n is even, middle is empty).
    // Swapping them gives "kinnik" + "" + "kinnik", which is the same.
    // But for "kinnikkinnik", k=1 works: cut "kinnik"|"kinnik". Swap to get "kinnikkinnik".
    // Oh, wait, the example says "kinnikkinnik" -> 1.
    // "kinnik" + "kinnik". Swap gives "kinnikkinnik". This is the same.
    // The example note says: "you can cut the suffix nik and add it to the beginning, so you get nikkinnikkin."
    // s = "kinnikkinnik".
    // Cut at index 9: "kinnikkin" | "nik".
    // p1 = "kinnikkin", p2 = "nik".
    // s' = p2 + p1 = "nik" + "kinnikkin" = "nikkinnikkin".
    // Is "nikkinnikkin" a palindrome? Yes.
    // Is "nikkinnikkin" != "kinnikkinnik"? Yes.
    // So k=1 works for "kinnikkinnik". My k=1 loop should have found this.

    // The logic for k=2 being always possible if not all chars are same is based on a known competitive programming trick.
    // If s is a palindrome and not all characters are the same, then s.substr(0, n-1) is not a palindrome.
    // Consider s = "nolon". n=5.
    // s.substr(0, 4) = "nolo". Not a palindrome.
    // s.substr(0, n-1) is "nolo".
    // s.substr(1, n-1) is "olon".
    // If we cut s into s[0] and s.substr(1, n-1), i.e., 'n' and "olon".
    // Reorder: "olon" + 'n' = "olonn". Not a palindrome.
    // The general argument for k=2:
    // If not all characters are the same, then there exists at least one character `c` such that `s[0] != c`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    // Consider the string `s_prime = s.substr(1) + s[0]`.
    // This is formed by one cut (k=1). We already checked this.
    // If `s_prime` is not a palindrome or `s_prime == s`, then k=1 doesn't work for this specific cut.
    // The problem statement implies that if k=1 doesn't work, then k=2 must work, unless all characters are the same.
    // This is a common property for palindromes.
    // If a palindrome `s` is not composed of all identical characters, then it's always possible to make 2 cuts
    // to form a different palindrome.
    // The proof usually involves taking `s_prefix = s.substr(0, n/2)` and `s_suffix = s.substr(n - n/2)`.
    // If `s_prefix` is not a palindrome, then `s_prefix != reverse(s_prefix)`.
    // Since `s` is a palindrome, `s_prefix = reverse(s_suffix)`.
    // So `s_prefix != s_suffix`.
    // Then `s_prime = s_suffix + s_middle + s_prefix` is a palindrome and `s_prime != s`.
    // This requires 2 cuts (one before `s_middle`, one after `s_middle`).
    // If `s_prefix` IS a palindrome, then `s_prefix == reverse(s_prefix)`.
    // Since `s_prefix = reverse(s_suffix)`, this means `s_prefix == s_suffix`.
    // In this case, `s_prime = s_suffix + s_middle + s_prefix = s_prefix + s_middle + s_suffix = s`.
    // So this specific reordering doesn't work.
    // Example: "abacaba". n=7. s_prefix="aba". This is a palindrome.
    // s_suffix="aba". s_middle="c".
    // "aba" + "c" + "aba" -> "abacaba". Same.
    // But for "abacaba", k=1 works: "abac" | "aba". Swap: "aba" + "abac" = "abaac". Not a palindrome.
    // "a" | "bacaba". Swap: "bacabaa". Not a palindrome.
    // "ab" | "acaba". Swap: "acabaab". Not a palindrome.
    // "aba" | "caba". Swap: "cabaaba". Palindrome. Different. So k=1 works.

    // The problem statement implies that if k=1 doesn't work, and not all characters are the same, then k=2 works.
    // This is a standard result for palindromes.
    // If a palindrome `s` is not composed of all identical characters, then it's always possible to make 2 cuts
    // to form a different palindrome.
    // The only exception is when all characters are the same, which we handled.
    // So, if we reach here, it means k=1 didn't work, and not all characters are the same.
    // Therefore, the answer must be 2.
    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

// Function to check if all target tracks can be covered within 'time'
bool check(long long time, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // Create a list of unique target tracks that are not initially covered by any head
    std::vector<long long> required_p;
    std::set<long long> h_set(h.begin(), h.end());
    for (long long val : p) {
        if (h_set.find(val) == h_set.end()) {
            required_p.push_back(val);
        }
    }

    if (required_p.empty()) {
        return true; // All target tracks are already covered
    }

    // dp[i][j] will be true if the first 'i' heads can cover the first 'j' required tracks.
    // We only need the previous row of dp, so we can optimize space.
    // dp[j] will mean: can the current head (or previous heads) cover up to required_p[j-1]?
    std::vector<bool> dp(required_p.size() + 1, false);
    dp[0] = true; // Base case: 0 tracks can always be covered

    for (int i = 0; i < n; ++i) { // Iterate through each head
        std::vector<bool> next_dp = dp; // Initialize next_dp with results from previous heads

        // For each head h[i], calculate the range it can cover: [h[i] - time, h[i] + time]
        long long left_reach = h[i] - time;
        long long right_reach = h[i] + time;

        // Find the first required track that can be covered by h[i]
        auto it_start = std::lower_bound(required_p.begin(), required_p.end(), left_reach);
        int start_idx = std::distance(required_p.begin(), it_start);

        // Iterate backwards through required_p to update dp
        // This ensures that when we update dp[j], it uses the dp values from the *previous* head
        // or the *current* head's coverage of tracks *before* j.
        for (int j = required_p.size(); j > 0; --j) {
            // If dp[j] is already true from previous heads, no need to re-evaluate for this head
            if (next_dp[j]) continue;

            // Check if required_p[j-1] can be covered by the current head h[i]
            if (required_p[j-1] >= left_reach && required_p[j-1] <= right_reach) {
                // If required_p[j-1] is covered by h[i], then we need to check if
                // all tracks before required_p[j-1] (i.e., up to required_p[j-2])
                // can be covered by previous heads OR by the current head h[i]
                // by moving it to cover required_p[j-1] and some tracks to its left.

                // Option 1: h[i] covers required_p[j-1] and moves left to cover more.
                // The leftmost track h[i] can cover is required_p[j-1] - (time - (required_p[j-1] - h[i]))
                // which simplifies to 2*required_p[j-1] - h[i] - time.
                // This is equivalent to h[i] moving to required_p[j-1] and then covering
                // [2*required_p[j-1] - h[i] - time, required_p[j-1]].
                // The total distance covered is time.
                // The range covered is [h[i] - (time - (required_p[j-1] - h[i])), required_p[j-1]]
                // = [2*required_p[j-1] - h[i] - time, required_p[j-1]]
                long long left_bound_option1 = 2 * required_p[j-1] - h[i] - time;

                // Find the index k such that required_p[k-1] is the leftmost track covered by this option.
                // We need to cover tracks from required_p[k-1] to required_p[j-1].
                // This means we need dp[k-1] to be true (tracks up to required_p[k-2] covered by previous heads).
                auto it_k = std::upper_bound(required_p.begin(), required_p.end(), left_bound_option1);
                int k_idx = std::distance(required_p.begin(), it_k);
                if (dp[k_idx]) {
                    next_dp[j] = true;
                }

                // Option 2: h[i] covers required_p[j-1] and moves right to cover more.
                // The rightmost track h[i] can cover is required_p[j-1] + (time - (h[i] - required_p[j-1]))
                // which simplifies to 2*required_p[j-1] - h[i] + time.
                // This is equivalent to h[i] moving to required_p[j-1] and then covering
                // [required_p[j-1], 2*required_p[j-1] - h[i] + time].
                // This option is only relevant if h[i] is to the left of required_p[j-1].
                // If h[i] is to the right, it's covered by Option 1 (symmetric).
                // If h[i] is at required_p[j-1], both options are the same.
                // The range covered is [required_p[j-1], h[i] + (time - (h[i] - required_p[j-1]))]
                // = [required_p[j-1], 2*required_p[j-1] - h[i] + time]
                long long right_bound_option2 = 2 * required_p[j-1] - h[i] + time;

                // Find the index k such that required_p[k-1] is the leftmost track covered by this option.
                // We need to cover tracks from required_p[k-1] to required_p[j-1].
                // This means we need dp[k-1] to be true (tracks up to required_p[k-2] covered by previous heads).
                // The current head h[i] covers [required_p[k-1], required_p[j-1]]
                // The leftmost track it can cover is h[i] - time.
                // The rightmost track it can cover is h[i] + time.
                // If h[i] covers required_p[j-1] and moves right, it can cover up to right_bound_option2.
                // The tracks it covers are [required_p[j-1], right_bound_option2].
                // This means it can cover a segment [required_p[k_prime-1], required_p[j-1]]
                // where required_p[k_prime-1] is the leftmost track in the segment.
                // The total length of the segment is required_p[j-1] - required_p[k_prime-1].
                // The time taken to cover this segment and reach required_p[j-1] from h[i] is
                // max(abs(h[i] - required_p[j-1]), abs(h[i] - required_p[k_prime-1]), required_p[j-1] - required_p[k_prime-1]).
                // This is not quite right. The problem is simpler:
                // If head h[i] covers required_p[j-1], it can also cover any track x such that
                // max(abs(h[i]-x), abs(h[i]-required_p[j-1]), abs(x-required_p[j-1])) <= time.
                // This means x must be in [h[i]-time, h[i]+time] AND [required_p[j-1]-time, required_p[j-1]+time].
                // The union of all tracks covered by h[i] is [h[i]-time, h[i]+time].
                // If h[i] covers required_p[j-1], it can cover a contiguous block of tracks
                // [L, R] where L <= required_p[j-1] <= R.
                // The time taken is max(abs(h[i]-L), abs(h[i]-R), R-L).
                // This is the key insight for the DP transition.
                // If we use head h[i] to cover tracks from required_p[k_idx-1] to required_p[j-1],
                // then we need dp[k_idx-1] to be true.
                // The condition for h[i] to cover [required_p[k_idx-1], required_p[j-1]] is:
                // 1. abs(h[i] - required_p[k_idx-1]) <= time
                // 2. abs(h[i] - required_p[j-1]) <= time
                // 3. required_p[j-1] - required_p[k_idx-1] <= time
                // These three conditions can be combined into:
                // max(abs(h[i] - required_p[k_idx-1]), abs(h[i] - required_p[j-1]), required_p[j-1] - required_p[k_idx-1]) <= time.
                // This is equivalent to:
                // h[i] - time <= required_p[k_idx-1]
                // required_p[j-1] <= h[i] + time
                // required_p[j-1] - required_p[k_idx-1] <= time

                // We need to find the smallest k_idx such that dp[k_idx-1] is true AND
                // h[i] can cover the segment [required_p[k_idx-1], required_p[j-1]].
                // Iterate k_idx from 0 to j-1.
                for (int k_idx = 0; k_idx <= j; ++k_idx) {
                    if (dp[k_idx]) { // If tracks up to required_p[k_idx-1] are covered
                        // Check if h[i] can cover the segment [required_p[k_idx], required_p[j-1]]
                        // (if k_idx == 0, it means h[i] covers from the very first required track)
                        long long segment_start = (k_idx == 0) ? -2e18 : required_p[k_idx-1]; // Use a very small number if k_idx is 0
                        long long segment_end = required_p[j-1];

                        // The actual segment to cover is from required_p[k_idx] to required_p[j-1]
                        // if k_idx > 0. If k_idx == 0, it means we are covering from the beginning
                        // of required_p up to required_p[j-1].
                        // The condition is that h[i] must be able to cover the entire range
                        // [required_p[k_idx], required_p[j-1]] (if k_idx > 0)
                        // or [required_p[0], required_p[j-1]] (if k_idx == 0).
                        // This means:
                        // 1. h[i] must be able to reach required_p[k_idx] (if k_idx > 0)
                        // 2. h[i] must be able to reach required_p[j-1]
                        // 3. The length of the segment must be <= time
                        // 4. h[i] must be within 'time' distance from both ends of the segment.
                        // This is equivalent to:
                        // h[i] - time <= required_p[k_idx] (if k_idx > 0)
                        // required_p[j-1] <= h[i] + time
                        // required_p[j-1] - required_p[k_idx] <= time (if k_idx > 0)

                        // Let's simplify the condition for h[i] to cover a segment [A, B]:
                        // max(abs(h[i]-A), abs(h[i]-B), B-A) <= time
                        // If k_idx == 0, A is required_p[0].
                        // If k_idx > 0, A is required_p[k_idx].
                        long long current_segment_start_val = (k_idx == 0) ? required_p[0] : required_p[k_idx];

                        if (k_idx == 0 || (required_p[k_idx-1] < current_segment_start_val)) { // Ensure k_idx-1 is strictly before current_segment_start_val
                            if (std::max({std::abs(h[i] - current_segment_start_val),
                                           std::abs(h[i] - segment_end),
                                           segment_end - current_segment_start_val}) <= time) {
                                next_dp[j] = true;
                                break; // Found a way to cover up to j, move to next j
                            }
                        }
                    }
                }
            }
        }
        dp = next_dp;
    }

    return dp[required_p.size()];
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance for a single head to cover all tracks
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

