#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it
        // as many times as possible without exceeding k.
        // The current pile a[i] can become a[i] + x * min_val <= k
        // x * min_val <= k - a[i]
        // x <= (k - a[i]) / min_val
        // Since x must be an integer, x = floor((k - a[i]) / min_val)
        if (a[i] < k) { // Only add if there's room
            operations += (k - a[i]) / min_val;
        }
    }
    std::cout << operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem guarantees that a solution exists.
    // A simple strategy that often works for these types of problems
    // is to reverse the permutation.
    // Let's verify if reversing the permutation always works.
    // If p = [p_1, p_2, ..., p_n], then F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n]).
    // If p' = [p_n, p_{n-1}, ..., p_1], then F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1]).
    // The set of sums {p_i + p_{i+1}} is the same as {p_{n-i+1} + p_{n-i}}.
    // For example, p_1+p_2 corresponds to p_n+p_{n-1} (if n-1 = 1, i.e., n=2).
    // More generally, the sum p_k + p_{k+1} in the original permutation
    // corresponds to the sum p_{n-k+1} + p_{n-k} in the reversed permutation.
    // These are the same set of sums, just in a different order.
    // Since the fingerprint is the *sorted* array of sums, F(p) will be equal to F(p_reversed).
    // The only case where p_reversed might be equal to p is if p is a palindrome.
    // However, a permutation of distinct integers from 1 to n can only be a palindrome
    // if n=1 (which is not allowed, n>=2) or if n=2 and p=[1,2] or p=[2,1].
    // For n=2, if p=[1,2], p_reversed=[2,1], which is different.
    // If p=[2,1], p_reversed=[1,2], which is different.
    // For n > 2, a permutation cannot be a palindrome because the elements are distinct.
    // For example, if p_1 = p_n, then p_1 and p_n are the same element, but they must be distinct.
    // So, p_reversed is always different from p for n >= 2.

    // Therefore, reversing the permutation always yields a different permutation
    // with the same fingerprint.
    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

