int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long ans = 0;

        // Use as many +5/-5 as possible
        ans += diff / 5;
        diff %= 5;

        // Remaining diff is 0, 1, 2, 3, 4
        if (diff == 0) {
            // No additional presses needed
        } else if (diff == 1) {
            // Can use +1/-1 (1 press)
            // Or use +2/-2 then -1/+1 (2 presses)
            // Or use +5/-5 then -2/+2 then -2/+2 (3 presses)
            // Or use +5/-5 then -1/+1 then -1/+1 then -1/+1 then -1/+1 (5 presses)
            // Minimum is 1 press (+1/-1)
            ans += 1;
        } else if (diff == 2) {
            // Can use +2/-2 (1 press)
            // Or use +1/-1 then +1/-1 (2 presses)
            // Minimum is 1 press (+2/-2)
            ans += 1;
        } else if (diff == 3) {
            // Can use +1/-1 then +2/-2 (2 presses)
            // Or use +1/-1 then +1/-1 then +1/-1 (3 presses)
            // Or use +5/-5 then -2/+2 (2 presses)
            // Minimum is 2 presses
            ans += 2;
        } else if (diff == 4) {
            // Can use +2/-2 then +2/-2 (2 presses)
            // Or use +1/-1 then +1/-1 then +2/-2 (3 presses)
            // Or use +5/-5 then -1/+1 (2 presses)
            // Minimum is 2 presses
            ans += 2;
        }

        std::cout << ans << "\n";
    }
    return 0;
}

