void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The first digit is 2.
        // The last digit is 3.
        // All intermediate digits are 7.
        // This forms the number 277...773 (n-2 sevens).

        // Let's check the divisibility conditions for 27...73:
        // 1. Not divisible by 2: The number ends in 3, which is odd. So, not divisible by 2.
        // 2. Not divisible by 3: The sum of digits is 2 + (n-2)*7 + 3 = 5 + 7n - 14 = 7n - 9.
        //    For n=2, sum=7(2)-9=5. Not div by 3.
        //    For n=3, sum=7(3)-9=12. Div by 3. This construction fails for n=3.
        //    For n=4, sum=7(4)-9=19. Not div by 3.
        //    For n=5, sum=7(5)-9=26. Not div by 3.
        //    In general, 7n-9 is divisible by 3 if 7n is divisible by 3, which means n is divisible by 3.
        //    So, if n is a multiple of 3, this construction fails for digit 3.

        // Let's try a different construction:
        // First digit 2.
        // All other n-1 digits are 3.
        // Number is 233...3 (n-1 threes).
        // Digits are 2, 3.
        // 1. Not divisible by 2: Ends in 3, so odd. Not divisible by 2.
        // 2. Not divisible by 3: Sum of digits is 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    3n-1 is never divisible by 3 (since 3n is divisible by 3, 3n-1 leaves remainder 2 when divided by 3).
        // This construction works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

