#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by 'val' to current_sum
        // Each 'val' contributes 'val' to the sum.
        // We only care about values up to 2048.
        // If current_sum exceeds 2048, we can stop adding.
        // The problem is not about sum, but about forming 2048.
        // Let's re-think.
        // We can think of it as having a "budget" of 2048.
        // Each number 'x' contributes 'x' to this budget.
        // If we have two 'x's, they become '2x'. This means the 'value' is conserved.
        // So, the total sum of numbers less than or equal to 2048 is what matters.
        // If the sum is >= 2048, we can always form 2048.
        // Example: {1024, 512, 512, 4} -> sum = 2048.
        // 512+512=1024. Multiset becomes {1024, 1024, 4}.
        // 1024+1024=2048. Multiset becomes {2048, 4}. YES.
        // Example: {64, 512, 2} -> sum = 578. NO.
        // This logic seems correct. The operations preserve the sum of the elements.
        // If we have numbers x1, x2, ..., xk, and we combine two equal numbers x_i, x_j (where x_i = x_j),
        // the new multiset has x1, ..., 2*x_i, ..., xk (without x_i, x_j).
        // The sum changes from Sum(all x) to Sum(all x) - x_i - x_j + 2*x_i = Sum(all x).
        // So the sum is invariant.
        // If the initial sum of numbers <= 2048 is >= 2048, then we can always form 2048.
        // Why? Because we can always combine smaller numbers to form larger ones until we reach 2048.
        // For example, if we have 1024, 512, 256, 128, 64, 32, 16, 8, 4, 2, 1.
        // Sum is 2047. We can't make 2048.
        // If we have 1024, 1024. Sum is 2048. We can make 2048.
        // If we have 1024, 512, 512. Sum is 2048. We can make 2048.
        // The key is that any power of two can be formed by summing smaller powers of two.
        // E.g., 2048 = 1024 + 1024. 1024 = 512 + 512, etc.
        // So if the total sum of numbers (that are <= 2048) is S, and S >= 2048,
        // we can always combine numbers to form 2048.
        // We can greedily combine the smallest numbers first, or largest.
        // The most straightforward way is to just sum up all numbers that are <= 2048.
        // If this sum is >= 2048, then YES. Otherwise, NO.
        current_sum += val * count;
        if (current_sum >= 2048) {
            std::cout << "YES\n";
            return;
        }
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

