#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The state of has_one and has_minus_one is for elements *before* index i.
            // So, if a[i] is 1 or -1, it contributes to the flags for elements j < i.
            // But we are iterating backwards, so the flags should reflect elements 0 to i-1.
            // The flags are updated *after* checking a[i] vs b[i].
            // This means has_one and has_minus_one are for elements 0 to i.
            // When checking index i, we need to know if there's a 1 or -1 at indices 0 to i-1.
            // So, the flags should be updated *before* the loop, and then for elements 0 to i-1.
            // Let's re-evaluate the flags.
            // The flags `has_one` and `has_minus_one` should track if there's a 1 or -1
            // in the prefix `a[0...i-1]`.
            // So, we need to compute these flags dynamically or precompute.
            // Precomputing prefix sums of 1s and -1s is an option.
            // Let's use dynamic flags.
        } else if (a[i] < b[i]) {
            if (!has_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            if (!has_minus_one) {
                possible = false;
                break;
            }
        }
        // Update flags for the next iteration (i-1).
        // If a[i] was 1, it means for elements j < i, there was a 1 at index i.
        // But we need to know if there's a 1 at index k < i.
        // So, the flags should be updated *after* processing a[i].
        // The current `has_one` and `has_minus_one` are for `a[0...i]`.
        // For `a[i-1]`, we need `a[0...i-2]`.
        // This means the flags should be computed for `a[0...i-1]` when checking `a[i]`.
        // Let's re-think the flag logic.

        // The flags `has_one_prefix[k]` and `has_minus_one_prefix[k]`
        // should indicate if there's a 1 or -1 in `a[0...k]`.
        // When checking `a[i]`, we need to know if there's a 1 or -1 in `a[0...i-1]`.
        // So, we need to precompute prefix flags.

        // Let's restart the logic for flags.
        // `has_one_before_i` means there is a 1 in `a[0...i-1]`.
        // `has_minus_one_before_i` means there is a -1 in `a[0...i-1]`.
    }

    // Re-implementing with prefix flags
    std::vector<bool> prefix_has_one(n, false);
    std::vector<bool> prefix_has_minus_one(n, false);

    if (a[0] == 1) prefix_has_one[0] = true;
    if (a[0] == -1) prefix_has_minus_one[0] = true;

    for (int i = 1; i < n; ++i) {
        prefix_has_one[i] = prefix_has_one[i-1] || (a[i] == 1);
        prefix_has_minus_one[i] = prefix_has_minus_one[i-1] || (a[i] == -1);
    }

    possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No action needed, or it's already correct.
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. Requires adding 1 from some a_k (k < i).
            // This means there must be a 1 in a[0...i-1].
            if (i == 0 || !prefix_has_one[i-1]) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. Requires adding -1 from some a_k (k < i).
            // This means there must be a -1 in a[0...i-1].
            if (i == 0 || !prefix_has_minus_one[i-1]) {
                possible = false;
                break;
            }
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

