        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;

        long long current_cost = 0;
        long long count = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)

        while (true) {
            // Cost for a staircase with k stairs: k * (k + 1) / 2
            // k is of the form 2^p - 1.
            // So, cost is (2^p - 1) * (2^p) / 2
            // Let m = 2^p. Cost = (m - 1) * m / 2
            // For k=1 (p=1, m=2), cost = (2-1)*2/2 = 1
            // For k=3 (p=2, m=4), cost = (4-1)*4/2 = 6
            // For k=7 (p=3, m=8), cost = (8-1)*8/2 = 28
            // For k=15 (p=4, m=16), cost = (16-1)*16/2 = 120

            // Calculate cost for current k
            // k * (k + 1) / 2
            // Since k can be up to 2^60 - 1, k+1 can be 2^60.
            // k * (k+1) can be (2^60-1)*2^60, which is approx 2^120.
            // This will overflow long long.
            // However, k is always odd, so k+1 is always even.
            // We can write cost as k * ((k+1)/2).
            // (k+1)/2 will be 2^(p-1).
            // So cost is (2^p - 1) * 2^(p-1).
            // This is (2^p - 1) * (k+1)/2.
            // Max k is approx 2^60. Max (k+1)/2 is approx 2^59.
            // Product is approx 2^60 * 2^59 = 2^119. Still too large.

            // Let's re-evaluate the cost calculation.
            // The number of cells for a staircase with n stairs is n*(n+1)/2.
            // For a nice staircase, n must be of the form 2^p - 1.
            // Let n = 2^p - 1.
            // Cost = (2^p - 1) * (2^p - 1 + 1) / 2
            // Cost = (2^p - 1) * 2^p / 2
            // Cost = (2^p - 1) * 2^(p-1)
            // Let's use `k` as the number of stairs, so `k = 2^p - 1`.
            // The cost is `k * (k+1) / 2`.
            // `k+1` is `2^p`.
            // So cost is `k * (2^p / 2) = k * 2^(p-1)`.
            // `p` starts from 1.
            // For p=1, k=1. Cost = 1 * 2^0 = 1.
            // For p=2, k=3. Cost = 3 * 2^1 = 6.
            // For p=3, k=7. Cost = 7 * 2^2 = 28.
            // For p=4, k=15. Cost = 15 * 2^3 = 120.

            // The maximum value of x is 10^18.
            // We need to find the largest p such that (2^p - 1) * 2^(p-1) <= 10^18.
            // (2^p - 1) * 2^(p-1) is roughly 2^p * 2^(p-1) = 2^(2p-1).
            // 2^(2p-1) <= 10^18
            // 2p-1 <= log2(10^18) = 18 * log2(10) approx 18 * 3.32 = 59.79
            // 2p-1 <= 59
            // 2p <= 60
            // p <= 30.
            // So, k = 2^p - 1 will be at most 2^30 - 1.
            // k * (k+1)/2 will be (2^30 - 1) * 2^30 / 2 = (2^30 - 1) * 2^29.
            // This is approximately 2^59, which fits in long long.
            // Max value for p=30: k = 2^30 - 1 = 1073741823.
            // Cost = (2^30 - 1) * 2^29 = 1073741823 * 536870912 = 576460751766556672.
            // This fits in long long.

            long long cost_k = k * (k + 1) / 2;

            if (current_cost + cost_k <= x) {
                current_cost += cost_k;
                count++;
                // Next k is 2*k + 1
                // k = 2^p - 1
                // 2k+1 = 2(2^p - 1) + 1 = 2^(p+1) - 2 + 1 = 2^(p+1) - 1
                // This correctly generates the next number of stairs for a nice staircase.
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int open_count = 0;
    int close_count = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < open_needed) {
                result += '(';
                open_count++;
            }
        } else { // c == ')'
            if (close_count < close_needed && open_count > close_count) {
                result += ')';
                close_count++;
            }
        }
        if (open_count == open_needed && close_count == close_needed) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // The first k+1 elements will generate k distinct differences.
    // We want to generate differences 1, 2, ..., k.
    // We can do this by alternating between the smallest available and largest available numbers.
    // For example, if k=4, we use numbers 1, 2, 3, 4, 5.
    // Sequence: 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1. These are 4 distinct differences.
    // In general, for k distinct differences, we use numbers 1 to k+1.
    // The sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // This generates differences k, k-1, k-2, ..., 1.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...)
            std::cout << left << " ";
            left++;
        } else { // Odd index (1, 3, 5, ...)
            std::cout << right << " ";
            right--;
        }
    }

    // After generating k distinct differences using numbers 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these numbers in increasing order to avoid generating new distinct differences.
    // The last number printed was either `left-1` or `right+1`.
    // If the last number was `left-1`, then `left` is the next smallest available number.
    // If the last number was `right+1`, then `right` is the next largest available number.
    // In either case, `left` is the smallest unused number from the `1` to `k+1` range.
    // The numbers `k+2, k+3, ..., n` are all greater than `k+1`.
    // If we append `k+2, k+3, ..., n` in increasing order, the differences will be `1`.
    // For example, if the last number printed was `X`, and we print `X+1`, the difference is `1`.
    // This does not introduce new distinct differences if `1` is already among the `k` differences generated.
    // Since we generated differences `1, 2, ..., k`, `1` is always included (as `k >= 1`).

    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

