void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This `i` is the start of the first decreasing sequence from the right.
    // All elements a[i...n-1] are non-decreasing.
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j] > a[j-1]
    // This `j` is the start of the first increasing sequence from the right
    // after the initial non-decreasing part.
    // All elements a[j...i-1] are non-increasing.
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing.
    // If j is 0, then a[0...i-1] is non-increasing, and a[i...n-1] is non-decreasing.
    // This means the suffix a[0...n-1] (the whole array) is good.

    std::cout << j << std::endl;
}

