    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            // Since d >= 4, discriminant will be non-negative.
            // d^2 - 4d = d(d-4) >= 4(4-4) = 0.

            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Both a1 and b1 must be non-negative.
            // Since d >= 4, d + sqrt_discriminant is clearly positive.
            // For b1, we need d - sqrt_discriminant >= 0.
            // This is equivalent to d >= sqrt_discriminant, or d^2 >= discriminant.
            // d^2 >= d^2 - 4d, which simplifies to 0 >= -4d, or 4d >= 0.
            // Since d >= 0, this condition is always met.
            // So, both a1 and b1 are non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx and max_idx are both pos[1].
        // Length is 1. Max value is 1.
        // This is always beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1]...pos[m]) to max(pos[1]...pos[m]).
        // Let's maintain current_min_idx and current_max_idx as the minimum and maximum
        // indices encountered so far for numbers 1 to (m-1).
        // When we consider 'm', we update these bounds to include pos[m].

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the segment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The length of the segment must be exactly m.
        //    (current_max_idx - current_min_idx + 1 == m)
        // 2. The maximum value in this segment must be exactly m.
        //    (This is implicitly handled by how we expand the segment.
        //     If the length is m, and it contains 1..m, then m must be the max.)

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

