#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if a peak can be formed at index i (0-indexed)
    // This means a[0] < a[1] < ... < a[i] and a[i] > a[i+1] > ... > a[n-1]
    // After operations, the array elements must satisfy:
    // b[j] >= j for j <= i
    // b[j] >= (n-1-j) for j >= i
    // And b[j] <= a[j] for all j.
    // So, we need a[j] >= j for j <= i
    // And a[j] >= (n-1-j) for j >= i

    // Find the maximum possible length of the strictly increasing prefix starting from 0.
    // That is, find the largest `i` such that we can make `b_0 < b_1 < ... < b_i`
    // where `b_j` is derived from `a_j`.
    // The minimum value for `b_j` in such a sequence is `j`.
    // So we need `a_j >= j` for all `j` from `0` to `i`.
    int max_inc_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            max_inc_len = i + 1;
        } else {
            break;
        }
    }

    // Find the maximum possible length of the strictly decreasing suffix ending at n-1.
    // That is, find the largest `j` such that we can make `b_j > b_{j+1} > ... > b_{n-1}`
    // where `b_k` is derived from `a_k`.
    // The minimum value for `b_k` in such a sequence is `n-1-k`.
    // So we need `a_k >= (n-1-k)` for all `k` from `j` to `n-1`.
    int max_dec_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            max_dec_len = (n - 1 - i) + 1;
        } else {
            break;
        }
    }

    // If there is any overlap between the possible increasing prefix and decreasing suffix,
    // then we can form a sharpened array.
    // The increasing prefix covers indices [0, max_inc_len - 1].
    // The decreasing suffix covers indices [n - max_dec_len, n - 1].
    // We need to check if max_inc_len + max_dec_len > n.
    // This means the union of the two ranges covers at least one index twice,
    // which implies there's a potential peak index.
    if (max_inc_len + max_dec_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

