int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // For 0-indexed array, (n-1)/2 is the middle index

    // First, ensure the median element itself is s.
    // This is a mandatory cost.
    operations += std::abs(a[mid_idx] - s);
    a[mid_idx] = s; // Conceptually change it to s for subsequent checks

    // Ensure elements to the left of median are <= s
    // Iterate from mid_idx - 1 down to 0
    for (int i = mid_idx - 1; i >= 0; --i) {
        if (a[i] > s) {
            operations += (a[i] - s);
            a[i] = s; // Conceptually change it to s
        }
    }

    // Ensure elements to the right of median are >= s
    // Iterate from mid_idx + 1 up to n - 1
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
            a[i] = s; // Conceptually change it to s
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

