#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a subarray is a permutation
// `arr` is the input array
// `start_idx` is the starting index of the subarray (inclusive)
// `end_idx` is the ending index of the subarray (inclusive)
// `expected_len` is the expected length of the permutation (end_idx - start_idx + 1)
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int expected_len) {
    if (expected_len <= 0) {
        return false; // Permutations must have non-zero length
    }
    if (end_idx - start_idx + 1 != expected_len) {
        return false; // Length mismatch
    }

    std::vector<bool> seen(expected_len + 1, false);
    int max_val = 0;

    for (int i = start_idx; i <= end_idx; ++i) {
        int val = arr[i];
        if (val < 1 || val > expected_len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // All values from 1 to expected_len must be present
    // This is implicitly checked by `val > expected_len` and `seen[val]`
    // and `max_val == expected_len`
    return max_val == expected_len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix permutation checks
    // `is_prefix_perm[i]` is true if a[0...i-1] is a permutation of length i
    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_prefix_val = 0;
    bool current_prefix_valid = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val < 1 || val > i + 1 || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        if (current_prefix_valid) {
            seen_prefix[val] = true;
            if (val > max_prefix_val) {
                max_prefix_val = val;
            }
            if (max_prefix_val == i + 1) { // Check if all numbers from 1 to i+1 are present
                is_prefix_perm[i + 1] = true;
            }
        }
    }

    // Precompute suffix permutation checks
    // `is_suffix_perm[i]` is true if a[i...n-1] is a permutation of length n-i
    std::vector<bool> is_suffix_perm(n + 1, false); // index i means a[i...n-1]
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix_val = 0;
    bool current_suffix_valid = true;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        int current_suffix_len = n - i;
        if (val < 1 || val > current_suffix_len || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        if (current_suffix_valid) {
            seen_suffix[val] = true;
            if (val > max_suffix_val) {
                max_suffix_val = val;
            }
            if (max_suffix_val == current_suffix_len) { // Check if all numbers from 1 to current_suffix_len are present
                is_suffix_perm[i] = true;
            }
        }
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (l2 <= 0) continue; // l2 must be positive

        if (is_prefix_perm[l1] && is_suffix_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

