int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // that needs to pass this 'b' will contribute to steps.
            // The number of 'a's currently to the left of this 'b'
            // (that haven't been processed yet) is `count_a`.
            // Each such 'a' will cause `count_a` steps when it passes this 'b'.
            // The total steps for this 'b' is `count_a`.
            // After these `count_a` 'a's pass this 'b', this 'b' effectively
            // doubles the number of 'a's that will be processed by 'b's further left.
            // This is because each 'a' passing this 'b' creates a new 'b'.
            // So, the effective number of 'a's for the next 'b' to the left doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now available
            // to be processed by any 'b's to its right (which we have already processed).
            // This 'a' will contribute to `count_a` for 'b's further left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum, X = current_xor_sum
    // We need S' = 2 * X'
    // S' = S + b1 + b2 + b3
    // X' = X ^ b1 ^ b2 ^ b3

    // Strategy: Append at most 3 elements.
    // It's always possible to append 2 elements.
    // Let's try to append two elements, say Y and Z.
    // S + Y + Z = 2 * (X ^ Y ^ Z)
    // A simple choice for Y and Z is to make X ^ Y ^ Z equal to some value, say X.
    // If X ^ Y ^ Z = X, then Y ^ Z = 0, which means Y = Z.
    // So, if we append Y and Y, the new XOR sum is X ^ Y ^ Y = X.
    // The new sum is S + Y + Y = S + 2Y.
    // The condition becomes S + 2Y = 2 * X.
    // This means 2Y = 2X - S.
    // For Y to be an integer, 2X - S must be an even number.
    // This means S must be an even number.
    // If S is odd, then 2X - S is odd, and 2Y cannot be odd. So this strategy doesn't work directly.

    // Let's try to append two elements: X and current_sum.
    // No, this is not general enough.

    // Consider the property: sum(a_i) % 2 == xor_sum(a_i) % 2.
    // This is because a + b = (a ^ b) + 2 * (a & b).
    // So a + b and a ^ b have the same parity.
    // Extending this, sum(a_i) and xor_sum(a_i) have the same parity.
    // Let S_new be the new sum and X_new be the new XOR sum.
    // We need S_new = 2 * X_new.
    // This implies S_new must be even.
    // Since S_new and X_new have the same parity, X_new must also be even.

