// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern += '0';
            } else { // Odd digit
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 digits long
    // This is equivalent to padding from the right of the reversed string
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

// Function to normalize a query pattern to 18 digits
std::string normalize_query_pattern(const std::string& s) {
    std::string normalized_s = s;
    // Pad with '0's from the left to make it 18 digits long
    // This is equivalent to padding from the right of the reversed string
    while (normalized_s.length() < 18) {
        normalized_s += '0';
    }
    return normalized_s;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            std::cout << counts[normalize_query_pattern(s)] << "\n";
        }
    }

    return 0;
}

