int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for counts of 'x', 'y', 'z'
    // counts[0] for 'x', counts[1] for 'y', counts[2] for 'z'
    // counts[char_idx][i] stores the count of that character in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            counts[j][i + 1] = counts[j][i];
        }
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        // Adjust to 0-indexed
        // Substring is s[l-1 ... r-1]
        // Length of substring is r - (l-1) = r - l + 1
        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // Check if the counts are "balanced" enough
        // The difference between max and min count must be at most 1
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

