    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            // If p is not divisible by q, then p itself is the largest divisor of p
            // and it's not divisible by q. So p is the answer.
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, then p is not a valid x.
        // We need to find a smaller divisor of p.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // For any divisor x of p, if x is divisible by q, it means that for every fi,
        // the exponent of fi in x's prime factorization is at least ai.
        // To make x not divisible by q, we must reduce the exponent of at least one fi
        // in x's prime factorization below ai.
        // To maximize x, we should try to reduce the exponent of fi as little as possible,
        // and only for one fi at a time.
        // For each prime factor fi of q, we can form a candidate x by taking p
        // and dividing it by fi until its exponent of fi is (ai - 1).
        // More precisely, we divide p by fi until p is no longer divisible by q.
        // This means we divide p by fi until the count of fi in p is less than the count of fi in q.

        std::map<long long, int> q_factors = get_prime_factorization(q);
        long long max_x = 1;

        for (auto const& [factor, q_exponent] : q_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q.
            // This means we divide current_p by 'factor' until the exponent of 'factor'
            // in current_p is less than q_exponent.
            // The number of times 'factor' divides current_p must be at least q_exponent for current_p to be divisible by q.
            // So we need to divide current_p by 'factor' until its exponent is (q_exponent - 1).
            // This is equivalent to dividing current_p by factor^(count_in_p - (q_exponent - 1)).
            // Or simpler: keep dividing current_p by 'factor' as long as current_p is divisible by q.
            // No, this is not quite right. We need to find the largest divisor of p that is NOT divisible by q.
            // If p is divisible by q, then p = K * q.
            // We want to find x = p / (f_i^k) such that x is not divisible by q.
            // For a specific prime factor `factor` of `q`:
            // Let `p_exp_factor` be the exponent of `factor` in `p`.
            // Let `q_exp_factor` be the exponent of `factor` in `q`.
            // Since `p` is divisible by `q`, we know `p_exp_factor >= q_exp_factor`.
            // To make `x` not divisible by `q` by reducing the power of `factor`,
            // we need the exponent of `factor` in `x` to be less than `q_exp_factor`.
            // The largest such `x` would have `factor` with exponent `q_exp_factor - 1`.
            // So, we divide `p` by `factor` until its exponent becomes `q_exp_factor - 1`.
            // This means we divide `p` by `factor` `p_exp_factor - (q_exp_factor - 1)` times.
            // Which is `p_exp_factor - q_exp_factor + 1` times.

            long long temp_p = p;
            while (temp_p % q == 0) { // As long as temp_p is divisible by q
                temp_p /= factor; // Divide temp_p by the current prime factor of q
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>
