void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    std::string ans(n, ' ');
    bool possible = false;

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit
        std::vector<int> current_ans(n);
        int last1 = -1; // last digit colored 1
        int first2 = 10; // first digit colored 2

        bool valid_p = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                current_ans[i] = 1;
                if (d[i] < last1) { // S1 must be non-decreasing
                    valid_p = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > p) {
                current_ans[i] = 2;
                if (d[i] < first2) { // S2 must be non-decreasing
                    valid_p = false;
                    break;
                }
                first2 = d[i];
            } else { // d[i] == p
                // Try to assign to 2 first, if possible
                if (p < first2) { // If p can extend S2 without violating non-decreasing
                    current_ans[i] = 2;
                    first2 = p;
                } else { // Otherwise, assign to 1
                    current_ans[i] = 1;
                    if (p < last1) { // S1 must be non-decreasing
                        valid_p = false;
                        break;
                    }
                    last1 = p;
                }
            }
        }

        if (!valid_p) {
            continue;
        }

        // Check the condition last1 <= first2
        // If last1 is still -1, S1 is empty. If first2 is still 10, S2 is empty.
        // If both are empty, this loop wouldn't have run.
        // If S1 is empty, last1 effectively -infinity.
        // If S2 is empty, first2 effectively +infinity.
        // The condition holds if last1 <= first2.
        // The values -1 and 10 are chosen to make this check work naturally.
        if (last1 <= first2) {
            possible = true;
            for (int i = 0; i < n; ++i) {
                ans[i] = (char)(current_ans[i] + '0');
            }
            break;
        }
    }

    if (possible) {
        std::cout << ans << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

