void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 1: can move left (x-1, y)
        // f2 = 1: can move up (x, y+1)
        // f3 = 1: can move right (x+1, y)
        // f4 = 1: can move down (x, y-1)

        // If f1 = 0, robot cannot move left. So target X must be >= current x.
        // This means the lower bound for X is x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }
        // If f3 = 0, robot cannot move right. So target X must be <= current x.
        // This means the upper bound for X is x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // If f4 = 0, robot cannot move down. So target Y must be >= current y.
        // This means the lower bound for Y is y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
        // If f2 = 0, robot cannot move up. So target Y must be <= current y.
        // This means the upper bound for Y is y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. The problem guarantees that if a solution exists,
        // one exists with coordinates not exceeding 10^5 in absolute value.
        // We can pick any point within the valid range.
        // For example, (min_x, min_y) or (0,0) if it's within bounds.
        // The problem statement implies that the bounds for X, Y are within [-10^5, 10^5].
        // Our calculated min_x, max_x, min_y, max_y could be outside this range
        // if all robots have full movement capabilities and start far away.
        // However, the guarantee means we can clamp the chosen point.
        // Let's just pick min_x and min_y.
        // The initial large values for min/max_x/y are just to ensure they are
        // correctly updated by the first robot's constraints.
        // The actual coordinates x_i, y_i are within [-10^5, 10^5].
        // So min_x and max_x will be within [-10^5, 10^5] if they are updated.
        // If they are not updated (e.g., all f1=1, f3=1), they remain at their initial large values.
        // But the problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
        // So we can just output min_x and min_y, as they will be valid if a solution exists.
        // For example, if all f1=1, min_x remains -2e9. But if a solution exists, say at (0,0),
        // then (0,0) is >= -2e9. So (min_x, min_y) is a valid choice.
        // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
        // This implies we should pick a point within [-10^5, 10^5].
        // Let's pick a point that is within the valid range and also within [-10^5, 10^5].
        // The intersection of [min_x, max_x] and [-10^5, 10^5] is [max(min_x, -10^5), min(max_x, 10^5)].
        // Same for Y.
        // So we can pick X = max(min_x, -100000LL) and Y = max(min_y, -100000LL).
        // This is guaranteed to be within [-10^5, 10^5] and also within the valid range.
        // However, a simpler approach is to just output min_x and min_y.
        // If min_x is -2e9, and a solution exists at (0,0), then (0,0) is a valid point.
        // The problem says "if there exists at least one point reachable by all robots, then at least one of such points has both coordinates not exceeding 10^5 by absolute value."
        // This means we can just output any valid point, and if it's outside [-10^5, 10^5], it's fine,
        // as long as *some* point exists within [-10^5, 10^5].
