#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::map<char, int> degree;
    std::set<char> used_in_s;

    for (char c = 'a'; c <= 'z'; ++c) {
        degree[c] = 0;
    }

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            char c1 = s[i - 1];
            char c2 = s[i];
            if (adj[c1].find(c2) == adj[c1].end()) { // If this is a new adjacency
                adj[c1].insert(c2);
                adj[c2].insert(c1);
                degree[c1]++;
                degree[c2]++;
            }
        }
    }

    for (char c : used_in_s) {
        if (degree[c] > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string result_layout = "";
    std::set<char> visited_for_layout;

    for (char c : used_in_s) {
        if (degree[c] <= 1 && visited_for_layout.find(c) == visited_for_layout.end()) {
            // Start a new path from this character
            char current = c;
            char prev = '\0'; // Sentinel for no previous character

            while (current != '\0' && visited_for_layout.find(current) == visited_for_layout.end()) {
                result_layout += current;
                visited_for_layout.insert(current);

                char next_char = '\0';
                for (char neighbor : adj[current]) {
                    if (neighbor != prev) {
                        next_char = neighbor;
                        break;
                    }
                }
                prev = current;
                current = next_char;
            }
        }
    }

    if (result_layout.length() != used_in_s.size()) {
        // This means there's a cycle or a component where all nodes have degree 2
        // which would not be covered by starting from degree 0/1 nodes.
        // Or, it means the graph is disconnected and has multiple paths/cycles.
        // The problem constraints imply a single path or multiple paths that can be merged.
        // If result_layout.length() != used_in_s.size(), it means we couldn't form a single path
        // covering all characters in 's' or there was a cycle.
        // A cycle would mean degree[c] == 2 for all chars in the cycle, and we wouldn't start from them.
        // If there's a cycle, it's impossible.
        // If there are multiple paths, and we started from all degree 1 nodes,
        // and still didn't cover all used_in_s, it means there are isolated nodes or cycles.
        // Isolated nodes (degree 0) would be covered by the loop below.
        // So, if this condition is met, it implies a cycle.
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_for_layout.find(c) == visited_for_layout.end()) {
            result_layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << result_layout << "\n";
}

