// Function to compute Z-array for a string
std::vector<int> compute_z_array(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    // Precompute Z-arrays for all suffixes of s
    // z_arrays[i] stores the Z-array for s.substr(i)
    // z_arrays[i][j] is the length of the longest common prefix of s.substr(i) and s.substr(i+j)
    // This is equivalent to z_arrays[i][j] = LCP(s[i...], s[i+j...])
    // For our purpose, we need LCP(s, s.substr(i)) which is z_arrays[0][i]
    // And LCP(s.substr(i), s.substr(j))
    // A more direct approach is to compute LCP(s.substr(i), s.substr(j)) for all i, j
    // This can be done by computing Z-array for s.substr(i) + '#' + s.substr(j)
    // Or by using suffix array/LCP array, but for N=5000, N^2 LCPs are too slow.
    // We need LCP(s_i, s_j) for specific i, j.
    // LCP(s_i, s_j) is the length of the longest common prefix of s[i...N-1] and s[j...N-1].
    // This can be found by computing Z-array for s[i...N-1] + '#' + s[j...N-1].
    // Or, more efficiently, by computing Z-array for s[j...N-1] + '#' + s[i...N-1].
    // The Z-value at index (N-j+1+1) in this combined string gives LCP(s[j...], s[i...]).
    // Let's precompute Z-arrays for all cyclic shifts of s.
    // z_cyclic[k][j] = LCP(s_k s_{k+1} ... s_{N-1} s_0 ... s_{k-1}, s_j s_{j+1} ... s_{N-1} s_0 ... s_{j-1})
    // This is not what we need.

    // We need LCP(s_i, s_j) for all i, j.
    // LCP(s_i, s_j) is the length of the longest common prefix of s[i..] and s[j..].
    // This can be computed by building a string T = s + s.
    // Then LCP(s_i, s_j) is the Z-value of T[j..] in the Z-array of T[i..] + '#' + T[j..].
    // Or, more simply, LCP(s_i, s_j) is the Z-value of T[j..] in the Z-array of T[i..] + '#' + T[j..].
    // Let's use a 2D array for LCP values.
    std::vector<std::vector<int>> lcp_val(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            int len = 0;
            while (i + len < n && j + len < n && s[i + len] == s[j + len]) {
                len++;
            }
            lcp_val[i][j] = len;
        }
    }

    // Group indices by character s[i]
    std::map<char, std::vector<int>> char_indices;
    for (int i = 0; i < n; ++i) {
        char_indices[s[i]].push_back(i);
    }

    double total_win_prob = 0.0;

    // Iterate over each possible first character c0
    for (auto const& [c0_char, k_candidates] : char_indices) {
        // k_candidates are the indices i such that s[i] == c0_char
        // These are the possible values of k given t[0] = c0_char.
        int num_k_candidates = k_candidates.size();

        if (num_k_candidates == 1) {
            // If only one k is possible, Vasya wins for sure for this c0.
            total_win_prob += 1.0 / n; // Probability of this c0 occurring
            continue;
        }

        // If multiple k's are possible, Vasya needs to choose p.
        // He chooses p to maximize his win probability for this c0.
        double max_win_prob_for_c0 = 0.0;

        // Iterate over all possible positions p (1 to N-1)
        for (int p = 1; p < n; ++p) {
            // For a fixed p, we need to count how many k_i in k_candidates
            // lead to a unique (k_i, t[p-1]) pair.
            // This means, for a given k_i, there should be no other k_j in k_candidates
            // such that s[k_i] == s[k_j] (which is true by definition of k_candidates)
            // AND s[(k_i + p) % N] == s[(k_j + p) % N].
            // If such a k_j exists, then k_i is not uniquely determined.

            // We need to count how many k_i are unique.
            // A k_i is unique if for all other k_j in k_candidates (j != i),
            // s[(k_i + p) % N] != s[(k_j + p) % N].
            // This is equivalent to grouping k_candidates by s[(k_i + p) % N].
            // Any group with size 1 contributes to a win.

            std::map<char, int> char_at_p_counts;
            for (int k_idx : k_candidates) {
                char_at_p_counts[s[(k_idx + p) % n]]++;
            }

            int unique_k_count_for_p = 0;
            for (int k_idx : k_candidates) {
                if (char_at_p_counts[s[(k_idx + p) % n]] == 1) {
                    unique_k_count_for_p++;
                }
            }

            // This is the number of k's that are uniquely determined by t[0] and t[p-1].
            // The probability of winning for this c0 and chosen p is unique_k_count_for_p / num_k_candidates.
            max_win_prob_for_c0 = std::max(max_win_prob_for_c0, (double)unique_k_count_for_p / num_k_candidates);
        }
        total_win_prob += (1.0 / n) * max_win_prob_for_c0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob << std::endl;

    return 0;
}

