void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for differences (1 for strawberry, -1 for blueberry)
    // For left side (jars 1 to n), calculate diffs from right to left
    // For right side (jars n+1 to 2n), calculate diffs from left to right

    // Left side: jars 1 to n.
    // We are interested in the balance of jars *remaining* on the left side.
    // If we eat `i` jars from the left, jars `i+1` to `n` remain.
    // Let's calculate the balance of jars `1` to `k` for `k` from `n` down to `1`.
    // This is equivalent to calculating the balance of jars `1` to `k` for `k` from `1` to `n`.
    // `left_diffs[k]` stores the balance (S-B) for jars `1` to `k`.
    std::vector<int> left_diffs(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_diffs[i + 1] = left_diffs[i] + (a[i] == 1 ? 1 : -1);
    }

    // Right side: jars n+1 to 2n.
    // We are interested in the balance of jars *remaining* on the right side.
    // If we eat `j` jars from the right, jars `n+1` to `2n-j` remain.
    // Let's calculate the balance of jars `k` to `2n` for `k` from `n+1` up to `2n`.
    // This is equivalent to calculating the balance of jars `k` to `2n` for `k` from `2n` down to `n+1`.
    // `right_diffs[k]` stores the balance (S-B) for jars `k` to `2n`.
    std::vector<int> right_diffs(n + 1, 0); // right_diffs[k] stores balance for jars 2n-k+1 to 2n
    for (int i = 0; i < n; ++i) {
        right_diffs[i + 1] = right_diffs[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left side
    // to achieve a certain balance.
    // `left_balance_to_eaten[balance]` = `jars_eaten_from_left`
    std::map<int, int> left_balance_to_eaten;
    left_balance_to_eaten[0] = 0; // 0 jars eaten from left, balance 0

    for (int i = 0; i < n; ++i) { // i jars eaten from left means jars 1 to i are gone
        // Remaining jars on left are i+1 to n.
        // Balance of remaining jars on left is left_diffs[n] - left_diffs[i].
        int current_balance = left_diffs[n] - left_diffs[i];
        if (left_balance_to_eaten.find(current_balance) == left_balance_to_eaten.end()) {
            left_balance_to_eaten[current_balance] = i;
        }
    }

    int min_eaten = 2 * n; // Initialize with max possible jars eaten

    // Case 1: No jars eaten from the right side.
    // The balance of remaining jars on the right is `right_diffs[0]` (which is 0).
    // We need `left_balance_to_eaten[0]` jars from the left.
    // Total jars eaten = `left_balance_to_eaten[0]` + 0.
    // This is already covered by the loop below when `j=0`.

    // Iterate through possible number of jars eaten from the right side.
    for (int j = 0; j <= n; ++j) { // j jars eaten from right means jars 2n-j+1 to 2n are gone
        // Remaining jars on right are n+1 to 2n-j.
        // Balance of remaining jars on right is right_diffs[n] - right_diffs[j].
        int current_right_balance = right_diffs[n] - right_diffs[j];

        // We need the total remaining S and B to be equal.
        // This means (S_left_rem + S_right_rem) == (B_left_rem + B_right_rem)
        // (S_left_rem - B_left_rem) == -(S_right_rem - B_right_rem)
        // So, we need `balance_left_rem` == -`current_right_balance`.
        int target_left_balance = -current_right_balance;

        if (left_balance_to_eaten.count(target_left_balance)) {
            int jars_eaten_from_left = left_balance_to_eaten[target_left_balance];
            min_eaten = std::min(min_eaten, jars_eaten_from_left + j);
        }
    }

    std::cout << min_eaten << std::endl;
}

