    // A common canonical form is: (val | C_or) & C_and ^ C_xor
    // Or: (val ^ C_xor) & C_and | C_or
    // Let's use the order: OR, AND, XOR. This is usually sufficient.
    // (val | C_or) & C_and ^ C_xor

    std::vector<std::pair<char, int>> final_ops;
    if (C_or != 0) {
        final_ops.push_back({'|', C_or});
    }
    if (C_and != 1023) { // If C_and is 1023, it's equivalent to no AND operation.
        final_ops.push_back({'&', C_and});
    }
    if (C_xor != 0) {
        final_ops.push_back({'^', C_xor});
    }

    std::cout << final_ops.size() << "\n";
    for (const auto& op : final_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] stores the maximum possible initial value for a[i]

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;

            // Calculate the total delta applied to each element up to this point
            // for the purpose of finding the initial value.
            // This is a reverse pass, so we consider operations *after* this query.
            std::vector<long long> current_delta(n + 1, 0);
            for (int k = i + 1; k < m; ++k) {
                if (ops[k].type == 1) {
                    current_delta[ops[k].l] += ops[k].val;
                    if (ops[k].r + 1 < n) {
                        current_delta[ops[k].r + 1] -= ops[k].val;
                    }
                }
            }

            long long current_prefix_delta = 0;
            for (int j = 0; j < n; ++j) {
                current_prefix_delta += current_delta[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    b[j] = std::min(b[j], current_max_val - current_prefix_delta);
                }
            }
        }
    }

    // If b[j] is still LLONG_MAX, it means it was never constrained by a type 2 query.
    // We can set it to 0, as 0 is within the |a_i| <= 10^9 range.
    for (int j = 0; j < n; ++j) {
        if (b[j] == LLONG_MAX) {
            b[j] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> a_current = b; // This will be the array state after type 1 ops
    std::vector<long long> diff(n + 1, 0); // Difference array for range updates

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            diff[ops[i].l] += ops[i].val;
            if (ops[i].r + 1 < n) {
                diff[ops[i].r + 1] -= ops[i].val;
            }
        } else { // type 2 query
            long long current_prefix_sum = 0;
            long long max_val_in_range = LLONG_MIN;
            for (int j = 0; j < n; ++j) {
                current_prefix_sum += diff[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    max_val_in_range = std::max(max_val_in_range, b[j] + current_prefix_sum);
                }
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
