struct Child {
    long long v, d, p;
    int original_idx;
    bool removed;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].removed = false;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (children[i].removed) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].removed = true; // Child i goes to the doctor

        long long current_v_cry = children[i].v;
        long long total_d_cry_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (children[j].removed) {
                continue;
            }

            // Apply accumulated d_cry_effect
            children[j].p -= total_d_cry_effect;

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--; // v_cry decreases for subsequent children
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].removed = true;
                total_d_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

