    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = std::numeric_limits<long long>::max();
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // f values are only a_i + a_j.
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    if (n >= 2) {
        long long current_goodness = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                best_partition[a[i].original_index] = 1;
            }
        }
    } else { // n=1, no pairs, goodness is 0.
        min_goodness = 0;
        best_partition[a[0].original_index] = 1;
    }

    // Case 2: At least one element in S1 and at least one in S2.
    // This means there will be f values of type a_i + a_j + h.
    // The minimum possible f value is a_1 + a_2.
    // The maximum possible f value is a_{n-1} + a_n + h.
    // Goodness = (a_{n-1} + a_n + h) - (a_1 + a_2)
    // This partition is achieved by putting a_1 in S1 and a_2 in S2 (or vice versa),
    // and then distributing the rest.
    // For example, put a_1 in S1, and all other elements in S2.
    // min_f = a_1 + a_2 (if a_1 in S1, a_2 in S2) or a_2 + a_3 (if a_2, a_3 in S2)
    // max_f = a_{n-1} + a_n + h (if a_{n-1} in S1, a_n in S2) or a_{n-1} + a_n (if a_{n-1}, a_n in S2)

    // Consider a partition where a_1 is in S1 and all other elements are in S2.
    // min_f:
    //   - a_1 + a_2 + h (a_1 in S1, a_2 in S2)
    //   - a_2 + a_3 (a_2, a_3 in S2)
    //   So, min_f = min(a_1 + a_2 + h, a_2 + a_3)
    // max_f:
    //   - a_1 + a_n + h (a_1 in S1, a_n in S2)
    //   - a_{n-1} + a_n (a_{n-1}, a_n in S2)
    //   So, max_f = max(a_1 + a_n + h, a_{n-1} + a_n)
    // Goodness = max_f - min_f
    if (n >= 2) {
        long long current_min_f = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
        if (n == 2) { // Special case for n=2, only a_1+a_2+h is possible
            current_min_f = a[0].value + a[1].value + h;
        }

        long long current_max_f = std::max(a[0].value + a[n - 1].value + h, a[n - 2].value + a[n - 1].value);
        if (n == 2) { // Special case for n=2, only a_1+a_2+h is possible
            current_max_f = a[0].value + a[1].value + h;
        }

        long long goodness_option2 = current_max_f - current_min_f;

        if (goodness_option2 < min_goodness) {
            min_goodness = goodness_option2;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    // Case 3: Partition a_1, a_2 into S1 and a_3, ..., a_n into S2.
    // This is relevant if h is large, and we want to avoid a_1+a_2+h.
    // If a_1, a_2 are in S1, and a_3, ..., a_n are in S2.
    // min_f:
    //   - a_1 + a_2 (a_1, a_2 in S1)
    //   - a_1 + a_3 + h (a_1 in S1, a_3 in S2)
    //   - a_3 + a_4 (a_3, a_4 in S2)
    //   So, min_f = min(a_1 + a_2, a_1 + a_3 + h, a_3 + a_4)
    //   If n=2, only a_1+a_2.
    //   If n=3, min(a_1+a_2, a_1+a_3+h).
    // max_f:
    //   - a_1 + a_n + h (a_1 in S1, a_n in S2)
    //   - a_{n-1} + a_n (a_{n-1}, a_n in S2)
    //   So, max_f = max(a_1 + a_n + h, a_{n-1} + a_n)
    //   If n=2, only a_1+a_2.
    //   If n=3, max(a_1+a_3+h).
    if (n >= 3) {
        long long current_min_f_val = a[0].value + a[1].value; // a_1+a_2
        current_min_f_val = std::min(current_min_f_val, a[0].value + a[2].value + h); // a_1+a_3+h
        if (n >= 4) {
            current_min_f_val = std::min(current_min_f_val, a[2].value + a[3].value); // a_3+a_4
        }

        long long current_max_f_val = a[0].value + a[n - 1].value + h; // a_1+a_n+h
        if (n >= 4) {
            current_max_f_val = std::max(current_max_f_val, a[n - 2].value + a[n - 1].value); // a_{n-1}+a_n
        } else if (n == 3) { // Only a_1+a_3+h is possible for cross-subsequence max
            // No a_{n-1}+a_n if n=3 and a_3 is the only element in S2
            // But a_3 is in S2, so a_1+a_3+h is the only cross-subsequence value.
            // No same-subsequence values in S2 if only one element.
            // So max_f is max(a_1+a_2, a_1+a_3+h)
            current_max_f_val = std::max(a[0].value + a[1].value, a[0].value + a[2].value + h);
        }

        long long goodness_option3 = current_max_f_val - current_min_f_val;

        if (goodness_option3 < min_goodness) {
            min_goodness = goodness_option3;
            best_partition[a[0].original_index] = 1;
            best_partition[a[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

