    // If `count_ones_a` is odd, `parity(a)` is 1. `a` becomes `a + '1'`. `count_ones` becomes `count_ones_a + 1`.
    // In both cases, the new `count_ones` is `count_ones_a` if `count_ones_a` is even, and `count_ones_a + 1` if `count_ones_a` is odd.
    // This means the new `count_ones` is always `count_ones_a` if `count_ones_a` is even, and `count_ones_a` + 1 if `count_ones_a` is odd.
    // This is equivalent to `count_ones_a` if `count_ones_a % 2 == 0`, and `count_ones_a + 1` if `count_ones_a % 2 == 1`.
    // This can be written as `count_ones_a + (count_ones_a % 2)`.
    // So, after one append operation, the number of ones becomes `count_ones_a + (count_ones_a % 2)`.
    // This is the smallest even number greater than or equal to `count_ones_a`.
    // Let `current_ones = count_ones_a`.
    // After 1 op: `current_ones = current_ones + (current_ones % 2)`.
    // After 2 ops: `current_ones = current_ones + (current_ones % 2)`. (Since `current_ones` is now even, `current_ones % 2` is 0, so it doesn't change).
    // So, after the first append operation, the number of ones becomes `count_ones_a` if `count_ones_a` is even, or `count_ones_a + 1` if `count_ones_a` is odd.
    // And for all subsequent append operations, the number of ones will remain the same (because the parity will always be 0, so '0' is appended).
    // This means the maximum number of ones we can achieve in any string derived from 'a' by appending is `count_ones_a` if `count_ones_a` is even, or `count_ones_a + 1` if `count_ones_a` is odd.
    // Let's call this `max_ones_in_a_after_appends`.
    // `max_ones_in_a_after_appends = count_ones_a + (count_ones_a % 2)`.

    // The length of 'a' can be increased by appending.
    // The length of 'a' can be decreased by removing the first character.
    // We need to check if 'b' can be a suffix of some string 'a_prime' that is derived from 'a'.
    // This means 'a_prime' must have length at least |b|.
    // The number of ones in 'a_prime' must be `count_ones_b`.
    // The maximum number of ones we can have in a string derived from 'a' by appending is `count_ones_a + (count_ones_a % 2)`.
    // Let `max_ones_possible_from_a = count_ones_a + (count_ones_a % 2)`.

    // If `count_ones_b` is greater than `max_ones_possible_from_a`, it's impossible.
    // This is because appending can only increase the count of ones by at most 1 (if parity is 1),
    // and then it stabilizes. Removing characters can only decrease or keep the count of ones.
    // So, `count_ones_b` must be less than or equal to `max_ones_possible_from_a`.

    // Also, the length of 'a' must be at least the length of 'b' after some operations.
    // If `|a| < |b|`, we must append at least `|b| - |a|` times.
    // Each append operation increases the length by 1.
    // So, the length of the string `a_prime` (before removing prefix) can be `|a| + k` for `k >= 0`.
    // The number of ones in `a_prime` would be `count_ones_a` if `k=0`.
    // If `k > 0`, the number of ones would be `count_ones_a + (count_ones_a % 2)`.
    // Let `current_ones_a = count_ones_a`.
    // If `current_ones_a % 2 == 1`, then `current_ones_a++`. This is the effect of the first append.
    // After this, any further appends add '0' and don't change the count of ones.
    // So, the effective number of ones in `a` after any number of appends (if at least one append is performed)
    // is `count_ones_a + (count_ones_a % 2)`.
    // If no appends are performed, the number of ones is `count_ones_a`.

    // Case 1: No appends are performed.
    // In this case, `a` must be transformed into `b` only by removing prefix characters.
    // This means `b` must be a suffix of `a`.
    // And `count_ones_a` must be equal to `count_ones_b`.
    // This is not quite right. If `b` is a suffix of `a`, then `count_ones_b` is just the count of ones in that suffix.
    // The problem is asking if `a` can be turned into `b`.
    // This means `b` must be a suffix of some `a'` where `a'` is derived from `a` by appending.
    // And `a'` must have length at least `|b|`.

    // Let's simplify.
    // We can always make the length of `a` at least `|b|` by appending '0's or '1's.
    // The maximum number of '1's we can have in `a` after any number of appends is `count_ones_a + (count_ones_a % 2)`.
    // Let `max_ones_in_a_after_appends = count_ones_a + (count_ones_a % 2)`.
    // This is the number of ones in `a` if we append at least once.
    // If we don't append at all, the number of ones is `count_ones_a`.

    // So, the number of ones in the string `a_prime` (which `b` will be a suffix of)
    // can be `count_ones_a` (if no appends are done)
    // OR `count_ones_a + 1` (if `count_ones_a` is odd and at least one append is done)
    // OR `count_ones_a` (if `count_ones_a` is even and at least one append is done).
    // In summary, the number of ones in `a_prime` will be either `count_ones_a` or `count_ones_a + 1` (if `count_ones_a` is odd).
    // Let `final_ones_a` be the number of ones in `a` after all possible appends.
    // `final_ones_a = count_ones_a + (count_ones_a % 2)`.

    // We need to check if `count_ones_b` is less than or equal to `final_ones_a`.
    // If `count_ones_b <= final_ones_a`, then it is possible to achieve `count_ones_b` ones.
    // Why? Because we can always append enough characters to make `a` long enough.
    // If `count_ones_a` is even, `final_ones_a = count_ones_a`. We can only have `count_ones_a` ones.
    // If `count_ones_a` is odd, `final_ones_a = count_ones_a + 1`. We can have `count_ones_a` (if no appends) or `count_ones_a + 1` (if at least one append).
    // So, if `count_ones_a` is even, we can only ever have `count_ones_a` ones.
    // If `count_ones_a` is odd, we can have `count_ones_a` or `count_ones_a + 1` ones.

    // Let `max_ones_reachable_in_a = count_ones_a + (count_ones_a % 2)`.
    // This is the maximum number of ones we can have in `a` after any number of append operations.
    // If `count_ones_b > max_ones_reachable_in_a`, then it's impossible.
    // Example: a="00", b="1". count_ones_a=0, count_ones_b=1. max_ones_reachable_in_a=0. Impossible.
    // Example: a="0", b="1". count_ones_a=0, count_ones_b=1. max_ones_reachable_in_a=0. Impossible.

    // If `count_ones_b <= max_ones_reachable_in_a`, is it always possible?
    // We need to ensure that the length of `a` can be made at least `|b|`.
    // We can always append characters until `|a| >= |b|`.
    // If `count_ones_b <= max_ones_reachable_in_a`, then we can achieve `count_ones_b` ones.
    // The only constraint is that `|a|` must be at least `|b|` after some operations.
    // If `|a| < |b|`, we must append `|b| - |a|` times.
    // If `|a| >= |b|`, we might not need to append at all, or we can append and then remove.

    // The key insight is that we can always make the string `a` long enough by appending.
    // Each append operation increases the length by 1.
    // The number of ones in `a` can be `count_ones_a` (if no appends)
    // or `count_ones_a + (count_ones_a % 2)` (if at least one append).
    // Let `current_ones_in_a = count_ones_a`.
    // If `current_ones_in_a % 2 == 1`, then we can perform one append operation to make it `current_ones_in_a + 1`.
    // After this, any further append operations will add '0' and not change the count of ones.
    // So, the possible counts of ones in `a` (before removing prefix) are:
    // 1. `count_ones_a` (if we don't append, and `|a| >= |b|`)
    // 2. `count_ones_a + (count_ones_a % 2)` (if we append at least once, which we must do if `|a| < |b|`)

    // Let's consider the two scenarios for the number of ones in the string `a_prime` from which `b` is a suffix:
    // Scenario 1: `a_prime` has `count_ones_a` ones. This is possible if we don't perform any append operations.
    //             This implies `|a| >= |b|`.
    // Scenario 2: `a_prime` has `count_ones_a + (count_ones_a % 2)` ones. This is possible if we perform at least one append operation.
    //             This allows `|a|` to be extended to `|b|` or more.

    // So, we need to check if `count_ones_b` can be achieved.
    // If `count_ones_b == count_ones_a`:
    //   This is possible if `|a| >= |b|` (no appends needed, just remove prefix).
    //   OR if `count_ones_a % 2 == 0` (even), then `count_ones_a + (count_ones_a % 2) = count_ones_a`.
    //      In this case, we can append as many '0's as needed to make `|a| >= |b|`, and the count of ones remains `count_ones_a`.
    // If `count_ones_b == count_ones_a + 1`:
    //   This is only possible if `count_ones_a % 2 == 1` (odd).
    //   In this case, we must perform at least one append operation. This will make the count of ones `count_ones_a + 1`.
    //   We can then append more '0's if needed to make `|a| >= |b|`.

    // Combining these:
    // We need `count_ones_b` to be achievable.
    // The maximum number of ones we can achieve is `count_ones_a + (count_ones_a % 2)`.
    // If `count_ones_b > count_ones_a + (count_ones_a % 2)`, then it's impossible.
    // Otherwise (`count_ones_b <= count_ones_a + (count_ones_a % 2)`):
    //   It is always possible. We can always append enough characters to make `|a|` long enough.
    //   If `count_ones_a` is even: `count_ones_a + (count_ones_a % 2) = count_ones_a`.
    //     So we must have `count_ones_b <= count_ones_a`. Since `count_ones_b` cannot be negative, `count_ones_b` must be `count_ones_a`.
    //     If `count_ones_b == count_ones_a`, it's possible.
    //   If `count_ones_a` is odd: `count_ones_a + (count_ones_a % 2) = count_ones_a + 1`.
    //     So we must have `count_ones_b <= count_ones_a + 1`.
    //     If `count_ones_b == count_ones_a` or `count_ones_b == count_ones_a + 1`, it's possible.

    // This logic seems correct.
    // The length constraint: we can always make `a` long enough.
    // If `|a| < |b|`, we must append at least `|b| - |a|` times. This means we perform at least one append.
    // If `|a| >= |b|`, we might not need to append.

    // Let `max_ones_a_after_ops = count_ones_a + (count_ones_a % 2)`.
    // If `count_ones_b <= max_ones_a_after_ops`, then it's YES.
    // Otherwise, it's NO.

    // Example 1: a="01011", b="0110"
    // count_ones_a = 3 (odd)
    // count_ones_b = 3 (odd)
    // max_ones_a_after_ops = 3 + (3 % 2) = 3 + 1 = 4.
    // Is count_ones_b (3) <= max_ones_a_after_ops (4)? Yes. Output YES. Correct.

    // Example 2: a="0011", b="1110"
    // count_ones_a = 2 (even)
    // count_ones_b = 3 (odd)
    // max_ones_a_after_ops = 2 + (2 % 2) = 2 + 0 = 2.
    // Is count_ones_b (3) <= max_ones_a_after_ops (2)? No. Output NO. Correct.

    // Consider edge cases:
    // a="0", b="0"
    // count_ones_a=0, count_ones_b=0
    // max_ones_a_after_ops = 0 + (0%2) = 0.
    // 0 <= 0? Yes. Output YES. Correct. (Remove 0 chars)

    // a="1", b="1"
    // count_ones_a=1, count_ones_b=1
    // max_ones_a_after_ops = 1 + (1%2) = 2.
    // 1 <= 2? Yes. Output YES. Correct. (Remove 0 chars)

    // a="0", b="1"
    // count_ones_a=0, count_ones_b=1
    // max_ones_a_after_ops = 0 + (0%2) = 0.
    // 1 <= 0? No. Output NO. Correct.

    // a="1", b="0"
    // count_ones_a=1, count_ones_b=0
    // max_ones_a_after_ops = 1 + (1%2) = 2.
    // 0 <= 2? Yes. Output YES. Correct. (1 -> 11 -> 1 -> 0)

    // a="0", b="00"
    // count_ones_a=0, count_ones_b=0
    // max_ones_a_after_ops = 0 + (0%2) = 0.
    // 0 <= 0? Yes. Output YES. Correct. (0 -> 00)

    // a="1", b="11"
    // count_ones_a=1, count_ones_b=2
    // max_ones_a_after_ops = 1 + (1%2) = 2.
    // 2 <= 2? Yes. Output YES. Correct. (1 -> 11)

    // The logic seems robust.

    int max_ones_a_after_ops = count_ones_a + (count_ones_a % 2);

    if (count_ones_b <= max_ones_a_after_ops) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if all target tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int p_idx = 0;

    while (p_idx < m) {
        if (head_idx >= n) {
            // No more heads available, but there are still tracks to cover
            return false;
        }

        // Current head is h[head_idx]
        // Current target track is p[p_idx]

        // If the current head cannot reach the current target track p[p_idx]
        // even by moving left for T seconds (i.e., h[head_idx] + T < p[p_idx]),
        // then this head is too far to the left. We need to use the next head.
        if (h[head_idx] + T < p[p_idx]) {
            head_idx++;
            continue;
        }

        // The current head h[head_idx] can reach p[p_idx].
        // It can cover the range [h[head_idx] - T, h[head_idx] + T].
        // We want to cover as many subsequent p_j tracks as possible with this head.
        // The rightmost track this head can cover is h[head_idx] + T.
        long long current_head_coverage_right_limit = h[head_idx] + T;

        // The leftmost track this head can cover is h[head_idx] - T.
        // However, if p[p_idx] is to the left of h[head_idx], the head must move left.
        // The actual range covered by this head, starting from p[p_idx],
        // depends on whether p[p_idx] is to the left or right of h[head_idx].

        // Case 1: p[p_idx] is to the right of h[head_idx] (or at h[head_idx]).
        // The head moves right to p[p_idx]. Time taken: p[p_idx] - h[head_idx].
        // Remaining time: T - (p[p_idx] - h[head_idx]).
        // This head can then cover up to p[p_idx] + (T - (p[p_idx] - h[head_idx])) = h[head_idx] + T.
        // This is the simpler case, the rightmost point is h[head_idx] + T.

        // Case 2: p[p_idx] is to the left of h[head_idx].
        // The head moves left to p[p_idx]. Time taken: h[head_idx] - p[p_idx].
        // Remaining time: T - (h[head_idx] - p[p_idx]).
        // This head can then cover up to p[p_idx] + (T - (h[head_idx] - p[p_idx])) = 2 * p[p_idx] - h[head_idx] + T.
        // This is the rightmost point if the head first goes to p[p_idx] and then moves right.
        // This is also equivalent to h[head_idx] + T - 2 * (h[head_idx] - p[p_idx]).
        // The maximum reach is h[head_idx] + T.
        // The actual rightmost point reachable by this head, having covered p[p_idx], is:
        // max(h[head_idx] + T, p[p_idx] + (T - abs(h[head_idx] - p[p_idx])))
        // This simplifies to:
        // If p[p_idx] >= h[head_idx]: h[head_idx] + T
        // If p[p_idx] < h[head_idx]: p[p_idx] + (T - (h[head_idx] - p[p_idx])) = 2*p[p_idx] - h[head_idx] + T
        // Let's call this `effective_right_reach`.
        long long effective_right_reach;
        if (p[p_idx] >= h[head_idx]) {
            effective_right_reach = h[head_idx] + T;
        } else { // p[p_idx] < h[head_idx]
            // The head moves left to p[p_idx]. Cost: h[head_idx] - p[p_idx].
            // Remaining time: T - (h[head_idx] - p[p_idx]).
            // From p[p_idx], it can move right by this remaining time.
            effective_right_reach = p[p_idx] + (T - (h[head_idx] - p[p_idx]));
        }

        // Now, advance p_idx as long as tracks are covered by the current head.
        while (p_idx < m && p[p_idx] <= effective_right_reach) {
            p_idx++;
        }

        // Move to the next head
        head_idx++;
    }

    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p_j and h_i is ~10^10.
                                    // A head might need to move 10^10 units.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

