#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs_count = 0;

    // max_r_for_bad[l] stores the maximum r such that s[l-1...r-1] is a bad substring.
    // If s[l-1...r-1] is bad, then s[l-1...r'-1] for r' < r is also bad.
    // We want to find the largest r such that s[l-1...r-1] is bad.
    // This is equivalent to finding the smallest r_prime such that s[l-1...r_prime-1] is good.
    // Then max_r_for_bad[l] = r_prime - 1.
    // For a fixed l, the number of bad pairs (l, r) is max_r_for_bad[l] - l + 1.
    // If no good r_prime exists for a given l, then max_r_for_bad[l] = n.
    // If l > max_r_for_bad[l], it means there are no bad pairs starting at l.

    // The condition for a good substring s[l-1...r-1] is that there exist x, k
    // such that l-1 <= x < x+2k <= r-1 and s[x] = s[x+k] = s[x+2k].
    // Let's find the smallest r_prime for each l.
    // r_prime is the smallest index such that s[l-1...r_prime-1] contains a 3-AP.
    // If no such r_prime exists, we can consider it n+1.

    // We can iterate l from 0 to n-1.
    // For each l, we need to find the smallest r_prime.
    // A naive approach would be to iterate r from l to n-1, and for each (l, r) check all x, k.
    // This is too slow.

    // Let's find the minimum right endpoint `min_r_idx[x]` for each `x` such that `s[x]` is the start of a 3-AP.
    // `min_r_idx[x]` = `x + 2k` for the smallest `k` such that `s[x] = s[x+k] = s[x+2k]`.
    // If no such `k` exists, `min_r_idx[x]` can be `n`.
    std::vector<int> min_r_idx(n, n); // Stores x+2k for the smallest k, or n if no such k.

    // Iterate x from n-1 down to 0.
    // For each x, we need to find k.
    // k can be 1, 2, 3, ...
    // The maximum k is (n-1-x)/2.
    // We only need to check small values of k.
    // If s[x] = s[x+k] = s[x+2k], then x+2k is a potential right endpoint.
    // The smallest k is 1. So we check s[x+1], s[x+2].
    // If s[x] = s[x+1] = s[x+2], then min_r_idx[x] = x+2.
    // If s[x] = s[x+2] = s[x+4], then min_r_idx[x] = min(min_r_idx[x], x+4).
    // If s[x] = s[x+3] = s[x+6], then min_r_idx[x] = min(min_r_idx[x], x+6).
    // The maximum k we need to check is small.
    // If k is large, say k > 6, then x+2k > x+12.
    // If there is a 3-AP with large k, say (x, x+k, x+2k), then the substring s[x...x+2k] is "good".
    // If there is no 3-AP with small k (k <= 6), then the substring s[x...x+12] is "bad".
    // This implies that if a 3-AP exists, it must have a small k.
    // This is a known property for arithmetic progressions in binary strings.
    // For any binary string of length 9, it must contain a 3-AP of the form s[x]=s[x+k]=s[x+2k] for some k.
    // This means if a substring has length >= 9, it must contain a 3-AP.
    // The maximum length of a bad substring is 8.
    // So, we only need to check k such that x+2k < x+9, i.e., 2k < 9, so k <= 4.
    // Let's check k up to 6 for safety, as some sources say length 9, others 10.
    // If a substring of length 9 (indices x to x+8) is bad, it means no 3-AP exists.
    // Example: 001100110 (length 9) - no 3-AP.
    // Example: 0011001100 (length 10) - no 3-AP.
    // Example: 00110011000 (length 11) - s[8]=s[9]=s[10]=0, k=1.
    // The maximum length of a string without a 3-AP is 10.
    // So, if r-l+1 > 10, it must contain a 3-AP.
    // This means we only need to check k such that x+2k < x+11, i.e., 2k < 11, so k <= 5.
    // Let's check k up to 5.

    for (int x = 0; x < n; ++x) {
        for (int k = 1; k <= 5; ++k) { // k up to 5 is sufficient for length 11.
                                        // If x+2k >= n, then this k is too large.
            if (x + 2 * k < n) {
                if (s[x] == s[x + k] && s[x] == s[x + 2 * k]) {
                    min_r_idx[x] = x + 2 * k;
                    break; // Found smallest k for this x.
                }
            } else {
                break; // Further k values will also be out of bounds.
            }
        }
    }

    // Now, for each l (0-indexed), we want to find the smallest r_prime (0-indexed)
    // such that s[l...r_prime] contains a 3-AP.
    // This means there exists some x such that l <= x <= r_prime and min_r_idx[x] <= r_prime.
    // We can maintain a running minimum of min_r_idx[x] as l decreases.
    // Let current_min_r_endpoint be the minimum of min_r_idx[x] for x >= l.
    // For a given l, the smallest r_prime is current_min_r_endpoint.
    // If current_min_r_endpoint is n, it means no 3-AP starts at or after l.
    // In this case, all substrings s[l...r] for r from l to n-1 are bad.
    // The number of bad pairs is (n-1) - l + 1 = n-l.
    // Otherwise, the smallest r_prime is current_min_r_endpoint.
    // The bad substrings s[l...r] are those where r < current_min_r_endpoint.
    // So r can range from l to current_min_r_endpoint - 1.
    // The number of bad pairs is (current_min_r_endpoint - 1) - l + 1 = current_min_r_endpoint - l.

    int current_min_r_endpoint = n; // Initialize with n, meaning no 3-AP found yet.
    for (int l = n - 1; l >= 0; --l) {
        current_min_r_endpoint = std::min(current_min_r_endpoint, min_r_idx[l]);
        // current_min_r_endpoint now holds min(min_r_idx[x]) for x from l to n-1.
        // This is the smallest r_prime (0-indexed) such that s[l...r_prime] contains a 3-AP.
        // If current_min_r_endpoint is n, it means no 3-AP starts at or after l.
        // In this case, all substrings s[l...r] for r from l to n-1 are bad.
        // The number of bad pairs is (n-1) - l + 1 = n-l.
        // Otherwise, the smallest r_prime is current_min_r_endpoint.
        // The bad substrings s[l...r] are those where r can range from l to current_min_r_endpoint - 1.
        // The number of bad pairs is (current_min_r_endpoint - 1) - l + 1 = current_min_r_endpoint - l.

        // Note: current_min_r_endpoint is 0-indexed.
        // The r in the problem statement is 1-indexed.
        // If current_min_r_endpoint is the 0-indexed rightmost index of the 3-AP,
        // then the 1-indexed r_prime is current_min_r_endpoint + 1.
        // The bad pairs (l_1idx, r_1idx) are such that r_1idx < r_prime_1idx.
        // So r_1idx can go up to current_min_r_endpoint.
        // The number of bad pairs for a fixed l_1idx is current_min_r_endpoint - l_1idx + 1.
        // Using 0-indexed l: number of bad pairs is current_min_r_endpoint - l + 1.

        // However, if current_min_r_endpoint is n, it means no 3-AP exists starting at or after l.
        // So all substrings s[l...r] for r from l to n-1 are bad.
        // The number of bad pairs is (n-1) - l + 1 = n - l.
        // This can be unified: if current_min_r_endpoint is n, then n - l.
        // If current_min_r_endpoint < n, then current_min_r_endpoint - l.
        // This is equivalent to std::min(n, current_min_r_endpoint) - l.

        bad_pairs_count += (long long)std::min(n, current_min_r_endpoint) - l;
    }

    std::cout << total_pairs - bad_pairs_count << std::endl;

    return 0;
}

