    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        int min_idx = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < a[min_idx]) {
                min_idx = i;
            }
        }

        long long min_val = a[min_idx];
        long long total_spells = 0;

        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile a[i], we can add min_val to it
            // as many times as possible without exceeding k.
            // The number of times is floor((k - a[i]) / min_val)
            if (a[i] < k) { // Only if there's room to add
                total_spells += (k - a[i]) / min_val;
            }
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

