    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem asks for a different permutation p' with the same fingerprint.
        // The fingerprint is the sorted list of adjacent sums.
        // If p = [p_1, p_2, ..., p_n], the sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
        // If we reverse the permutation to p' = [p_n, p_{n-1}, ..., p_1],
        // the sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
        // These are exactly the same set of sums as for p, just in reverse order.
        // Therefore, their sorted lists (fingerprints) will be identical.
        // Since p is a permutation, all elements are distinct.
        // Thus, p_i != p_{n-1-i} for at least one i (unless n=1, but n>=2).
        // For n >= 2, p is guaranteed to be different from its reverse unless n=1 or p is a palindrome.
        // A permutation cannot be a palindrome unless n=1.
        // For example, if p = [1,2,3], reverse is [3,2,1]. They are different.
        // If p = [1,2], reverse is [2,1]. They are different.
        // So, reversing the permutation always yields a different permutation with the same fingerprint.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

