int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int max_a1 = a[0]; // Initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            int pile_idx = i; // 0-indexed pile index
            int pile_num = i + 1; // 1-indexed pile number
            int haybales_in_pile = a[pile_idx];
            int cost_per_haybale = pile_num - 1; // Cost to move one haybale to pile 1

            if (d >= cost_per_haybale) {
                // Calculate how many haybales can be moved from this pile
                int num_can_move = d / cost_per_haybale;

                // Move min(haybales_in_pile, num_can_move) haybales
                int moved_haybales = std::min(haybales_in_pile, num_can_move);

                max_a1 += moved_haybales;
                d -= moved_haybales * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile
                // And subsequent piles will have even higher costs, so break.
                break;
            }
        }
        std::cout << max_a1 << std::endl;
    }
    return 0;
}

