void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit and '3' for the rest.
        // This ensures that the number is not divisible by 2 (since it ends in 3, an odd digit)
        // and not divisible by 3 (since the sum of digits will be 2 + (n-1)*3.
        // For n=2, sum=2+3=5. 5%3 != 0.
        // For n=3, sum=2+3+3=8. 8%3 != 0.
        // For n=4, sum=2+3+3+3=11. 11%3 != 0.
        // In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        // (3n - 1) % 3 = -1 % 3 = 2 % 3 != 0.
        // So, the number will not be divisible by 2 or 3.
        // Since all digits are 2 or 3, and the number is not divisible by 2 or 3,
        // it satisfies the conditions.
        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

