void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n);

    // For elements a_i such that 2*a_i = T, we need to alternate their colors.
    // We use a counter `color_for_half_T` to assign 0, 1, 0, 1...
    int color_for_half_T = 0; 

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (2 * a[i] < T) {
            // If a_i is less than T/2, it should ideally be paired with an element > T/2.
            // We assign all such elements to color 0 (white).
            p[i] = 0;
        } else if (2 * a[i] > T) {
            // If a_i is greater than T/2, it should ideally be paired with an element < T/2.
            // We assign all such elements to color 1 (black).
            p[i] = 1;
        } else { // 2 * a[i] == T
            // If a_i is exactly T/2, it can form a pair with another T/2.
            // To minimize pairs of (T/2, T/2), we alternate their colors.
            p[i] = color_for_half_T;
            color_for_half_T = 1 - color_for_half_T; // Toggle color for the next T/2
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

