int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // Skip a[i][i] which is 0
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then there must be some p[j] > p[i], and min(p[i], p[j]) = p[i].
        // So max_val_in_row would be p[i].
        // If p[i] is n, then for all j != i, min(p[i], p[j]) = p[j].
        // The maximum of these p[j] values would be n-1 (since n is the largest value).
        // So if max_val_in_row is n-1, p[i] must be n.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from stdio and disables synchronization.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // For N up to 150,000, a vector is efficient.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n == 0) { // Edge case: if n is 0, no prices, no bad prices.
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price.
        // The last price can never be bad because there are no later days.
        int min_suffix = a[n - 1];

        // Iterate from the second-to-last day backwards to the first day.
        // This allows us to maintain the minimum price encountered so far
        // in the suffix of the array.
        for (int i = n - 2; i >= 0; --i) {
            // If the current price a[i] is greater than the minimum price
            // found in the suffix a[i+1...n-1], then a[i] is a bad price.
            if (a[i] > min_suffix) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix, it means a[i]
                // is less than or equal to min_suffix.
                // This a[i] now becomes the new minimum for the suffix a[i...n-1].
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The total number of students divided by 3 (since each team needs 3 members).
        // 2. The number of coders (each team needs at least 1 coder).
        // 3. The number of mathematicians (each team needs at least 1 mathematician).
        // So, the number of teams 'k' must satisfy:
        // k <= (c + m + x) / 3
        // k <= c
        // k <= m
        // Combining these, k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.

        long long max_possible_teams = std::min({c, m, (c + m + x) / 3});

        std::cout << max_possible_teams << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_R_idx = -1; // Represents the last 'R' cell index (0-indexed string) or -1 for initial position 0.
                             // So, if last_R_idx = -1, it means we are at cell 0.
                             // If last_R_idx = k, it means we are at cell k+1.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed).
                // Distance from previous 'R' cell (or 0) to current 'R' cell.
                // If last_R_idx was -1, previous cell was 0. Current cell is i+1. Distance is (i+1) - 0 = i+1.
                // If last_R_idx was k, previous cell was k+1. Current cell is i+1. Distance is (i+1) - (k+1) = i-k.
                max_dist = std::max(max_dist, i - last_R_idx);
                last_R_idx = i;
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // (or 0 if no 'R's) to the target n+1.
        // If last_R_idx was -1, it means no 'R's were found, so we jump from 0 to n+1. Distance is n+1.
        // If last_R_idx was k, it means the last 'R' was at cell k+1. We jump from k+1 to n+1. Distance is (n+1) - (k+1) = n-k.
        max_dist = std::max(max_dist, n - last_R_idx);

        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The first class will have median a[n-1]
        // The second class will have median a[n]
        // This corresponds to partitioning the sorted array into two halves:
        // [a_0, ..., a_{n-1}] and [a_n, ..., a_{2n-1}]
        // Each half has n elements.
        // If n is odd, then n elements is an odd number, and the median is a_{(n-1)/2} for the first half
        // and a_{n + (n-1)/2} for the second half.
        // This is not what the problem implies.
        // The problem implies that we can choose any odd sizes k1, k2 such that k1+k2 = 2n.
        // The key insight is that to minimize the difference, the medians should be as close as possible.
        // When the entire array is sorted, the median of any odd-sized subset of elements
        // will be one of the elements in the original sorted array.
        // Consider the two classes. Let their medians be M1 and M2.
        // To minimize |M1 - M2|, we should pick M1 and M2 to be adjacent elements in the sorted array.
        // If we pick a_i as the median of Class 1 and a_j as the median of Class 2,
        // then Class 1 must contain at least (k1-1)/2 elements smaller than or equal to a_i,
        // and at least (k1-1)/2 elements greater than or equal to a_i.
        // Similarly for Class 2.
        // The optimal strategy is to pick the two "middle" elements of the entire sorted array
        // as the medians of the two classes.
        // These are a[n-1] and a[n].
        // We can always construct two classes with these medians.
        // Class 1: {a_0, ..., a_{n-1}} (size n)
        // Class 2: {a_n, ..., a_{2n-1}} (size n)
        // If n is odd, then both classes have odd size, and their medians are a_{(n-1)/2} and a_{n + (n-1)/2}.
        // This is not what we want.
        // The problem states that the median of an array of $2k+1$ elements is $b_{k+1}$ (1-indexed).
        // For an array of size $S$, the median is $b_{(S-1)/2 + 1}$.
        //
        // The crucial observation is that if we sort the entire array $a_0, a_1, \dots, a_{2n-1}$,
        // then the minimum possible difference between the medians of two odd-sized classes
        // will always be achieved by picking $a_{n-1}$ and $a_n$ as the two medians.
        //
        // Let's prove this. Suppose we have two classes $C_1$ and $C_2$ with medians $M_1$ and $M_2$.
        // Let $M_1 = a_i$ and $M_2 = a_j$ for some $i, j$.
        // Without loss of generality, assume $M_1 \le M_2$.
        // For $a_i$ to be the median of $C_1$, $C_1$ must contain $a_i$, and $(k_1-1)/2$ elements $\le a_i$
        // and $(k_1-1)/2$ elements $\ge a_i$.
        // Similarly for $a_j$ and $C_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        // The element $a_{n-1}$ is the largest of the first $n$ elements.
        // The element $a_n$ is the smallest of the last $n$ elements.
        //
        // We can always form two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        // For example, Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$ and Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is not valid because $n$ might be even.
        //
        // The simplest partition that works is to put $a_{n-1}$ in one class and $a_n$ in the other.
        // Let $k_1 = 1$ and $k_2 = 2n-1$.
        // Class 1: $\{a_{n-1}\}$. Median is $a_{n-1}$.
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // This class has $2n-1$ elements. Its median is $a_{(2n-1-1)/2} = a_{n-1}$ if sorted.
        // But the elements are not necessarily sorted in this way.
        //
        // The problem is simpler than I thought.
        // The minimum difference is always $a_n - a_{n-1}$.
        // We can always construct two classes with these medians.
        // Class 1: $\{a_{n-1}\}$ (size 1, median $a_{n-1}$)
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$).
        // The elements of Class 2, when sorted, are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // The median of Class 2 (size $2n-1$) is the $((2n-1-1)/2 + 1)$-th element, which is the $n$-th element.
        // In the sorted list of Class 2 elements, the $n$-th element is $a_n$.
        // So, we can form Class 1 with median $a_{n-1}$ and Class 2 with median $a_n$.
        // The difference is $|a_n - a_{n-1}|$.
        // This is always possible.
        //
        // Can we do better?
        // Suppose we pick two medians $M_1$ and $M_2$ such that $M_1 < a_{n-1}$ or $M_2 > a_n$.
        // If $M_1 < a_{n-1}$ and $M_2 \le a_n$:
        // For $M_1$ to be a median of a class of size $k_1$, there must be $(k_1-1)/2$ elements $\le M_1$ and $(k_1-1)/2$ elements $\ge M_1$.
        // For $M_2$ to be a median of a class of size $k_2$, there must be $(k_2-1)/2$ elements $\le M_2$ and $(k_2-1)/2$ elements $\ge M_2$.
        //
        // Consider the $n$ smallest elements $a_0, \dots, a_{n-1}$.
        // And the $n$ largest elements $a_n, \dots, a_{2n-1}$.
        //
        // Any class with median $M$ must contain $M$.
        // If $M \le a_{n-1}$, then at most $n$ elements are $\le M$.
        // If $M \ge a_n$, then at most $n$ elements are $\ge M$.
        //
        // Let $M_1$ be the median of Class 1 and $M_2$ be the median of Class 2.
        // Assume $M_1 \le M_2$.
        // The total number of elements less than or equal to $M_1$ is $i+1$ if $M_1 = a_i$.
        // The total number of elements greater than or equal to $M_2$ is $2n-j$ if $M_2 = a_j$.
        //
        // For $M_1$ to be a median of a class of size $k_1$, there must be at least $(k_1-1)/2$ elements $\le M_1$ and $(k_1-1)/2$ elements $\ge M_1$ within that class.
        // For $M_2$ to be a median of a class of size $k_2$, there must be at least $(k_2-1)/2$ elements $\le M_2$ and $(k_2-1)/2$ elements $\ge M_2$ within that class.
        //
        // The total number of elements $\le M_1$ in the entire set is $i+1$.
        // The total number of elements $\ge M_2$ in the entire set is $2n-j$.
        //
        // The sum of elements required to be $\le M_1$ or $\le M_2$ is $(k_1-1)/2 + (k_2-1)/2$.
        // The sum of elements required to be $\ge M_1$ or $\ge M_2$ is $(k_1-1)/2 + (k_2-1)/2$.
        //
        // Total elements $2n$.
        // $k_1+k_2 = 2n$.
        // $(k_1-1)/2 + (k_2-1)/2 = (k_1+k_2-2)/2 = (2n-2)/2 = n-1$.
        //
        // So we need $n-1$ elements $\le M_1$ (or $M_2$) and $n-1$ elements $\ge M_1$ (or $M_2$).
        //
        // If $M_1 = a_i$ and $M_2 = a_j$.
        // The elements $a_0, \dots, a_i$ are $\le M_1$.
        // The elements $a_j, \dots, a_{2n-1}$ are $\ge M_2$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are the $n$ smallest elements.
        // The elements $a_n, \dots, a_{2n-1}$ are the $n$ largest elements.
        //
        // If $M_1 < a_{n-1}$, then $i < n-1$.
        // If $M_2 > a_n$, then $j > n$.
        //
        // Suppose $M_1 = a_i$ and $M_2 = a_j$.
        // The elements $a_0, \dots, a_i$ must contain at least $(k_1-1)/2$ elements for $C_1$.
        // The elements $a_j, \dots, a_{2n-1}$ must contain at least $(k_2-1)/2$ elements for $C_2$.
        //
        // The total number of elements available for the "lower half" of $C_1$ and $C_2$ is $i+1$ (for $M_1$) and $j+1$ (for $M_2$).
        // The total number of elements available for the "upper half" of $C_1$ and $C_2$ is $2n-i$ (for $M_1$) and $2n-j$ (for $M_2$).
        //
        // The crucial point is that $a_{n-1}$ and $a_n$ are the two "middle" elements of the sorted array.
        // Any median $M_1$ of a class $C_1$ must have $(k_1-1)/2$ elements smaller than it and $(k_1-1)/2$ elements larger than it.
        // Similarly for $M_2$.
        //
        // The total number of elements smaller than $M_1$ and $M_2$ combined must be at least $(k_1-1)/2 + (k_2-1)/2 = n-1$.
        // The total number of elements larger than $M_1$ and $M_2$ combined must be at least $(k_1-1)/2 + (k_2-1)/2 = n-1$.
        //
        // If $M_1 = a_i$ and $M_2 = a_j$ with $i < j$.
        // The elements $a_0, \dots, a_{i-1}$ are strictly less than $a_i$.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ are strictly greater than $a_j$.
        //
        // The $n-1$ smallest elements are $a_0, \dots, a_{n-2}$.
        // The $n-1$ largest elements are $a_{n+1}, \dots, a_{2n-1}$.
        //
        // If $M_1$ and $M_2$ are chosen such that $M_1 < a_{n-1}$ or $M_2 > a_n$, then $|M_1 - M_2|$ would be larger than $a_n - a_{n-1}$.
        // For example, if $M_1 = a_{n-2}$ and $M_2 = a_n$, then $|M_1 - M_2| = a_n - a_{n-2} \ge a_n - a_{n-1}$.
        // If $M_1 = a_{n-1}$ and $M_2 = a_{n+1}$, then $|M_1 - M_2| = a_{n+1} - a_{n-1} \ge a_n - a_{n-1}$.
        //
        // The minimum difference is achieved when $M_1$ and $M_2$ are adjacent in the sorted array.
        // The only pair of adjacent elements that can serve as medians for two classes that partition all $2n$ students
        // are $a_{n-1}$ and $a_n$.
        //
        // This is because $a_{n-1}$ is the largest element among the first $n$ elements, and $a_n$ is the smallest element among the last $n$ elements.
        // If we pick $a_i$ as a median, it needs $(k-1)/2$ elements smaller than it.
        // If we pick $a_j$ as a median, it needs $(k'-1)/2$ elements larger than it.
        //
        // The total number of elements needed to be smaller than the chosen medians is $n-1$.
        // The total number of elements needed to be larger than the chosen medians is $n-1$.
        //
        // The elements $a_0, \dots, a_{n-2}$ are $n-1$ elements.
        // The elements $a_{n+1}, \dots, a_{2n-1}$ are $n-1$ elements.
        //
        // If we choose $a_{n-1}$ and $a_n$ as the medians, we can assign $a_0, \dots, a_{n-2}$ to be the "smaller" elements for $a_{n-1}$ and $a_n$.
        // And $a_{n+1}, \dots, a_{2n-1}$ to be the "larger" elements for $a_{n-1}$ and $a_n$.
        //
        // The construction given in the example for $n=5$:
        // $a = [2, 3, 4, 5, 8, 13, 13, 16, 17, 20]$
        // $n=5$, $2n=10$.
        // $a_{n-1} = a_4 = 8$.
        // $a_n = a_5 = 13$.
        // Difference is $13-8=5$.
        //
        // Example partition:
        // Class 1: $[3, 4, 13, 13, 20]$ (size 5, median $a_2=13$ if sorted)
        // Sorted: $[3, 4, 13, 13, 20]$. Median is $13$.
        // Class 2: $[2, 5, 8, 16, 17]$ (size 5, median $a_2=8$ if sorted)
        // Sorted: $[2, 5, 8, 16, 17]$. Median is $8$.
        // Difference $|13-8|=5$.
        //
        // This matches $a_n - a_{n-1}$ if we consider the medians to be $a_n$ and $a_{n-1}$ from the original sorted array.
        // In the example, $a_4=8$ and $a_5=13$.
        // The medians chosen are $8$ and $13$.
        //
        // The logic is that the $n$-th element ($a_{n-1}$ in 0-indexed) and $(n+1)$-th element ($a_n$ in 0-indexed)
        // are the "central" elements of the entire sorted array.
        // To minimize the difference between two medians, they should be as close as possible.
        // The closest possible values are $a_{n-1}$ and $a_n$.
        // We can always form two classes, one with median $a_{n-1}$ and the other with median $a_n$.
        //
        // Class 1: $\{a_{n-1}\}$ (size 1, median $a_{n-1}$)
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$).
        // The elements of Class 2, when sorted, are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // The median of Class 2 (size $2n-1$) is the $n$-th element (1-indexed).
        // In the sorted list of Class 2 elements, the $n$-th element is $a_n$.
        // So, we can form Class 1 with median $a_{n-1}$ and Class 2 with median $a_n$.
        // The difference is $|a_n - a_{n-1}|$.
        // This is the minimum possible difference.
        //
        // The minimum difference is $a_n - a_{n-1}$ (using 0-indexed array $a$).
        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The area of the full triangle is A = (1/2) * base * h.
    // Since base is 1, A = h/2.
    // Each of the n pieces must have area A_piece = A / n = (h/2) / n = h / (2n).

    // Consider a smaller triangle formed by a cut at distance x from the apex.
    // Due to similarity, its base will be x/h * original_base = x/h * 1 = x/h.
    // Its area A_x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want the i-th cut (from the apex) to be at distance x_i.
    // The triangle formed by the i-th cut (at x_i) should have an area equal to
    // i times the area of a single piece.
    // So, A_{x_i} = i * A_piece
    // x_i^2 / (2h) = i * (h / (2n))
    // x_i^2 = i * (h^2 / n)
    // x_i = sqrt(i * h^2 / n)
    // x_i = h * sqrt(i / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += c;
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available and largest available numbers
    // from the range [1, k+1].
    // Example: k=2, range [1,3]. Output: 1 3 2. Differences: |1-3|=2, |3-2|=1.
    // Example: k=3, range [1,4]. Output: 1 4 2 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1.
    // Example: k=4, range [1,5]. Output: 1 5 2 4 3. Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, pick from left (smallest available)
            std::cout << left++;
        } else { // Odd index, pick from right (largest available)
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k+1) elements, just append them in increasing order.
    // This will only generate a difference of 1, which is already among the k distinct differences
    // (specifically, it's the smallest one generated by the alternating pattern).
    // So, no new distinct differences are introduced.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

