#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    std::vector<long long> last_digits_sum_cycle(10);
    for (int i = 0; i < 10; ++i) {
        last_digits_sum_cycle[i] = 0;
        for (int j = 1; j <= 10; ++j) {
            last_digits_sum_cycle[i] += (static_cast<long long>(j) * i) % 10;
        }
    }

    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k = n / m; // Number of multiples of m up to n

        int m_last_digit = m % 10;

        long long full_cycles = k / 10;
        long long remaining_multiples = k % 10;

        long long total_sum = full_cycles * last_digits_sum_cycle[m_last_digit];

        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m_last_digit) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

