#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a non-increasing suffix
    // This is the first element from the right that breaks the non-increasing order
    // i.e., a[i] > a[i+1]
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-increasing.
    // If i=0, the whole array is non-increasing.

    // Find the rightmost peak of a non-decreasing suffix
    // This is the first element from the right that breaks the non-decreasing order
    // i.e., a[j] < a[j+1]
    int j = i; // Start search from i, as elements to the right of i are already non-increasing
               // and thus potentially part of a non-decreasing sequence if we pick from left.
               // More precisely, we need to find the first element from the right that breaks
               // the non-decreasing order of the suffix a[0...j].
               // The elements a[j...n-1] must be non-decreasing.
               // So we look for the first element a[k] such that a[k] < a[k+1]
               // starting from k=i-1 and going left.
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now a[j...n-1] is non-decreasing.
    // If j=0, the whole array is non-decreasing.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the number 1 is always beautiful.
    // The subsegment is just [1] at pos[1].
    // min_idx and max_idx track the current range of indices that contain 1...k.
    int min_idx = pos[1];
    int max_idx = pos[1];
    ans[0] = '1';

    // Iterate for m from 2 to n
    for (int k = 2; k <= n; ++k) {
        // Update min_idx and max_idx to include the position of k
        min_idx = std::min(min_idx, pos[k]);
        max_idx = std::max(max_idx, pos[k]);

        // The length of the subsegment p[min_idx ... max_idx] is max_idx - min_idx + 1.
        // If this length is equal to k, it means all numbers from 1 to k are
        // contained within this contiguous subsegment, and no other numbers.
        // Since p is a permutation, all numbers in this subsegment are distinct.
        // Therefore, if length == k, p[min_idx ... max_idx] is a permutation of 1...k.
        if (max_idx - min_idx + 1 == k) {
            ans[k - 1] = '1';
        } else {
            ans[k - 1] = '0';
        }
    }

    std::cout << ans << std::endl;
}

