#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // 0-indexed median position

    // First, ensure the median element itself is s
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually change it to s for subsequent checks

    // Elements to the left of the median must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
            // a[i] = s; // No need to actually change it, just count operations
        }
    }

    // Elements to the right of the median must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
            // a[i] = s; // No need to actually change it, just count operations
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>
#include <limits>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        // The quadratic equation for 'a' is a^2 - d*a + d = 0.
        // The discriminant is D = (-d)^2 - 4*1*d = d^2 - 4d.
        // For real solutions, D must be non-negative.
        // d^2 - 4d >= 0
        // d * (d - 4) >= 0

        // Case 1: d = 0
        // If d = 0, then a^2 - 0*a + 0 = 0 => a^2 = 0 => a = 0.
        // If a = 0, then b = d - a = 0 - 0 = 0.
        // So (a, b) = (0, 0) is a solution.
        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
            continue;
        }

        // Case 2: d > 0
        // For d > 0, d * (d - 4) >= 0 implies d - 4 >= 0, so d >= 4.
        // If 0 < d < 4, then d - 4 < 0, so d * (d - 4) < 0.
        // In this range, the discriminant is negative, so no real solutions.
        if (d < 4.0) {
            std::cout << "N\n";
            continue;
        }

        // Case 3: d >= 4
        // Discriminant D = d^2 - 4d is non-negative.
        // Solutions for 'a' are (d +/- sqrt(D)) / 2.
        double sqrt_D = std::sqrt(d * d - 4.0 * d);
        double a1 = (d + sqrt_D) / 2.0;
        double b1 = d - a1; // b = d - a

        // We need a, b to be non-negative.
        // Since d >= 4, d is positive.
        // sqrt_D is non-negative.
        // So a1 = (d + sqrt_D) / 2.0 will always be non-negative.
        // For b1 = d - a1 to be non-negative:
        // b1 = d - (d + sqrt_D) / 2.0 = (2d - d - sqrt_D) / 2.0 = (d - sqrt_D) / 2.0
        // We need d - sqrt_D >= 0, which means d >= sqrt_D.
        // Squaring both sides (since d >= 4, d is positive, sqrt_D is non-negative):
        // d^2 >= D
        // d^2 >= d^2 - 4d
        // 0 >= -4d
        // 4d >= 0
        // This is true for d >= 0.
        // So, both a1 and b1 are guaranteed to be non-negative when d >= 4.

        // The problem asks for any valid pair (a, b).
        // The pair (a1, b1) is a valid solution.
        std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (from sorted 'a')
    int right_ptr = 0; // Pointer for positions (from sorted 'a')

    // We try to match a[right_ptr] with a[left_ptr] such that a[left_ptr] > a[right_ptr]
    // and maximize such matches.
    // Both pointers iterate through the sorted array 'a'.
    // 'left_ptr' represents the element we are trying to place.
    // 'right_ptr' represents the original element at a position.
    // We want to find a 'left_ptr' element that is strictly greater than 'right_ptr' element.
    // Since both are sorted, we can use a greedy approach.
    // If a[left_ptr] > a[right_ptr], we found a valid pair. Increment both pointers and count.
    // If a[left_ptr] <= a[right_ptr], a[left_ptr] cannot be placed at a[right_ptr]'s position
    // to satisfy the condition. We need a larger element for a[right_ptr]'s position,
    // so we increment left_ptr to find a potentially larger element.
    while (left_ptr < n && right_ptr < n) {
        if (a[left_ptr] > a[right_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            left_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check for the increasing part from left
    // We need a_i >= i-1 for 0 <= i < k
    // The maximum possible k is n-1 (0-indexed)
    // So we need a_i >= i for 0 <= i < n-1
    // The first element a[0] must be at least 0.
    // The second element a[1] must be at least 1.
    // ...
    // The i-th element a[i] must be at least i.
    // This is for the case where k is the last element.
    // If k is not the last element, say k-1 (0-indexed), then a[k-1] must be at least k-1.
    // The condition is a[i] >= i for the increasing part.
    // Let's find the maximum index `left_reach` such that a[i] >= i for all 0 <= i <= left_reach.
    int left_reach = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_reach = i;
        } else {
            break;
        }
    }

    // Check for the decreasing part from right
    // We need a_i >= n-1-i for k <= i < n
    // The maximum possible k is 0 (0-indexed)
    // So we need a[i] >= n-1-i for 0 <= i < n
    // The last element a[n-1] must be at least 0.
    // The second to last a[n-2] must be at least 1.
    // ...
    // The i-th element a[i] must be at least n-1-i.
    // Let's find the minimum index `right_reach` such that a[i] >= n-1-i for all right_reach <= i < n.
    int right_reach = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_reach = i;
        } else {
            break;
        }
    }

    // If there is any overlap between the reachable indices, it's possible.
    // An overlap means there exists an index `k` (0-indexed) such that
    // `k` is reachable from the left (a[k] >= k) AND
    // `k` is reachable from the right (a[k] >= n-1-k).
    // This means `left_reach` must be greater than or equal to `right_reach`.
    if (left_reach >= right_reach) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

