    // 1. Final sign is positive (A+B is even).
    // 2. Final magnitude is >= 1.
    //    This requires at least one toy with magnitude >= 1 (from Box 1 or Box 4)
    //    OR all toys have magnitude < 1, but then the final magnitude would be < 1.
    //    So, we need A+D > 0.
    //    If A+D=0, then all initial toys have magnitude < 1.
    //    Then the final product will also have magnitude < 1.
    //    So, if A+D=0, Box 4 is impossible.
    //    If A+D > 0, we can always arrange operations to make the final magnitude >= 1.

    // So, for Box 4: (A+B)%2 == 0 AND (A+D > 0)
    if ((a + b) % 2 == 0 && (a + d > 0)) {
        ans4 = "Ya";
    }

    // Special case: total_toys == 1
    // If there's only one toy, it's the super toy.
    // Its box is the special box.
    if (total_toys == 1) {
        ans1 = "Tidak"; ans2 = "Tidak"; ans3 = "Tidak"; ans4 = "Tidak";
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

