#include <numeric>
#include <algorithm>

// Function to check if a subarray is a permutation of its length
// This function is not strictly needed if we precompute prefix/suffix permutation properties.
// For completeness, a direct check would involve a frequency array or a set.
// However, the optimized approach below avoids repeated checks.

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix permutation properties
    // is_prefix_perm[i] is true if a[0...i-1] is a permutation of length i
    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_prefix = 0;
    bool distinct_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > i + 1 || seen_prefix[a[i]]) {
            distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        max_prefix = std::max(max_prefix, a[i]);
        if (distinct_prefix && max_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Precompute suffix permutation properties
    // is_suffix_perm[i] is true if a[i...n-1] is a permutation of length n-i
    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix = 0;
    bool distinct_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] > current_len || seen_suffix[a[i]]) {
            distinct_suffix = false;
        }
        seen_suffix[a[i]] = true;
        max_suffix = std::max(max_suffix, a[i]);
        if (distinct_suffix && max_suffix == current_len) {
            is_suffix_perm[i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can be from 1 to n-1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

