#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1) { // N/2 is odd
                    // If N/2 is odd, taking N/2 leaves an odd number for opponent.
                    // Opponent will take 1, leaving an even number for Chanek.
                    // This seems good.
                    // What if Chanek takes 1? N-1 is odd. Opponent takes 1. N-2 is even.
                    // This is a greedy approach.
                    // If N/2 is odd, taking N/2 is better than taking 1.
                    // Example: N=6. N/2=3 (odd). Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 3+1=4. Opponent: 1+1=2.
                    // If Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                    // Chanek: 1+2+1=4. Opponent: 1+1=2.
                    // Both give 4.
                    // Example: N=10. N/2=5 (odd). Chanek takes 5. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                    // Chanek: 5+2+1=8. Opponent: 1+1=2.
                    // If Chanek takes 1. N=9. Opponent takes 1. N=8. Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 1+4+1=6. Opponent: 1+2+1=4.
                    // Taking N/2 is better.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    // If N/2 is even, taking N/2 leaves an even number for opponent.
                    // Opponent can then take half, which might be bad for Chanek.
                    // Example: N=4. N/2=2 (even).
                    // If Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                    // Chanek: 2+1=3. Opponent: 1.
                    // If Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 1+1=2. Opponent: 1+1=2.
                    // In this case, taking N/2 is better.
                    //
                    // Example: N=8. N/2=4 (even).
                    // If Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 4+1=5. Opponent: 2+1=3.
                    // If Chanek takes 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                    // Both give 5.
                    //
                    // It seems taking 1 is always safe if N/2 is even.
                    // The logic is: if N/2 is even, taking N/2 leaves an even number for the opponent.
                    // The opponent can then take half, which might be a large amount.
                    // If Chanek takes 1, N-1 is odd. The opponent must take 1. N-2 is even.
                    // This guarantees Chanek gets to play on an even number again, but smaller.
                    // This strategy seems to be "take 1 if N/2 is even, otherwise take N/2".
                    // This is equivalent to taking 1 if N is a power of 2 (except N=2).
                    // If N is a power of 2 (N=2^k, k>1), then N/2 is also a power of 2 (2^(k-1)).
                    // If N is not a power of 2, but even, then N = 2^k * M where M is odd and M > 1.
                    // N/2 = 2^(k-1) * M. If k-1 > 0, N/2 is even. If k-1 = 0, N/2 = M is odd.
                    // So, if N/2 is odd, it means N = 2 * M where M is odd. Chanek takes M.
                    // If N/2 is even, it means N = 2^k * M where M is odd and k > 1.
                    // In this case, Chanek takes 1.
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    n -= 1;
                } else if ((n / 2) % 2 == 1) { // N/2 is odd
                    n /= 2; // Opponent takes N/2
                } else { // N/2 is even
                    n -= 1; // Opponent takes 1
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

