    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually move past this 'b'.
            // Each such 'a' will contribute 'count_a' steps to move past this 'b'.
            // The 'b' itself will also be duplicated 'count_a' times.
            // So, the total steps for this 'b' is 'count_a'.
            // After this 'b' is processed, it effectively doubles the number of 'a's
            // that are "active" for future 'b's to its left.
            // This is because each 'a' to its left will now have to pass this 'b'
            // AND the new 'b' that is created when 'ab' -> 'bba'.
            // So, count_a effectively doubles for the next iteration.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are waiting to be processed by 'b's to their left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

