int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right side

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // The sum of weights for items w_n, w_{n-1}, ..., w_{n-j+1}
        // is prefix_sum[n] - prefix_sum[n-j]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add extra energy for consecutive actions
        if (i > j) { // More items taken from left than right
            // The last item taken must have been from the left.
            // The difference is (i - j).
            // If i = j+1, then 1 extra left item. No penalty.
            // If i = j+2, then 2 extra left items. 1 penalty.
            // The number of extra left items that incur penalty is (i - j - 1).
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items taken from right than left
            // The last item taken must have been from the right.
            // The difference is (j - i).
            // If j = i+1, then 1 extra right item. No penalty.
            // If j = i+2, then 2 extra right items. 1 penalty.
            // The number of extra right items that incur penalty is (j - i - 1).
            current_energy += (j - i - 1) * Qr;
        }
        // If i == j, no extra penalty from this rule.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

