// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern_str;
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with leading zeros to length 18
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    // The pattern is built from right to left, so it's already in the correct order for map key
    // e.g., 241 -> 100100000000000000 (1 for 1, 0 for 4, 0 for 2, then 0s)
    // The problem statement implies matching from right to left, and padding from left.
    // So, if we have 241, its digits are 2,4,1. Parities are 0,0,1.
    // The pattern for 241 would be 001.
    // If we reverse the string, it becomes 100.
    // Let's re-evaluate.
    // "parity of the i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
    // For 241, rightmost is 1 (odd), next is 4 (even), next is 2 (even).
    // So the pattern for 241 is ...000000000000000001 (18 digits)
    // The current loop builds it as '1' then '0' then '0'.
    // So pattern_str for 241 would be "100".
    // If we want to store it as "001" (rightmost first), we need to reverse it.
    // No, the map key should be the pattern as described.
    // If s = 010, and x = 92.
    // x = 092.
    // x's parities: 0 (for 0), 1 (for 9), 0 (for 2).
    // So x's pattern is 010.
    // This means the string should be built from left to right, or reversed at the end.
    // Let's rebuild the string from right to left, then reverse it.
    // Example: 241
    // n=241, pattern_str=""
    // n%10=1 (odd) -> pattern_str="1"
    // n=24
    // n%10=4 (even) -> pattern_str="10"
    // n=2
    // n%10=2 (even) -> pattern_str="100"
    // n=0
    // Pad to 18: "100000000000000000"
    // This is the pattern for 241, where the rightmost digit is 1, next is 0, next is 0.
    // This is correct. The map key should be this string.
    // The problem states "parity of the i-th from the right digit ... matches the i-th from the right digit of the pattern."
    // So if pattern is "010", it means rightmost is 0, middle is 1, leftmost is 0.
    // For 92, rightmost is 2 (even), middle is 9 (odd), leftmost is 0 (even).
    // So 92's pattern is "010".
    // My current `to_parity_pattern` for 92:
    // n=92, pattern_str=""
    // n%10=2 (even) -> pattern_str="0"
    // n=9
    // n%10=9 (odd) -> pattern_str="01"
    // n=0
    // Pad to 18: "010000000000000000"
    // This is correct. The string is built from right to left, and then padded.
    // The map key should be this string.
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with leading zeros to length 18
            // The problem states "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // And "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we should effectively compare patterns of fixed length.
            // Since max number is < 10^18, it has at most 18 digits. Max pattern length is 18.
            // So we pad both to 18.
            std::string padded_s = s;
            std::reverse(padded_s.begin(), padded_s.end()); // Reverse to match the to_parity_pattern logic
            while (padded_s.length() < 18) {
                padded_s += '0';
            }
            // The to_parity_pattern function builds the string from right to left.
            // So for a pattern like "010", it means rightmost is 0, middle is 1, leftmost is 0.
            // If we read "010" from input, we want to match it against "010" in the map.
            // The `to_parity_pattern` for 92 (which matches "010") produces "01" then pads to "01000...".
            // So the input pattern "010" should be stored as "01000...".
            // The current `padded_s` logic:
            // s = "010"
            // reverse(s) -> "010"
            // pad -> "01000..."
            // This is correct.
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    // If temp_q is still greater than 1, it means temp_q itself is a prime factor
    if (temp_q > 1) {
        long long current_p = p;
        while (current_p % temp_q == 0) {
            current_p /= temp_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

