int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_val = std::min({count_x, count_y, count_z});
        int max_val = std::max({count_x, count_y, count_z});

        if (max_val - min_val <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit
        std::vector<int> colors(n);
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                colors[i] = 1;
                s1_digits.push_back(d[i]);
            } else if (d[i] > p) {
                colors[i] = 2;
                s2_digits.push_back(d[i]);
            } else { // d[i] == p
                // Try to assign to color 2 first if possible, to keep s1_digits sorted
                // If s2_digits is empty or d[i] >= last_s2_digit, assign to 2
                if (s2_digits.empty() || d[i] >= s2_digits.back()) {
                    colors[i] = 2;
                    s2_digits.push_back(d[i]);
                } else { // Must assign to color 1
                    colors[i] = 1;
                    s1_digits.push_back(d[i]);
                }
            }
        }

        // Check if s1_digits is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if s2_digits is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if last s1_digit <= first s2_digit
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_p = false;
            }
        }
        if (!possible_p) continue;

        // If all checks pass, we found a valid coloring
        for (int i = 0; i < n; ++i) {
            std::cout << colors[i];
        }
        std::cout << "\n";
        return;
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

