int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1 means can move left (x-1). If f1=0, cannot move left.
            // So, target X must be >= current x.
            if (f1 == 0) { // Cannot move left
                min_x = std::max(min_x, x);
            }
            // f3 = 1 means can move right (x+1). If f3=0, cannot move right.
            // So, target X must be <= current x.
            if (f3 == 0) { // Cannot move right
                max_x = std::min(max_x, x);
            }
            // f4 = 1 means can move down (y-1). If f4=0, cannot move down.
            // So, target Y must be >= current y.
            if (f4 == 0) { // Cannot move down
                min_y = std::max(min_y, y);
            }
            // f2 = 1 means can move up (y+1). If f2=0, cannot move up.
            // So, target Y must be <= current y.
            if (f2 == 0) { // Cannot move up
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r;
    if (b == 1) { // If b=1, then b-1=0, sum is 0.
        sum_r = 0;
    } else {
        sum_r = (b - 1);
        sum_r = (sum_r * b) % MOD;
        // Multiply by modular inverse of 2
        // Modular inverse of 2 modulo 10^9+7 is (10^9+8)/2 = 500000004
        sum_r = (sum_r * 500000004) % MOD;
    }

    // Calculate sum_kb_plus_1 = sum_{k=1 to a} (k * b + 1)
    // This is (sum_{k=1 to a} k*b) + (sum_{k=1 to a} 1)
    // = b * (sum_{k=1 to a} k) + a
    // = b * (a * (a+1) / 2) + a
    long long sum_k = (a % MOD);
    sum_k = (sum_k * ((a + 1) % MOD)) % MOD;
    // Multiply by modular inverse of 2
    sum_k = (sum_k * 500000004) % MOD;

    long long sum_kb_plus_1 = (b % MOD);
    sum_kb_plus_1 = (sum_kb_plus_1 * sum_k) % MOD;
    sum_kb_plus_1 = (sum_kb_plus_1 + (a % MOD)) % MOD;

    // Total sum = sum_r * sum_kb_plus_1
    long long total_sum = (sum_r * sum_kb_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <numeric>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i - 1]);
            adj[s[i - 1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find a starting point for a chain: a character with only one neighbor in the password graph
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If all characters in s have 2 neighbors (i.e., form a cycle), pick any character from s as start
    if (start_char == '\0' && !used_in_s.empty()) {
        start_char = *used_in_s.begin();
    }

    // Build the layout chain
    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the first character

        while (visited_in_layout.find(current) == visited_in_layout.end()) {
            layout_str += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
            if (current == '\0') break; // End of chain
        }
    }

    // Check if all characters from s are included in the built chain
    if (layout_str.length() != used_in_s.size()) {
        std::cout << "NO\n"; // This means there's a cycle or multiple disconnected components in the password graph
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct Element {
    long long val;
    int original_idx;
};

bool compareElements(const Element& a, const Element& b) {
    return a.val < b.val;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].val;
        a_elements[i].original_idx = i;
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b.rbegin(), b.rend());

    // Create pairs (A_i, B_j) such that A_i is sorted ascending and B_j is sorted descending.
    // This maximizes F(A_i, B_j) for each pair.
    // The problem states A_i >= B_j for all i, j.
    // F(n, k) = (n+1) / (k+1).
    // We want to maximize sum (A_i' + 1) / (B_i + 1).
    // Let x_i = A_i' + 1 and y_i = B_i + 1. We want to maximize sum x_i / y_i.
    // If we have x_1 < x_2 and y_1 < y_2, then x_1/y_1 + x_2/y_2 vs x_1/y_2 + x_2/y_1.
    // (x_1 y_2 + x_2 y_1) / (y_1 y_2) vs (x_1 y_1 + x_2 y_2) / (y_1 y_2)
    // x_1 y_2 + x_2 y_1 vs x_1 y_1 + x_2 y_2
    // x_1 y_2 - x_1 y_1 vs x_2 y_2 - x_2 y_1
    // x_1 (y_2 - y_1) vs x_2 (y_2 - y_1)
    // Since y_2 > y_1, y_2 - y_1 > 0.
    // x_1 vs x_2. Since x_1 < x_2, we have x_1 (y_2 - y_1) < x_2 (y_2 - y_1).
    // So x_1 y_2 + x_2 y_1 < x_1 y_1 + x_2 y_2.
    // This means (x_1/y_1 + x_2/y_2) > (x_1/y_2 + x_2/y_1).
    // To maximize sum x_i/y_i, we should pair smallest x_i with smallest y_i, second smallest x_i with second smallest y_i, etc.
    // Or, smallest x_i with largest y_i, second smallest x_i with second largest y_i, etc.
    // The proof above shows that if x_i are sorted ascending and y_i are sorted ascending, then sum x_i/y_i is maximized.
    // If x_i are sorted ascending and y_i are sorted descending, then sum x_i/y_i is minimized.
    //
    // Wait, the problem is to maximize sum F(A_i', B_i).
    // F(n, k) = (n+1)/(k+1).
    // We want to maximize sum (A_i' + 1) / (B_i + 1).
    // Let X_i = A_i' + 1 and Y_i = B_i + 1.
    // We have a set of X values (derived from A) and a set of Y values (derived from B).
    // We want to pair them up to maximize sum X_i / Y_i.
    // Let X_1 <= X_2 <= ... <= X_m be the sorted values from A.
    // Let Y_1 <= Y_2 <= ... <= Y_m be the sorted values from B.
    // The rearrangement inequality states that to maximize sum X_i / Y_i, we should pair X_i with Y_i such that both are sorted in the same order.
    // So, X_1 with Y_1, X_2 with Y_2, ..., X_m with Y_m.
    // This means A_i' should be sorted ascending, and B_i should be sorted ascending.
    //
    // The problem asks to rearrange A. B is fixed.
    // So we have A_1, ..., A_m and B_1, ..., B_m.
    // We sort A to get A'_1 <= A'_2 <= ... <= A'_m.
    // We sort B to get B'_1 <= B'_2 <= ... <= B'_m.
    // The optimal pairing is A'_i with B'_i.
    // However, we cannot rearrange B. We must use the original B values.
    //
    // Let's re-evaluate. We have a fixed array B. We have a set of values {A_1, ..., A_m} to assign to A'_1, ..., A'_m.
    // We want to maximize sum_{i=1 to m} (A'_i + 1) / (B_i + 1).
    // Let C_i = B_i + 1. These are fixed.
    // We want to maximize sum_{i=1 to m} (A'_i + 1) / C_i.
    // Let X_j be the sorted values of A (X_1 <= X_2 <= ... <= X_m).
    // Let C_i be the values of B_i + 1.
    // We need to assign X_j to A'_i such that sum (X_j + 1) / C_i is maximized.
    // This is a standard rearrangement inequality application.
    // To maximize sum (X_j / C_i), we should pair the largest X_j with the smallest C_i,
    // the second largest X_j with the second smallest C_i, and so on.
    // Or, equivalently, pair the smallest X_j with the largest C_i,
    // the second smallest X_j with the second largest C_i, and so on.
    //
    // So, sort A in ascending order: A_sorted[0], A_sorted[1], ..., A_sorted[m-1].
    // Sort B in descending order: B_sorted_desc[0], B_sorted_desc[1], ..., B_sorted_desc[m-1].
    // The optimal assignment is A'_i = A_sorted[i] and B_i = B_sorted_desc[i].
    // This means we pair A_sorted[j] with B_sorted_desc[j].
    //
    // The problem is that B is not rearranged. We need to output A' such that A'_i is paired with B_i (original B_i).
    // So, we need to find a permutation P of {0, ..., m-1} such that
    // sum_{i=0 to m-1} F(A_sorted[P[i]], B_i) is maximized.
    // This is equivalent to maximizing sum_{i=0 to m-1} (A_sorted[P[i]] + 1) / (B_i + 1).
    // Let X_j = A_sorted[j] + 1.
    // Let Y_i = B_i + 1.
    // We want to maximize sum_{i=0 to m-1} X_{P[i]} / Y_i.
    // To maximize this sum, we should pair the largest X_j with the smallest Y_i,
    // the second largest X_j with the second smallest Y_i, and so on.
    //
    // So, we need to:
    // 1. Store original indices of A elements. Sort A elements by value (ascending).
    //    Let this sorted array be `a_sorted_elements`.
    // 2. Store original indices of B elements. Sort B elements by value (ascending).
    //    Let this sorted array be `b_sorted_elements`.
    //    (Or, more simply, create pairs (B_i+1, original_index_B_i) and sort them ascending).
    //
    // Let `a_sorted_elements` be `(A_val, A_orig_idx)` pairs, sorted by `A_val` ascending.
    // Let `b_indexed` be `(B_val, B_orig_idx)` pairs.
    // We need to assign `a_sorted_elements[j].val` to `ans[b_indexed[i].original_idx]`.
    //
    // To maximize sum (A'_k + 1) / (B_k + 1):
    // We have values A_val_0 <= A_val_1 <= ... <= A_val_{m-1} (these are from sorted A).
    // We have values B_val_0, B_val_1, ..., B_val_{m-1} (these are from original B).
    // We want to assign A_val_j to A'_k such that sum (A'_k + 1) / (B_k + 1) is maximized.
    // This means we should pair A_val_j with B_k such that (A_val_j + 1) and (B_k + 1) are sorted in opposite orders.
    // So, A_val_0 should be paired with the B_k that has the largest (B_k + 1).
    // A_val_1 should be paired with the B_k that has the second largest (B_k + 1), etc.
    //
    // Algorithm:
    // 1. Create a vector of pairs for B: `std::vector<std::pair<long long, int>> b_indexed(m);`
    //    For `i = 0 to m-1`, `b_indexed[i] = {b[i], i};`
    // 2. Sort `a_elements` by `val` in ascending order.
    // 3. Sort `b_indexed` by `val` in ascending order.
    //    Now `a_elements[j].val` is the j-th smallest A value.
    //    And `b_indexed[j].val` is the j-th smallest B value, and `b_indexed[j].second` is its original index.
    // 4. Create the result array `ans` of size `m`.
    // 5. To maximize sum (A'_k + 1) / (B_k + 1), we pair the smallest A value with the largest B value (from the sorted B_indexed list),
    //    the second smallest A value with the second largest B value, and so on.
    //    So, `a_elements[j].val` (j-th smallest A value) should be assigned to the position `b_indexed[m-1-j].second` (original index of (m-1-j)-th smallest B value, which is j-th largest B value).
    //    `ans[b_indexed[m-1-j].original_idx] = a_elements[j].val;`
    //
    // Example:
    // A = [7, 3, 5, 3, 4], m=5
