// Z-algorithm implementation
std::vector<int> calculate_z_function(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    for (int i = 1, l = 0, r = 0; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-arrays for all cyclic shifts of s
    // z_arrays[i] stores the Z-function for s[i..L-1] + s[0..i-1]
    std::vector<std::vector<int>> z_arrays(L);
    for (int i = 0; i < L; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        z_arrays[i] = calculate_z_function(shifted_s);
    }

    // Group indices by character s[k]
    std::vector<std::vector<int>> indices_by_char(26);
    for (int i = 0; i < L; ++i) {
        indices_by_char[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    // Iterate over each possible first character c_0
    for (int char_code = 0; char_code < 26; ++char_code) {
        const std::vector<int>& S0 = indices_by_char[char_code];
        if (S0.empty()) {
            continue;
        }

        // If only one k matches c_0, Vasya wins for sure.
        if (S0.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // Otherwise, Vasya needs to choose an optimal p.
        // Maximize win probability for this c_0.
        double max_win_prob_for_c0 = 0.0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            // For a fixed p, count how many k's in S0 lead to a unique determination.
            int unique_count = 0;
            for (int k_idx = 0; k_idx < S0.size(); ++k_idx) {
                int k_true = S0[k_idx]; // The actual k chosen by Kolya
                char c_p = s[(p + k_true) % L]; // The character t[p] Vasya would see

                // Check if k_true is uniquely determined by (c_0, c_p)
                bool is_unique = true;
                for (int k_other_idx = 0; k_other_idx < S0.size(); ++k_other_idx) {
                    if (k_idx == k_other_idx) continue;
                    int k_other = S0[k_other_idx];

                    // If another k_other also produces c_p at position p,
                    // then k_true is not unique.
                    if (s[(p + k_other) % L] == c_p) {
                        is_unique = false;
                        break;
                    }
                }
                if (is_unique) {
                    unique_count++;
                }
            }
            max_win_prob_for_c0 = std::max(max_win_prob_for_c0, (double)unique_count / S0.size());
        }
        total_win_prob += max_win_prob_for_c0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

