#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[j] = A_j + S_j_final
                                          // Initialize with a very large value, as b[j] <= m_i
                                          // for all type 2 operations covering j.

    // First pass: Determine upper bounds for b[j]
    // For each type 2 operation (l, r, m), we know that for all j in [l, r], A_j + S_j_final <= m.
    // This means b[j] <= m.
    // We need to consider the S_j_final values.
    // Let's define b_j = A_j.
    // When a type 1 op (l, r, d) occurs, it adds d to A_j for j in [l, r].
    // When a type 2 op (l, r, m) occurs, it means max_{j=l..r} (A_j + current_sum_on_j) = m.
    // This is tricky because current_sum_on_j depends on previous type 1 ops.

    // Let's rephrase: we are looking for an initial array `a_init`.
    // Let `a_init[j]` be the initial value of element `j`.
    // For each element `j`, let `delta[j]` be the sum of all `d_i` from type 1 operations
    // that cover index `j` and occur *before* the current operation.
    // When a type 2 operation `(l, r, m)` occurs, it means:
    // `max_{k=l..r} (a_init[k] + delta[k]) = m`.
    // This implies `a_init[k] + delta[k] <= m` for all `k` in `[l, r]`.

    // Let `a_final[j]` be the value of `a_init[j]` plus the sum of all `d_i` from type 1 operations
    // that cover index `j` *up to the point of the type 2 query*.
    // This is still not quite right. The problem asks for *an* initial array.
    // Let's define `a_init[j]` as the initial array.
    // We want to find `a_init[j]` such that `|a_init[j]| <= 10^9`.

    // Let `a_final[j]` be the value of `a_init[j]` after all type 1 operations have been applied.
    // This is `a_init[j] + sum_of_all_d_i_for_j`.
    // This is not what we need. The `delta` values are cumulative.

    // Let `a_base[j]` be the initial value of `a[j]`.
    // For each type 2 query `(l, r, m)`, we know that `max_{k=l..r} (a_base[k] + current_delta[k]) = m`.
    // This implies `a_base[k] + current_delta[k] <= m` for all `k` in `[l, r]`.
    // Let `b[k] = a_base[k]`.
    // We need to find `b[k]` values.

    // Let's define `a_val[j]` as the value of `a[j]` *just before* the first operation.
    // This is the array we need to find.
    // Let `diff[j]` be the total sum of `d_i` for all type 1 operations that cover index `j`.
    // Then, for any type 2 operation `(l, r, m)`, the condition is:
    // `max_{k=l..r} (a_val[k] + (sum of d_i for k up to this point)) = m`.

    // This is a standard approach for this type of problem:
    // 1. Initialize `a_val[j]` to some value (e.g., 0).
    // 2. For each type 2 query `(l, r, m)`, we know that `a_val[k] + current_delta[k] <= m` for `k` in `[l, r]`.
    //    This gives an upper bound for `a_val[k]`.
    //    Let `a_val[k] = m - current_delta[k]`. This is a candidate value.
    //    Since `a_val[k]` must be less than or equal to `m - current_delta[k]` for *all* such queries,
    //    we take the minimum of these `m - current_delta[k]` values.
    //    So, `a_val[k] = min(a_val[k], m - current_delta[k])`.
    //    Initialize `a_val[k]` to a very large value.

    std::vector<long long> a_val(n, 2000000000LL); // Initialize with a value larger than 10^9
                                                  // Max possible m_i is 5*10^7. Max d_i is 10^4.
                                                  // Max number of ops is 5000.
                                                  // So current_delta can be up to 5000 * 10^4 = 5*10^7.
                                                  // So m - current_delta can be 5*10^7 - (-5*10^7) = 10^8.
                                                  // Or -5*10^7 - (5*10^7) = -10^8.
                                                  // So 2*10^9 is a safe initial upper bound.

    std::vector<long long> current_delta(n, 0); // current_delta[j] stores sum of d_i for type 1 ops covering j
                                                // up to the current point in the first pass.

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // type 2
            for (int j = op.l; j <= op.r; ++j) {
                a_val[j] = std::min(a_val[j], op.val - current_delta[j]);
            }
        }
    }

    // After the first pass, a_val[j] holds the maximum possible initial value for a[j]
    // such that all type 2 conditions `a_init[k] + current_delta[k] <= m` are met.
    // We can choose these `a_val[j]` as our candidate initial array.
    // Let's verify if this candidate array works.

    // Second pass: Verify the candidate array
    std::vector<long long> test_array(n);
    for (int j = 0; j < n; ++j) {
        test_array[j] = a_val[j];
    }

    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta for verification

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val_in_range = std::max(max_val_in_range, test_array[j] + current_delta[j]);
            }
            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the array
    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << a_val[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
