    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k < abs_n (not enough moves to reach the furthest coordinate)
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= abs_n
        // We can always reach (abs_n, abs_m) in abs_n moves using abs_m diagonal moves
        // and (abs_n - abs_m) axial moves.
        // The remaining k - abs_n moves must be used to return to (abs_n, abs_m).
        // Each pair of moves (e.g., (1,0) then (-1,0)) effectively uses 2 moves
        // and changes the parity of the sum of coordinates by 0.
        // Each pair of moves (e.g., (1,1) then (-1,-1)) effectively uses 2 moves
        // and changes the parity of the sum of coordinates by 0.
        //
        // The parity of (x+y) changes with each move.
        // (x1, y1) -> (x2, y2)
        // (x2+y2) - (x1+y1) = (x2-x1) + (y2-y1)
        // (x2-x1) is -1, 0, or 1. (y2-y1) is -1, 0, or 1.
        // The sum (x2-x1) + (y2-y1) can be -2, -1, 0, 1, 2.
        // It cannot be 0 if it's a move.
        // If it's a diagonal move, (x2-x1) and (y2-y1) are both non-zero.
        //   e.g., (1,1) -> sum change is 2. (1,-1) -> sum change is 0.
        //   This is not correct. (x2-x1) + (y2-y1) is the change in sum.
        //   A move changes x by dx, y by dy.
        //   (x+y) changes by (dx+dy).
        //   dx, dy are in {-1, 0, 1}. Not both 0.
        //   dx+dy can be -2, -1, 0, 1, 2.
        //   If dx+dy is even, (x+y) parity doesn't change.
        //   If dx+dy is odd, (x+y) parity changes.
        //   Moves like (1,0), (-1,0), (0,1), (0,-1) have dx+dy = +/-1. Parity changes.
        //   Moves like (1,1), (-1,-1) have dx+dy = +/-2. Parity doesn't change.
        //   Moves like (1,-1), (-1,1) have dx+dy = 0. Parity doesn't change.
        //
        // This parity argument is tricky. A simpler one:
        // Each move changes the parity of x or y or both.
        // If x changes, x_parity flips. If y changes, y_parity flips.
        //
        // Consider the parity of (abs_n + abs_m) and k.
        // Each move changes the parity of (x+y).
        // So, after k moves, the parity of (final_x + final_y) must be the same as the parity of (initial_x + initial_y + k).
        // Initial: (0,0). So (0+0) = 0.
        // Final: (abs_n, abs_m).
        // So, (abs_n + abs_m) must have the same parity as k.
