        if ((k - abs_n) % 2 != (abs_m - abs_n) % 2) { // (k - abs_n) and (abs_m - abs_n) must have same parity
                                                      // This is equivalent to (k - abs_n - (abs_m - abs_n)) % 2 == 0
                                                      // which simplifies to (k - abs_m) % 2 == 0
