                                                      //
                                                      // The key insight is that each move changes the parity of the sum of coordinates (x+y) if and only if it's an axial move.
                                                      // (x_final + y_final) % 2 == (x_initial + y_initial + (number of axial moves)) % 2
                                                      // (abs_n + abs_m) % 2 == (0 + 0 + a) % 2
                                                      // (abs_n + abs_m) % 2 == a % 2
                                                      // Since k = d + a, then a = k - d.
                                                      // (abs_n + abs_m) % 2 == (k - d) % 2
                                                      //
                                                      // We want to maximize `d`.
