// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of a
    int current_parity_a = calculate_parity(a);

    // Calculate parity of b
    int parity_b = calculate_parity(b);

    // The length of string a can only increase or decrease.
    // If we want to transform a into b, b must be a suffix of some
    // string a' that is formed by appending parities to the original a.
    // The length of a' can be at most |a| + (|b| - |a|) = |b|.
    // If |a| < |b|, we must append |b| - |a| parities to a.
    // If |a| >= |b|, we don't need to append any parities to reach length |b|.
    // However, we might need to append parities to change the final parity.
    // The maximum length of a string we need to consider is |b|.
    // If we append more parities, the string gets longer than |b|,
    // and we would have to remove characters from the front, which means
    // b would be a suffix of a string of length > |b|.
    // But we can always just append exactly enough parities to make the string
    // length |b|, and then check its suffix.
    // The maximum length of a string we need to consider is |b|.
    // If |a| < |b|, we must append |b| - |a| characters.
    // If |a| >= |b|, we don't need to append any characters to reach length |b|.
    // The maximum number of '1's in a string of length 1000 is 1000.
    // The maximum number of '1's in a string of length 1000 + 1000 = 2000 is 2000.
    // The parity of a string of length L is `sum of '1's % 2`.
    // When we append a parity bit, the new string `s'` has length `L+1`.
    // The number of '1's in `s'` is `ones_s + parity_s`.
    // The parity of `s'` is `(ones_s + parity_s) % 2`.
    // If `parity_s` is 0, `parity_s'` is `ones_s % 2 = parity_s`.
    // If `parity_s` is 1, `parity_s'` is `(ones_s + 1) % 2 = (parity_s + 1) % 2`.
    // So, `new_parity = (old_parity + appended_bit) % 2`.
    // This means the parity of the string `a` can change from `P` to `(P+1)%2` if we append a '1',
    // or stay `P` if we append a '0'.
    // The parity of the string `a` can always be flipped by appending a '1' (if `a` has odd '1's, append '0', if even '1's, append '1').
    // No, this is wrong. The appended bit is `parity(a)`.
    // If `parity(a)` is 0, we append '0'. The number of '1's doesn't change. The parity of the new string is still 0.
    // If `parity(a)` is 1, we append '1'. The number of '1's increases by 1. The parity of the new string becomes 0.
    // So, after the first append operation, the parity of the string becomes 0.
    // And it stays 0 for all subsequent appends.
    // Example: "01011" (parity 1) -> "010111" (parity 0) -> "0101110" (parity 0) -> "01011100" (parity 0) ...
    // This means that any string `a'` formed by `a` and one or more appended parity bits will have parity 0.
    // The only exception is the original `a` itself, if its parity is 1.
    // And `a` with 0 appended, if `parity(a)` is 0.

    // Case 1: The original string 'a' can be transformed into 'b' by only removing prefix characters.
    // This means 'b' is a suffix of 'a'.
    if (a.length() >= b.length()) {
        if (a.substr(a.length() - b.length()) == b) {
            std::cout << "YES\n";
            return 0;
        }
    }

    // Case 2: We need to append parity bits to 'a'.
    // If we append at least one parity bit, the string 'a' becomes 'a + parity(a)'.
    // Let's call this new string `a_prime`.
    // If `parity(a)` was 0, `a_prime` has `parity(a_prime) = 0`.
    // If `parity(a)` was 1, `a_prime` has `parity(a_prime) = 0`.
    // So, any string formed by `a` and at least one appended parity bit will have parity 0.
    // And any further appended bits will also be '0', maintaining the parity of 0.
    // This means if we need to append any bits, the final string `a_final` (before removing prefix)
    // will have parity 0.
    // Therefore, if `b` is to be a suffix of such an `a_final`, `b` must have parity 0.
    // If `parity_b` is 1, and we need to append bits, it's impossible.
    // The only way `b` can have parity 1 is if `b` is a suffix of the original `a` (checked above),
    // or if `b` is a suffix of `a` after appending exactly one '1' (which happens if `parity(a)` was 1).
    // But if `parity(a)` was 1, appending '1' makes the new string have parity 0.
    // So, if `parity_b` is 1, the only possibility is that `b` is a suffix of the original `a`.
    // We already checked that.

    // So, if `parity_b` is 1, and `b` was not a suffix of `a`, then it's impossible.
    if (parity_b == 1) {
        std::cout << "NO\n";
        return 0;
    }

    // Now we know `parity_b` is 0.
    // We need to check if `b` can be a suffix of `a` after appending some '0's.
    // The number of '1's in `a` is `current_parity_a` (modulo 2).
    // If `current_parity_a` is 1, we can append a '1' to `a`.
    // The new string `a_new` will have `current_parity_a + 1` ones (if `current_parity_a` was 1)
    // or `current_parity_a` ones (if `current_parity_a` was 0).
    // The parity of `a_new` will be 0 in both cases.
    // After this, all subsequent appended bits will be '0'.
    // So, we can effectively extend `a` with `current_parity_a` (as a char) followed by as many '0's as needed.
    // The maximum length of the string we need to consider is `b.length()`.
    // We can form a string `a_extended` by taking `a`, appending `current_parity_a` (as char '0' or '1'),
    // and then appending enough '0's until its length is `b.length()`.
    // The number of '1's in `a_extended` will be `ones_in_a + current_parity_a`.
    // The parity of `a_extended` will be 0.
    // We need to check if `b` is a suffix of `a_extended`.

    // Let's count the number of '1's in `a`.
    int ones_in_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a++;
        }
    }

    // The maximum number of '1's we can have in the extended string `a_ext`
    // (which `b` must be a suffix of) is `ones_in_a` if `parity(a)` is 0,
    // or `ones_in_a + 1` if `parity(a)` is 1.
    // This is because if `parity(a)` is 0, we append '0', `ones_in_a` remains `ones_in_a`.
    // If `parity(a)` is 1, we append '1', `ones_in_a` becomes `ones_in_a + 1`.
    // After this first (or zero-th) append, the parity of the string becomes 0,
    // and all subsequent appends will be '0', not changing the count of '1's.
    int max_ones_in_a_prefix = ones_in_a + current_parity_a;

    // Now, `b` must be a suffix of some string `a_prefix` which has at most `max_ones_in_a_prefix` ones.
    // The length of `a_prefix` can be anything from `a.length()` up to `b.length()`.
    // If `b` is a suffix of `a_prefix`, then `b` itself must have at most `max_ones_in_a_prefix` ones.
    // The number of '1's in `b` is `ones_in_b`.
    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // If `ones_in_b` is greater than `max_ones_in_a_prefix`, it's impossible.
    // This is because `b` would need more '1's than can be generated from `a`
    // by appending at most one '1' and then only '0's.
    if (ones_in_b <= max_ones_in_a_prefix) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

