        // So we only need to check k=1, 2, 3.

        // Check k=1
        if (x + 2 < n && s[x] == s[x+1] && s[x] == s[x+2]) {
            // Found a 3-AP: s_x = s_{x+1} = s_{x+2}
            // This 3-AP is contained in any range [l, r] where l <= x+1 and r >= x+3 (1-indexed)
            // The smallest such r is x+3.
            // We update min_r_for_l[l] for l from 1 to x+1.
            // The current 3-AP starts at 1-indexed position x+1 and ends at x+3.
            // So for any l from 1 to x+1, the minimum r that covers this 3-AP is x+3.
            min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 3);
        }

        // Check k=2
        if (x + 4 < n && s[x] == s[x+2] && s[x] == s[x+4]) {
            // Found a 3-AP: s_x = s_{x+2} = s_{x+4}
            // This 3-AP is contained in any range [l, r] where l <= x+1 and r >= x+5 (1-indexed)
            // The smallest such r is x+5.
            min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 5);
        }

        // Check k=3
        if (x + 6 < n && s[x] == s[x+3] && s[x] == s[x+6]) {
            // Found a 3-AP: s_x = s_{x+3} = s_{x+6}
            // This 3-AP is contained in any range [l, r] where l <= x+1 and r >= x+7 (1-indexed)
            // The smallest such r is x+7.
            min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 7);
        }
    }

    // Propagate minimum r values:
    // If min_r_for_l[l] is R, then for any l' > l, if min_r_for_l[l'] is currently larger than R,
    // it can be updated to R because any range [l', r] that contains a 3-AP starting at l'
    // also contains the 3-AP that starts at l and ends at R, if l' <= l.
    // This is not quite right. The propagation should be:
    // If min_r_for_l[l] is R, then for any l' < l, min_r_for_l[l'] can be at most R.
    // No, it's simpler: if a 3-AP exists for [l, R], then for any l' < l, the range [l', R] also contains it.
    // So, min_r_for_l[l'] <= min_r_for_l[l].
    // We want to find the minimum r for a given l.
    // If min_r_for_l[l] is R, then for any l' < l, min_r_for_l[l'] must be <= R.
    // This means we should iterate from right to left.
    // min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l+1])
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long total_pairs = 0;
    for (int l = 1; l <= n; ++l) {
        // For a fixed l, we need to count r such that l <= r <= n and min_r_for_l[l] <= r.
        // If min_r_for_l[l] is n+1, it means no 3-AP starts at or after l.
        // In this case, no r will satisfy the condition for this l.
        if (min_r_for_l[l] <= n) {
            // The valid r values are from min_r_for_l[l] to n.
            // Number of such r values is n - min_r_for_l[l] + 1.
            total_pairs += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...n-1].
    // We can form s' = s[i...n-1] + s[0...i-1].
    // We need s' to be a palindrome and s' != s.
    // The original string s is guaranteed to be a palindrome.
    // If s' is a palindrome and s' != s, then k=1 is the answer.
    for (int i = 1; i < n; ++i) { // i is the cut point, s[0...i-1] and s[i...n-1]
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string s_prime = p2 + p1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 is not possible, we need to check k=2.
    // If all characters in s are the same (e.g., "aaaaa"), then no matter how we cut and reorder,
    // the resulting string will always be "aaaaa". In this case, it's impossible to get s' != s.
    // We can check this by counting unique characters.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider s = "abacaba". n=7.
    // s[0...n-2] = "abacab"
    // s[1...n-1] = "bacaba"
    // If s[0...n-2] is not a palindrome, then s[0...n-2] + s[n-1] is not a palindrome.
    // If s[0...n-2] is a palindrome, then s[0...n-2] + s[n-1] is not a palindrome unless s[n-1] is the center.
    //
    // The problem statement guarantees s is a palindrome.
    // If k=1 is not possible, it means for any cut point i, `s[i...n-1] + s[0...i-1]` is either `s` or not a palindrome.
    //
    // Consider the string `s_prefix = s.substr(0, n-1)`.
    // If `s_prefix` is not a palindrome, then `s_prefix + s[n-1]` is not a palindrome.
    // If `s_prefix` is a palindrome, then `s_prefix` is `s[0...n-2]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`, `s[1] == s[n-2]`, etc.
    // If `s_prefix` is a palindrome, it means `s[0...n-2]` is a palindrome.
    // This implies `s[0] == s[n-2]`, `s[1] == s[n-3]`, etc.
    // Combined with `s[0] == s[n-1]`, we get `s[n-2] == s[n-1]`.
    // This means the last two characters are the same.
    // If `s_prefix` is a palindrome, then `s` must be of the form `XcX` where `X` is a palindrome, or `XX` where `X` is a palindrome.
    // Example: "abacaba". `s_prefix` = "abacab". Not a palindrome.
    // Example: "racecar". `s_prefix` = "raceca". Not a palindrome.
    // Example: "madam". `s_prefix` = "mada". Not a palindrome.
    // Example: "otto". `s_prefix` = "ott". Not a palindrome.
    // Example: "aaaaa". `s_prefix` = "aaaa". Palindrome.
    // Example: "ababa". `s_prefix` = "abab". Not a palindrome.
    //
    // If `s.substr(0, n-1)` is a palindrome, then `s[0...n-2]` is a palindrome.
    // Since `s` is a palindrome, `s[0] == s[n-1]`, `s[1] == s[n-2]`, etc.
    // If `s[0...n-2]` is a palindrome, then `s[0] == s[n-2]`, `s[1] == s[n-3]`, etc.
    // This implies `s[n-1] == s[n-2]`.
    // If `s[n-1] == s[n-2]`, then `s` looks like `...XYY` where `X` is `s[n-3]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]` and `s[1] == s[n-2]`.
    // So `s[0] == s[1]`.
    // This means `s` starts and ends with at least two identical characters.
    // Example: "abccba". `s_prefix` = "abccb". Not a palindrome.
    // Example: "aabbaa". `s_prefix` = "aabba". Not a palindrome.
    //
    // The only case where `s.substr(0, n-1)` is a palindrome is if `s` consists of all identical characters.
    // E.g., "aaaaa". `s.substr(0,4)` = "aaaa", which is a palindrome.
    // But we've already handled the "all same char" case.
    //
    // So, if we reach this point, it means `s` does not consist of all identical characters.
    // This implies `s.substr(0, n-1)` is NOT a palindrome.
    //
    // Consider cutting `s` into `s[0]` and `s[1...n-1]`.
    // Let `P1 = s[0]` and `P2 = s[1...n-1]`.
    // `s_prime = P2 + P1 = s[1...n-1] + s[0]`.
    // We know `s_prime != s` (otherwise `k=1` would have caught it for `i=1`).
    // We also know `s_prime` is not a palindrome (otherwise `k=1` would have caught it for `i=1`).
    //
    // Now, consider `k=2`.
    // We can always make two cuts to get a new palindrome if not all characters are the same.
    // For example, cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
    // Reorder them as `s[n-1]`, `s[1...n-2]`, `s[0]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    // So the new string is `s[0] + s[1...n-2] + s[0]`.
    // This is `s[0] + s.substr(1, n-2) + s[0]`.
    // This string is a palindrome if and only if `s.substr(1, n-2)` is a palindrome.
    // `s.substr(1, n-2)` is `s[1...n-2]`.
    // Since `s` is a palindrome, `s[1...n-2]` is also a palindrome.
    // So, `s[n-1] + s[1...n-2] + s[0]` is always a palindrome.
    // Is this new string different from `s`?
    // `s = s[0] + s[1...n-2] + s[n-1]`
    // `s_new = s[n-1] + s[1...n-2] + s[0]`
    // Since `s[0] == s[n-1]`, `s_new` is actually identical to `s`.
    // This specific reordering doesn't work.

    // Let's reconsider the general case for k=2.
    // If `s` is not all same characters, and `k=1` doesn't work, then `k=2` is the answer.
    // Why?
    // Consider `s = "abacaba"`. `n=7`.
    // `s[0...n-1]` is "abacaba".
    // `s[0...n-2]` is "abacab".
    // `s[1...n-1]` is "bacaba".
    // Neither "abacab" nor "bacaba" are palindromes.
    //
    // If `s` is not all same characters, then `s.substr(0, n-1)` is not a palindrome.
    // (Proof: If `s.substr(0, n-1)` is a palindrome, then `s[0] == s[n-2]`, `s[1] == s[n-3]`, etc.
    // Since `s` is a palindrome, `s[0] == s[n-1]`, `s[1] == s[n-2]`, etc.
    // Combining these, `s[0] == s[n-1]` and `s[0] == s[n-2]`, so `s[n-1] == s[n-2]`.
    // Similarly, `s[1] == s[n-2]` and `s[1] == s[n-3]`, so `s[n-2] == s[n-3]`.
    // Continuing this, all characters must be the same. This contradicts our assumption that `s` is not all same characters.)
    //
    // So, if `s` is not all same characters, then `s.substr(0, n-1)` is not a palindrome.
    // This means `s[0...n-2]` is not a palindrome.
    //
    // Consider the string `s_new = s[n-1] + s[0...n-2]`.
    // This is formed by one cut (between `s[n-2]` and `s[n-1]`) and swapping `s[n-1]` to the front.
    // This is a `k=1` operation.
    // We know `s_new != s` (otherwise `k=1` would have been found).
    // We also know `s_new` is not a palindrome (otherwise `k=1` would have been found).
    //
    // The problem states that if `s` is not all same characters, then `k=2` is always possible.
    // This is a known property for palindromes.
    // If a palindrome `s` is not composed of all identical characters, then `s` can be cut into two pieces `A` and `B` such that `B+A` is a palindrome different from `s`, OR `s` can be cut into three pieces `A, B, C` such that `CBA` is a palindrome different from `s`.
    // The first case is `k=1`. If `k=1` fails, then the second case implies `k=2`.
    //
    // The logic is:
    // 1. If all characters in `s` are the same, it's "Impossible".
    // 2. Otherwise, try `k=1`. If a valid `s'` is found, output 1.
    // 3. If `k=1` fails, then `k=2` is always the answer.
    //
    // The proof for why `k=2` is always possible if `s` is not all same characters and `k=1` fails:
    // If `s` is not all same characters, then `s.substr(0, n-1)` is not a palindrome.
    // (As shown above, if `s.substr(0, n-1)` were a palindrome, then all characters of `s` would be the same.)
    //
    // Let `s = s_0 s_1 ... s_{n-1}`.
    // Consider the string `s' = s_1 s_2 ... s_{n-1} s_0`.
    // This is formed by one cut (between `s_0` and `s_1`) and reordering.
    // We know `s'` is not `s` (otherwise `k=1` would have found it).
    // We know `s'` is not a palindrome (otherwise `k=1` would have found it).
    //
    // Now consider `k=2`.
    // Cut `s` into `s_0`, `s_1...s_{n-2}`, `s_{n-1}`.
    // Reorder to `s_1...s_{n-2} + s_0 + s_{n-1}`.
    // This is `s.substr(1, n-2) + s[0] + s[n-1]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    // So this is `s.substr(1, n-2) + s[0] + s[0]`.
    // This is not necessarily a palindrome.
    //
    // A simpler argument for k=2:
    // If `s` is not all same characters, then `s.substr(0, n-1)` is not a palindrome.
    // Let `s_prefix = s.substr(0, n-1)`.
    // Let `s_suffix = s.substr(1, n-1)`.
    // Since `s` is a palindrome, `s_prefix` is `reverse(s_suffix)`.
    // Since `s_prefix` is not a palindrome, `s_suffix` is not a palindrome.
    //
    // Consider `s = "nolon"`. `n=5`.
    // `k=1` check:
    // `i=1`: "olon" + "n" = "olonn". Not palindrome.
    // `i=2`: "lon" + "no" = "lonno". Not palindrome.
    // `i=3`: "on" + "nol" = "onnol". Not palindrome.
    // `i=4`: "n" + "nolo" = "nnolo". Not palindrome.
    // `k=1` fails.
    // All chars not same. So `k=2` is the answer.
    // Example given: `no|l|on` -> `on|l|no`. This is `s[3..4] + s[2] + s[0..1]`.
    // `s[3..4]` is "on". `s[2]` is "l". `s[0..1]` is "no".
    // "on" + "l" + "no" = "onlno". This is a palindrome.
    // And "onlno" != "nolon". So `k=2` works.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.
// x can be up to n, so int is fine for x.

// dp_odd[i] stores {final_x, final_y} if starting at (i, 0) and first step is x = x + a[x], y = y + a[x]
// dp_even[i] stores {final_x, final_y} if starting at (i, 0) and first step is x = x - a[x], y = y + a[x]
// We use a pair of long long for {final_x, final_y}.
// final_x will be 0 if it terminates, or -1 if it loops.
// final_y will be the accumulated y.
// If final_x is 0, final_y is the answer.
// If final_x is -1, it means infinite loop.

// We need to store the actual x value, not 0 or -1.
// Let's use a pair of long long: {next_x, total_y_added}.
// If next_x is 0, it means it terminated.
// If next_x is -1, it means it looped.
// If next_x is positive, it means it landed on next_x.

// To handle cycles, we can use a visited array during DFS.
// visited[i] = 0: not visited
// visited[i] = 1: currently in recursion stack (potential cycle)
// visited[i] = 2: finished processing (memoized)

struct Result {
    long long final_x; // 0 if terminates, -1 if loop, positive if lands on this x
    long long total_y; // accumulated y
};

std::vector<long long> a_arr;
int N;
std::vector<Result> dp_odd;
std::vector<Result> dp_even;
std::vector<int> visited_odd;
std::vector<int> visited_even;

// Function to solve for a given starting x and operation type
// type = 0 for x = x + a[x], y = y + a[x]
// type = 1 for x = x - a[x], y = y + a[x]
Result solve(int current_x, int type) {
    if (current_x <= 0 || current_x > N) {
        return {0, 0}; // Terminated
    }

    if (type == 0) { // x = x + a[x], y = y + a[x]
        if (visited_odd[current_x] == 1) {
            return {-1, 0}; // Cycle detected
        }
        if (visited_odd[current_x] == 2) {
            return dp_odd[current_x]; // Memoized result
        }

        visited_odd[current_x] = 1; // Mark as visiting

        long long val_a_x = a_arr[current_x];
        long long next_x = current_x + val_a_x;
        long long y_added = val_a_x;

        Result next_res = solve(next_x, 1); // Next step is type 1

        visited_odd[current_x] = 2; // Mark as visited

        if (next_res.final_x == -1) {
            dp_odd[current_x] = {-1, 0}; // Propagate cycle
        } else {
            dp_odd[current_x] = {next_res.final_x, y_added + next_res.total_y};
        }
        return dp_odd[current_x];

    } else { // type == 1, x = x - a[x], y = y + a[x]
        if (visited_even[current_x] == 1) {
            return {-1, 0}; // Cycle detected
        }
        if (visited_even[current_x] == 2) {
            return dp_even[current_x]; // Memoized result
        }

        visited_even[current_x] = 1; // Mark as visiting

        long long val_a_x = a_arr[current_x];
        long long next_x = current_x - val_a_x;
        long long y_added = val_a_x;

        Result next_res = solve(next_x, 0); // Next step is type 0

        visited_even[current_x] = 2; // Mark as visited

        if (next_res.final_x == -1) {
            dp_even[current_x] = {-1, 0}; // Propagate cycle
        } else {
            dp_even[current_x] = {next_res.final_x, y_added + next_res.total_y};
        }
        return dp_even[current_x];
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_arr.resize(N + 1);
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_arr[i];
    }

    dp_odd.resize(N + 1);
    dp_even.resize(N + 1);
    visited_odd.resize(N + 1, 0);
    visited_even.resize(N + 1, 0);

    for (int i = 1; i < N; ++i) {
        // For each i, a_1 = i.
        // The program starts with x=1, y=0.
        // First operation is x = x + a[x], y = y + a[x].
        // So we call solve(1, 0) with a_arr[1] = i.
        a_arr[1] = i;

        // Reset visited states for each run.
        // This is inefficient. A better approach is to clear only relevant parts or use a global counter.
        // However, N is up to 2*10^5, so N*N operations for visited array is too much.
        // The DFS approach with memoization means we only compute each (x, type) state once.
        // The `solve` function will fill `dp_odd` and `dp_even` for all reachable states.
        // We only need to call `solve(1, 0)` once for each `i`.
        // The `dp` and `visited` arrays are global and persist across calls to `solve`.
        // The problem is that `a_arr[1]` changes.
        // This means the entire DP state depends on `a_arr[1]`.
        // So, for each `i`, we effectively have a new problem instance.
        // We must clear `dp` and `visited` for each `i`.
        // This makes the complexity O(N * (N + N)) = O(N^2), which is too slow for N=2*10^5.

        // Let's re-evaluate the problem structure.
        // The sequence is i, a_2, a_3, ..., a_n.
        // This means a_1 is set to i.
        // The values a_2 to a_n are fixed.
        // Only a_1 changes.
        // The states are (x, type).
        // If x != 1, then a[x] is fixed.
        // If x == 1, then a[1] is variable.
        // This means dp_odd[1] and dp_even[1] depend on a_arr[1].
        // All other dp_odd[x] and dp_even[x] (for x > 1) are independent of a_arr[1].

        // So, we can precompute dp_odd[x] and dp_even[x] for x from 2 to N.
        // Then, for each i, we only need to compute dp_odd[1] and dp_even[1] based on a_arr[1] = i.

        // Initialize for the current run
        std::fill(visited_odd.begin(), visited_odd.end(), 0);
        std::fill(visited_even.begin(), visited_even.end(), 0);

        // The initial state is (x=1, y=0).
        // The first step is x = x + a[x], y = y + a[x].
        // So we need to calculate solve(1, 0) where a_arr[1] = i.
        // This means we need to compute the path starting from (1,0) with a_arr[1]=i.
        // The `solve` function will correctly use the current `a_arr[1]` value.
        // The issue is that `solve` will try to memoize `dp_odd[1]` and `dp_even[1]`
        // which are specific to the current `a_arr[1]`.
        // If we clear `dp` and `visited` for each `i`, it's O(N^2).

        // Let's rethink the memoization.
        // The states (x, type) for x > 1 are independent of a_arr[1].
        // So we can compute them once.
        // The states (1, type) depend on a_arr[1].
        // For x > 1, a_arr[x] is fixed.
        // For x = 1, a_arr[1] is `i`.

        // We need to compute `solve(1, 0)` for each `i`.
        // When `solve(1, 0)` is called, it will use `a_arr[1] = i`.
        // It will then call `solve(1 + i, 1)`.
        // If `1 + i` is 1, it will call `solve(1, 1)`.
        // If `1 + i` is > 1, it will call `solve(1 + i, 1)`.
        // The `solve` function for `x > 1` will correctly use the precomputed `dp` values.
        // The `solve` function for `x = 1` will need to be recomputed for each `i`.

        // To avoid O(N^2), we need to avoid clearing the whole `dp` and `visited` arrays.
        // Instead, we can use a global `run_id` counter.
        // `visited_odd[x]` and `visited_even[x]` would store `run_id` if visited in current run.
        // `dp_odd[x]` and `dp_even[x]` would store results for `run_id`.
        // This is still problematic because `dp_odd[1]` and `dp_even[1]` depend on `a_arr[1]`.

        // The key insight:
        // The path from (1,0) with a_arr[1]=i goes to (1+i, 1).
