#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees a solution exists.
    // Reversing the permutation always produces the same set of adjacent sums.
    // If the original permutation is not a palindrome, then the reversed permutation is different.
    // If the original permutation is a palindrome, then reversing it yields the same permutation.
    // However, for n >= 2, a permutation [p_1, p_2, ..., p_n] and its reverse [p_n, ..., p_2, p_1]
    // will have the same set of adjacent sums:
    // {p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n}
    // and
    // {p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1}
    // These two sets are identical.
    // The problem guarantees that a *different* permutation p' exists.
    // This implies that for any given p, p_reversed is either different from p
    // or there is another simple transformation that works.
    // The simplest general solution is to reverse the permutation.
    // The problem statement implies that this will always be different or
    // that if it's not different, some other simple solution exists.
    // For n=2, p=[1,2], p_rev=[2,1]. Different. Works.
    // For n=6, p=[2,1,6,5,4,3], p_rev=[3,4,5,6,1,2]. Different. Works.
    // For n=5, p=[2,4,3,1,5], p_rev=[5,1,3,4,2]. Different. Works.
    // The problem statement guarantees a solution exists.
    // Reversing the permutation is the most straightforward way to get the same fingerprint.
    // If p is a palindrome, p_i = p_{n-1-i}. This means p_1 = p_n, p_2 = p_{n-1}, etc.
    // For a permutation, all elements are distinct.
    // So, p_1 = p_n implies p_1 is the only element equal to p_n.
    // This can only happen if n=1, but n >= 2.
    // Thus, p_1 != p_n for any permutation of length n >= 2.
    // Therefore, p is never a palindrome.
    // So, reversing p always yields a different permutation p'.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

