#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Find the pile with the minimum number of candies.
    // This pile will be used as the source for copying.
    // We want to keep this pile's value small to maximize operations.
    long long min_val = a[0];
    int min_idx = 0;
    for (int i = 1; i < n; ++i) {
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long total_spells = 0;

    // Iterate through all other piles (j != min_idx)
    // and add candies from the minimum pile (min_idx) to them.
    for (int j = 0; j < n; ++j) {
        if (j == min_idx) {
            continue; // Cannot copy a pile to itself
        }

        // Current candies in pile j
        long long current_j_candies = a[j];

        // Candies in the minimum pile
        long long source_candies = a[min_idx];

        // Calculate how many times we can add source_candies to current_j_candies
        // without exceeding k.
        // We need current_j_candies + count * source_candies <= k
        // count * source_candies <= k - current_j_candies
        // count <= (k - current_j_candies) / source_candies

        // If source_candies is 0, this logic needs care, but problem constraints say 1 <= a_i.
        // If current_j_candies is already >= k, we can't add anything.
        if (current_j_candies >= k) {
            continue;
        }

        long long remaining_capacity = k - current_j_candies;
        long long spells_for_this_pile = remaining_capacity / source_candies;

        total_spells += spells_for_this_pile;
    }

    std::cout << total_spells << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

