            // Option 1: +1, +2 (2 presses)
            // Option 2: +1, +1, +1 (3 presses) -> not better
            // Option 3: -5, +2, +2, +2, +2 (5 presses) -> not better
            // So, for diff=3, 2 presses (+1, +2) is optimal.
            ans += 2;
        } else if (diff == 4) {
            // Need to make 4.
            // Option 1: +2, +2 (2 presses)
            // Option 2: +1, +1, +2 (3 presses) -> not better
            // Option 3: +1, +1, +1, +1 (4 presses) -> not better
            // Option 4: +5, -1 (2 presses)
            // Both (2,2) and (5,-1) take 2 presses.
            ans += 2;
        }

        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i; // 0-indexed pile_idx
        long long distance = pile_idx; // distance from pile 0 (pile 1 in problem statement)

        if (d == 0) {
            break; // No more days left
        }

        if (a[i] > 0) {
            // Calculate how many haybales can be moved from pile i
            // Each haybale costs 'distance' days
            long long haybales_to_move = a[i];
            long long days_needed_per_haybale = distance;

            if (days_needed_per_haybale == 0) { // Should not happen for i > 0
                current_a1 += haybales_to_move;
                a[i] = 0;
                continue;
            }

            long long max_haybales_possible_with_days = d / days_needed_per_haybale;

            long long actual_haybales_moved = std::min(haybales_to_move, max_haybales_possible_with_days);

            current_a1 += actual_haybales_moved;
            d -= actual_haybales_moved * days_needed_per_haybale;
            // a[i] -= actual_haybales_moved; // Not strictly necessary to update a[i] as we only care about a[0]
        }
    }

    std::cout << current_a1 << std::endl;
}

