void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only numbers up to 2048 are relevant
            counts[s_val]++;
        }
    }

    // Simulate the merging process
    // Start from the smallest power of two and merge upwards
    // We only care about powers of two up to 1024, as 2048 is the target.
    // If we have 2048 initially, we win.
    // If we form 2048, we win.

    // Iterate through powers of two from 1 up to 1024
    for (int p = 1; p < 2048; p *= 2) {
        if (counts[p] >= 2) {
            // If we have two 'p's, we can merge them into one '2p'
            // Add the resulting '2p' to our counts
            counts[2 * p] += counts[p] / 2;
        }
    }

    // After all possible merges, check if we have 2048
    if (counts[2048] > 0) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

