#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position.
        // The flags `has_one` and `has_minus_one` are updated based on a[i] *before* it's potentially changed.
        // However, for the logic, we need to know if a 1 or -1 *existed at an earlier index* to modify the current index.
        // The flags `has_one` and `has_minus_one` are correctly updated for elements *up to* index i-1.
        // The current element a[i] itself can be 1 or -1, but it can only affect elements j > i.
        // So, the flags should reflect elements a[0]...a[i-1].
        // The loop structure naturally handles this: `has_one` and `has_minus_one` are true if any `a[k]` for `k < i` was 1 or -1 respectively.
    }

    std::cout << "YES\n";
}

