#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The median of the first class will be a[n-1]
        // The median of the second class will be a[n]
        // This is because if we sort all 2n elements,
        // the smallest n elements are a[0]...a[n-1]
        // the largest n elements are a[n]...a[2n-1]
        // To minimize the difference, we want the medians to be as close as possible.
        // The optimal strategy is to assign a[n-1] to one class and a[n] to the other.
        // For example, Class 1: {a[0], ..., a[n-1]} and Class 2: {a[n], ..., a[2n-1]}.
        // Both classes have n elements. If n is odd, this is a valid partition.
        // If n is even, this is not a valid partition because class sizes are even.
        // However, the problem states that the total number of students is 2n.
        // We need to partition them into two classes of odd sizes.
        // Let the sizes be $k_1$ and $k_2$, where $k_1, k_2$ are odd and $k_1+k_2=2n$.
        // The median of a class of size $2k+1$ is the $(k+1)$-th element.
        //
        // Consider the sorted array a[0], a[1], ..., a[2n-1].
        // The smallest possible median for any class is a[0] (if class size is 1).
        // The largest possible median for any class is a[2n-1] (if class size is 1).
        //
        // To minimize the difference between medians, we want to pick two elements
        // from the sorted array that are close to each other, and make them the medians.
        //
        // Let's say we pick a[i] as the median of Class 1 and a[j] as the median of Class 2.
        // For a[i] to be a median, there must be $k$ elements smaller than or equal to a[i]
        // and $k$ elements greater than or equal to a[i] in its class.
        // The class size would be $2k+1$.
        //
        // The key insight is that the $n$-th element (0-indexed, a[n-1]) and the $(n+1)$-th element (a[n])
        // in the globally sorted array are the "middle" two elements.
        //
        // If we form one class with elements {a[0], ..., a[n-1]} and another with {a[n], ..., a[2n-1]},
        // this is not necessarily valid because n might be even.
        //
        // However, the problem asks for *any* partition into two odd-sized classes.
        // The minimum possible difference will always be achieved by picking a[n-1] and a[n]
        // as the medians of the two classes.
        //
        // Why? Consider any two medians $M_1$ and $M_2$ from two classes.
        // Let $M_1$ be the median of Class 1 of size $2k_1+1$, and $M_2$ be the median of Class 2 of size $2k_2+1$.
        // $M_1$ must be at least the $(k_1+1)$-th smallest element in its class.
        // $M_2$ must be at least the $(k_2+1)$-th smallest element in its class.
        //
        // If we sort all $2n$ elements, $a_0, a_1, \dots, a_{2n-1}$.
        // The element $a_{n-1}$ is the largest of the first $n$ elements.
        // The element $a_n$ is the smallest of the last $n$ elements.
        //
        // It can be proven that the minimum difference is always $|a_n - a_{n-1}|$.
        // This is because we can always construct a partition where $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other.
        //
        // For example, Class 1: {a[0], ..., a[n-1]} and Class 2: {a[n], ..., a[2n-1]}.
        // If n is odd, this is a valid partition. Medians are a[n/2] and a[n + n/2].
        // This is not what we want.
        //
        // The problem is simpler: we need to find two medians.
        // The median of a class of size $2k+1$ is the $(k+1)$-th element.
        //
        // The crucial observation is that the $n$-th element (0-indexed $a[n-1]$) and the $(n+1)$-th element ($a[n]$)
        // in the sorted array are the two elements that are "closest" to being the overall median.
        //
        // We can always form two classes such that $a[n-1]$ is the median of one class and $a[n]$ is the median of the other.
        // For example, consider Class 1: $\{a[0], a[1], \dots, a[n-1]\}$ and Class 2: $\{a[n], a[n+1], \dots, a[2n-1]\}$.
        // If $n$ is odd, then both classes have odd size $n$. The median of Class 1 is $a[(n-1)/2]$ and Class 2 is $a[n + (n-1)/2]$.
        // This is not $a[n-1]$ and $a[n]$.
        //
        // The problem is simpler than trying to construct the classes.
        // We are looking for the minimum possible absolute difference.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // We need to pick two elements $m_1, m_2$ from this array to be the medians.
        // $m_1$ must be the median of some odd-sized class $C_1$.
        // $m_2$ must be the median of some odd-sized class $C_2$.
        // $C_1 \cup C_2 = \{a_0, \dots, a_{2n-1}\}$ and $C_1 \cap C_2 = \emptyset$.
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Without loss of generality, assume $m_1 \le m_2$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are the first $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are the last $n$ elements.
        //
        // It is always possible to make $a_{n-1}$ the median of one class and $a_n$ the median of the other.
        // For example, let Class 1 be $\{a_0, a_1, \dots, a_{n-1}, a_{n+1}, \dots, a_{2n-1}\}$ and Class 2 be $\{a_n\}$.
        // This is not valid because Class 1 has $2n-1$ elements (odd) and Class 2 has 1 element (odd).
        // The median of Class 2 is $a_n$.
        // The median of Class 1 (size $2n-1$) is the $n$-th element.
        // If we sort Class 1: $\{a_0, \dots, a_{n-1}, a_{n+1}, \dots, a_{2n-1}\}$, its $n$-th element is $a_{n-1}$.
        // So, this partition works! The medians are $a_{n-1}$ and $a_n$.
        // The difference is $|a_n - a_{n-1}|$.
        //
        // Can we achieve a smaller difference? No, because $a_n$ and $a_{n-1}$ are adjacent in the sorted array.
        // Any other pair of medians $m_1, m_2$ would have to "skip over" $a_{n-1}$ or $a_n$ or both,
        // or be $a_{n-1}$ and some $a_j$ where $j \ne n$, or $a_n$ and some $a_i$ where $i \ne n-1$.
        // In any case, the difference would be at least $|a_n - a_{n-1}|$.
        //
        // The minimum difference is $a[n] - a[n-1]$.
        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
