#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // This is because if p[i] were n-1, then there would be no value n
        // to be the other element in the min operation that results in n-1.
        // More formally, if max_val_in_row = k, and p[i] = k, then for some j, min(k, p[j]) = k.
        // This implies p[j] >= k.
        // If k is the largest value in the permutation (n), then p[i] must be n.
        // If k is not n, then p[i] could be k or n.
        // The problem guarantees a solution exists.
        // The strategy is to assign p[i] = max_val_in_row if max_val_in_row < n.
        // If max_val_in_row is n-1, then p[i] must be n.
        // This is because if p[i] was n-1, then all other p[j] would have to be >= n-1.
        // But there is only one value n in the permutation.
        // So if max_val_in_row is n-1, p[i] must be n.
        // Otherwise, p[i] = max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
