                // it means the frog can jump right from cell i+1.
                // The distance from the last 'R' cell (or cell 0) to this 'R' cell is (i+1) - (last_r_pos + 1).
                // Or simply, the distance from last_r_pos to i+1.
                max_dist = std::max(max_dist, (i + 1) - (last_r_pos + 1) + 1);
                last_r_pos = i;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // (or cell 0 if no 'R's were found) to the target cell n+1.
        // The distance is (n+1) - (last_r_pos + 1).
        max_dist = std::max(max_dist, (n + 1) - (last_r_pos + 1) + 1);

        std::cout << max_dist << "\n";
    }
    return 0;
}

