int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' is limited by three factors:
        // 1. The number of coders: k <= c
        // 2. The number of mathematicians: k <= m
        // 3. The total number of students: 3k <= c + m + x  =>  k <= (c + m + x) / 3
        //
        // So, k <= min(c, m, (c + m + x) / 3).
        // Let's prove this is sufficient.
        // Suppose we want to form 'k' teams, where k = min(c, m, (c + m + x) / 3).
        // We need 'k' coders and 'k' mathematicians.
        // Since k <= c and k <= m, we have enough coders and mathematicians.
        // After assigning one coder and one mathematician to each of the 'k' teams,
        // we have used 'k' coders and 'k' mathematicians.
        // The remaining students are:
        // c' = c - k
        // m' = m - k
        // x' = x
        //
        // Each team needs 3 members. We've assigned 2 members (1 coder, 1 mathematician) to each team.
        // So, each of the 'k' teams still needs 1 more member.
        // The total number of remaining students available to fill these 'k' spots is c' + m' + x'.
        //
        // We need to show that c' + m' + x' >= k.
        // Substitute c' and m':
        // (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        //
        // This inequality (c + m + x >= 3k) is true by our definition of k,
        // because k is chosen such that k <= (c + m + x) / 3, which implies 3k <= c + m + x.
        //
        // Therefore, the maximum number of teams is indeed min(c, m, (c + m + x) / 3).

        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

