    // This will not introduce new distinct differences if k >= 1.
    // If k=0 was allowed, this would be 1,2,...,n. But k >= 1.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
