void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the number 1 is always beautiful.
    // The subsegment is just [1] at pos[1].
    result[0] = '1';

    // Initialize current_min_idx and current_max_idx with the position of 1
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Get the position of the current number m
        int m_pos = pos[m];

        // Update the overall minimum and maximum indices seen so far
        // for numbers 1 to m.
        current_min_idx = std::min(current_min_idx, m_pos);
        current_max_idx = std::max(current_max_idx, m_pos);

        // The length of the subsegment containing all numbers from 1 to m
        // (and potentially other numbers) is current_max_idx - current_min_idx + 1.
        // If this length is exactly m, it means the subsegment
        // p[current_min_idx ... current_max_idx] contains exactly the numbers
        // 1, 2, ..., m (because it has length m, and contains min 1 and max m,
        // and all numbers are distinct).
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << std::endl;
}

