#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate minimum possible values for the left increasing part
    // a_i' >= i
    // a_i' >= a_i (original value)
    // So, a_i' >= max(i, a_i)
    // But we can decrease a_i. So we need a_i >= i for a_i' to be i.
    // If a_i < i, we cannot make a_i' = i.
    // The condition is that we can make a_i' = i.
    // This is possible if original a_i >= i.
    // If a_i < i, then it's impossible to make a_i' = i.
    // More precisely, we need a_i >= i for the sequence 0, 1, ..., i-1, i.
    // If a_i < i, then we cannot achieve a value of i for a_i.
    // So, we need to check if a_i >= i for all i from 0 to k-1.
    // This means a_0 >= 0, a_1 >= 1, ..., a_{k-1} >= k-1.
    // Let's find the maximum prefix length `left_len` such that a_i >= i for all i in [0, left_len-1].
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len++;
        } else {
            break;
        }
    }

    // Calculate minimum possible values for the right decreasing part
    // a_i' >= n-1-i
    // This means a_i' >= a_i (original value)
    // So, a_i' >= max(n-1-i, a_i)
    // Similar to the left part, we need a_i >= n-1-i for a_i' to be n-1-i.
    // Let's find the maximum suffix length `right_len` such that a_i >= n-1-i for all i in [n-right_len, n-1].
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_len++;
        } else {
            break;
        }
    }

    // If there is any k such that 1 <= k <= n, then the peak can be at index k-1 (0-indexed).
    // The left part is a_0 < a_1 < ... < a_{k-1}.
    // The right part is a_{k-1} > a_k > ... > a_{n-1}.
    // This means the peak element a_{k-1} must satisfy both conditions.
    // For the left part, a_{k-1} must be at least k-1.
    // For the right part, a_{k-1} must be at least n-k.
    // So, we need to find if there is an index `i` (0-indexed) such that:
    // 1. `i` is part of the valid left prefix (i.e., `i < left_len`)
    // 2. `i` is part of the valid right suffix (i.e., `i >= n - right_len`)
    // This is equivalent to checking if `left_len + right_len > n`.
    // If `left_len + right_len > n`, it means there is an overlap of indices that can serve as a peak.
    // For example, if n=5, left_len=3, right_len=3.
    // Left valid indices: 0, 1, 2.
    // Right valid indices: 2, 3, 4.
    // Overlap at index 2. This index can be the peak.
    // The condition `left_len + right_len > n` means that the union of the two valid ranges covers all indices,
    // and there's at least one index that is in both ranges.
    // The indices that satisfy the left condition are [0, left_len-1].
    // The indices that satisfy the right condition are [n-right_len, n-1].
    // We need to find if there's an `i` such that `0 <= i < left_len` AND `n-right_len <= i < n`.
    // This means `n-right_len < left_len`.
    // Or `left_len + right_len > n`.

    if (left_len + right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

