    }

    std::vector<Element> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(A.begin(), A.end(), compareElements);

    // Sort B in descending order
    std::sort(B.begin(), B.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    std::vector<long long> result(m);
    for (int i = 0; i < m; ++i) {
        // A[i].value is the i-th smallest value from original A
        // B[i].value is the i-th largest value from original B
        // We want to assign A[i].value to the position corresponding to B[i].original_index
        result[B[i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
