                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1 && n / 2 > 1) { // N/2 is odd and > 1
                    // If Chanek takes N/2, opponent gets an odd number (N/2)
                    // and will take 1. Then Chanek gets an even number (N/2 - 1).
                    // If Chanek takes 1, opponent gets an odd number (N-1).
                    // This is the tricky part.
                    // If N/2 is odd, taking N/2 leaves N/2 for opponent.
                    // Opponent will take 1, leaving N/2-1.
                    // If Chanek takes 1, leaves N-1 for opponent.
                    // N-1 is odd. Opponent takes 1, leaves N-2.
                    // The optimal strategy for Chanek when N is even and N/2 is odd
                    // is to take 1. This leaves N-1 (odd) for the opponent.
                    // The opponent will take 1, leaving N-2 (even).
                    // This ensures Chanek gets an even number on his next turn,
                    // or forces opponent to take 1.
                    chanek_coins += 1;
                    n -= 1;
                } else { // N/2 is even or N/2 is 1 (which means N=2)
                    // If N/2 is even, taking N/2 leaves an even number for opponent.
                    // Opponent will take N/4. This is good for Chanek.
                    // If N=2, N/2=1. Chanek takes 1.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 4) { // Opponent also plays optimally, so for N=4, they take 1
                    n -= 1;
                } else if ((n / 2) % 2 == 1 && n / 2 > 1) { // N/2 is odd and > 1
                    n -= 1;
                } else { // N/2 is even or N/2 is 1 (N=2)
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

