void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want to find b1, b2, b3 such that:
    // (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)

    // Strategy: Append at most 3 elements.
    // We can always make it good by appending 2 or 3 elements.
    // Let's try to append two elements: X and current_sum.
    // New sum = current_sum + X + current_sum = 2 * current_sum + X
    // New XOR sum = current_xor_sum ^ X ^ current_sum
    // We want: 2 * current_sum + X = 2 * (current_xor_sum ^ X ^ current_sum)

    // A simpler strategy that always works with 2 elements:
    // Let the current sum be S and current XOR sum be X.
    // We want to add elements b1, b2 such that:
    // S + b1 + b2 = 2 * (X ^ b1 ^ b2)
    //
    // Consider adding b1 = X.
    // Then the new XOR sum becomes X ^ X = 0.
    // The equation becomes S + X + b2 = 2 * (0 ^ b2) = 2 * b2.
    // S + X + b2 = 2 * b2
    // S + X = b2
    // So, if we add b1 = X and b2 = S + X, the array becomes good.
    //
    // Let's verify:
    // New sum S' = S + X + (S + X) = 2S + 2X
    // New XOR sum X' = X ^ X ^ (S + X) = S + X
    // Is S' = 2 * X'?
    // 2S + 2X = 2 * (S + X)
    // Yes, it is.

    // The problem states we can append at most 3 elements.
    // The strategy above appends 2 elements: current_xor_sum and (current_sum + current_xor_sum).
    // These values can be large, but within long long limits (up to 10^18).
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So current_sum + current_xor_sum is well within 10^18.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

