void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // If s_i is 0, then both w_{i-x} and w_{i+x} must be 0.
    // We use 0-based indexing for strings.
    // s_i corresponds to s[i], w_j corresponds to w[j].
    // The problem statement uses 1-based indexing for s_i, w_j.
    // s_i (1-based) -> s[i-1] (0-based)
    // w_{i-x} (1-based) -> w[i-x-1] (0-based)
    // w_{i+x} (1-based) -> w[i+x-1] (0-based)

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then w[i-x] (if exists) must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            // And w[i+x] (if exists) must be '0'
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // Construct a candidate s_prime from w.
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            s_prime[i] = '1';
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            s_prime[i] = '1';
        }
    }

    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

