}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right side

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add bonus energy if there's an imbalance
        if (i > j) { // More items from left than right
            // The difference is i - j.
            // If i - j = 1, the last item taken must have been from the left.
            // No extra cost for the last item.
            // If i - j >= 2, then at least (i - j - 1) items were taken from the left
            // consecutively after the right items ran out.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // The difference is j - i.
            // If j - i = 1, the last item taken must have been from the right.
            // No extra cost for the last item.
            // If j - i >= 2, then at least (j - i - 1) items were taken from the right
            // consecutively after the left items ran out.
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

