        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively -infinity
        long long max_x = 2000000000LL;  // Effectively +infinity
        long long min_y = -2000000000LL; // Effectively -infinity
        long long max_y = 2000000000LL;  // Effectively +infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
