// Function to find prime factors of a number
// Returns a vector of pairs {prime, exponent}
std::vector<std::pair<long long, int>> prime_factorize(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest divisor x of p such that x is not divisible by q.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // For x to not be divisible by q, there must be at least one prime factor fi of q
        // such that the exponent of fi in x is less than the exponent of fi in q.
        // We want to maximize x.
        // To do this, we iterate through each prime factor fi of q.
        // For each fi, we find the largest divisor of p that is not divisible by fi^ai (where ai is the exponent of fi in q).
        // This largest divisor will be p / (fi^k) where fi^k is the smallest power of fi such that p / (fi^k) is not divisible by fi^ai.
        // More simply, we want to remove just enough factors of fi from p such that the resulting number is no longer divisible by fi^ai.
        // The largest such number would be p / (fi^(exponent_of_fi_in_p - exponent_of_fi_in_q + 1)).
        // We take the maximum of these values over all prime factors fi of q.

        std::vector<std::pair<long long, int>> q_factors = prime_factorize(q);
        long long max_x = 1;

        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            int a = factor_pair.second; // exponent of f in q

            long long current_p = p;
            long long temp_x = p;

            // Count exponent of f in p
            int p_f_exponent = 0;
            while (current_p > 0 && current_p % f == 0) {
                current_p /= f;
                p_f_exponent++;
            }

            // If p_f_exponent < a, then p is not divisible by f^a, so p is not divisible by q.
            // This case is already handled by `if (p % q != 0)`.
            // So we know p_f_exponent >= a.
            // We need to remove enough factors of f from p such that the resulting number is not divisible by f^a.
            // The smallest number of factors of f to remove is (p_f_exponent - a + 1).
            // This means we divide p by f^(p_f_exponent - a + 1).

            long long divisor_power_of_f = 1;
            for (int i = 0; i < (p_f_exponent - a + 1); ++i) {
                divisor_power_of_f *= f;
            }
            temp_x = p / divisor_power_of_f;
            max_x = std::max(max_x, temp_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> used_in_layout;
    char start_char = '\0';

    // Find a starting character for the layout.
    // It should be a character that appears in the password and has only one neighbor.
    // If all characters in the password have two neighbors, pick any character from the password.
    // If the password has only one character, pick that one.
    if (s.length() == 1) {
        start_char = s[0];
    } else {
        for (const auto& pair : adj) {
            if (pair.second.size() == 1) {
                start_char = pair.first;
                break;
            }
        }
        if (start_char == '\0') { // All characters in password have 2 neighbors (cycle or single path with >2 chars)
            start_char = s[0]; // Pick any character from the password
        }
    }

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // Sentinel for the first step

        while (used_in_layout.find(current_char) == used_in_layout.end()) {
            layout += current_char;
            used_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
            if (current_char == '\0' && adj[prev_char].size() == 2) {
                // This means we've formed a cycle and current_char is the start_char again.
                // We should break here to avoid infinite loop and not add start_char again.
                // This case is handled by used_in_layout.find(current_char) == used_in_layout.end()
                // if current_char is start_char.
                // If current_char is '\0' and adj[prev_char].size() == 2, it means we've exhausted
                // the path and prev_char had two neighbors, one of which was the previous char in the path.
                // The other neighbor must have been the one we just added, meaning we've completed a cycle.
                // This is fine, we just stop.
                break;
            }
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (used_in_layout.find(c) == used_in_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

