    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: sum_r = (b-1) * b / 2
    // This is (b-1) * b * inv(2) mod MOD
    long long sum_r_term;
    if (b == 1) { // If b=1, then r must be 0, but r must be != 0. So no nice integers.
                  // The loop for r goes from 1 to b-1. If b=1, b-1=0, so sum is 0.
        sum_r_term = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long b_val = b;

        // Calculate (b-1) * b
        long long product_b_terms = (b_minus_1 % MOD * (b_val % MOD)) % MOD;

        // Calculate inv(2) mod MOD. Since MOD is prime (10^9+7), inv(2) = (MOD+1)/2
        long long inv2 = (MOD + 1) / 2;

        sum_r_term = (product_b_terms * inv2) % MOD;
    }

    // Sum of (k*b + 1) from k=1 to a: sum_k = b * sum(k) + sum(1)
    // sum(k) from 1 to a is a * (a+1) / 2
    // sum(1) from 1 to a is a
    long long sum_k_term;

    // Calculate a * (a+1) / 2
    long long a_val = a;
    long long a_plus_1 = a + 1;
    long long product_a_terms = (a_val % MOD * (a_plus_1 % MOD)) % MOD;
    long long inv2 = (MOD + 1) / 2; // inv2 is already calculated, but for clarity
    long long sum_k_val = (product_a_terms * inv2) % MOD;

    // Calculate b * sum_k_val + a
    sum_k_term = ((b % MOD * sum_k_val) % MOD + (a % MOD)) % MOD;

    // Total sum = sum_r_term * sum_k_term
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string colors(n, ' ');
    bool found_solution = false;

    for (int k = 0; k <= 9; ++k) { // k is the split point digit
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        std::string current_colors(n, ' ');
        bool possible_k = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < k) {
                current_colors[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > k) {
                current_colors[i] = '2';
                s2_digits.push_back(d[i]);
            } else { // d[i] == k
                // Try to assign '1' if possible
                if (!s2_digits.empty() && s2_digits.back() < k) { // This condition is always false if s2_digits.back() is defined and equals k
                    // This branch is unreachable because s2_digits only contains digits > k
                    // If d[i] == k, and we have already placed a digit > k into s2_digits,
                    // then this d[i] must go to s2 to maintain sorted order.
                    // But if we put it in s1, it would violate s1_last <= s2_first.
                    // This logic is flawed. The condition is s1_last <= s2_first.
                    // If d[i] == k, and we put it in s1, then s1_last becomes k.
                    // If we put it in s2, then s2_first becomes k.
                    // The critical point is that if we have already put a digit > k into s2,
                    // then any subsequent k must go into s2.
                    // If we have put a digit < k into s1, then any subsequent k can go into s1.
                    // The decision for d[i] == k depends on the state of s1_digits and s2_digits.
                    // If s1_digits is empty or s1_digits.back() <= k, we can put d[i] into s1.
                    // If s2_digits is empty or s2_digits.back() <= k, we can put d[i] into s2.
                    // The strategy is: if d[i] == k, put it into s2 if s2_digits is not empty and s2_digits.back() == k.
                    // Otherwise, put it into s1. This is to maximize the length of the '1' sequence.
                    // This is the greedy choice for digits equal to k.
                    // If we have already seen a digit > k (meaning s2_digits is not empty),
                    // then any subsequent k must go to s2.
                    // If we haven't seen a digit > k yet, then any k can go to s1.
                    // The split point k means all digits < k go to 1, all digits > k go to 2.
                    // Digits == k are flexible.
                    // We want to put as many k's into color 1 as possible, then switch to color 2.
                    // So, for d[i] == k:
                    // If we have already started s2 (i.e., s2_digits is not empty), then d[i] must go to s2.
                    // Otherwise, d[i] can go to s1.
                    // This is the logic for the "first block of k's go to 1, rest go to 2" strategy.
                    current_colors[i] = '2';
                    s2_digits.push_back(d[i]);
                } else {
                    current_colors[i] = '1';
                    s1_digits.push_back(d[i]);
                }
            }
        }

        // Check if s1_digits is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if s2_digits is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check s1_last <= s2_first
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_k = false;
            }
        }
        if (!possible_k) continue;

        // If we reach here, this k is a valid split point.
        // Now we need to refine the coloring for digits equal to k.
        // All digits < k are '1'. All digits > k are '2'.
        // For digits == k:
        // The first block of k's (before any digit > k is encountered) can be '1'.
        // The remaining k's (after any digit > k is encountered) must be '2'.

        std::string final_colors_for_k(n, ' ');
        bool seen_digit_greater_than_k = false;
        bool current_k_possible = true;

        std::vector<int> final_s1_digits;
        std::vector<int> final_s2_digits;

        for (int i = 0; i < n; ++i) {
            if (d[i] < k) {
                final_colors_for_k[i] = '1';
                final_s1_digits.push_back(d[i]);
            } else if (d[i] > k) {
                final_colors_for_k[i] = '2';
                final_s2_digits.push_back(d[i]);
                seen_digit_greater_than_k = true;
            } else { // d[i] == k
                if (!seen_digit_greater_than_k) {
                    final_colors_for_k[i] = '1';
                    final_s1_digits.push_back(d[i]);
                } else {
                    final_colors_for_k[i] = '2';
                    final_s2_digits.push_back(d[i]);
                }
            }
        }

        // Re-check validity with the refined coloring
        // Check if final_s1_digits is sorted
        for (size_t i = 0; i + 1 < final_s1_digits.size(); ++i) {
            if (final_s1_digits[i] > final_s1_digits[i+1]) {
                current_k_possible = false;
                break;
            }
        }
        if (!current_k_possible) continue;

        // Check if final_s2_digits is sorted
        for (size_t i = 0; i + 1 < final_s2_digits.size(); ++i) {
            if (final_s2_digits[i] > final_s2_digits[i+1]) {
                current_k_possible = false;
                break;
            }
        }
        if (!current_k_possible) continue;

        // Check s1_last <= s2_first
        if (!final_s1_digits.empty() && !final_s2_digits.empty()) {
            if (final_s1_digits.back() > final_s2_digits.front()) {
                current_k_possible = false;
            }
        }
        if (!current_k_possible) continue;

        // If all checks pass, we found a solution
        colors = final_colors_for_k;
        found_solution = true;
        break; // Found one, print and exit
    }

    if (found_solution) {
        std::cout << colors << "\n";
    } else {
        std::cout << "-\n";
    }
}

