    int n = s.length();

    std::vector<std::vector<int>> next_char_pos(n, std::vector<int>(26, -1));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 26; ++j) {
            int current_pos = (i + 1) % n;
            while (current_pos != i) {
                if (s[current_pos] == 'a' + j) {
                    next_char_pos[i][j] = current_pos;
                    break;
                }
                current_pos = (current_pos + 1) % n;
            }
        }
    }

    double total_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char c0 = s[k_actual]; // The first character Vasya sees

        // Group possible k values by their first character s[k]
        // This is not strictly needed for the loop structure, but conceptually it's what Vasya does.
        // Vasya knows c0, so he considers all k' such that s[k'] == c0.

        // For a fixed k_actual, Vasya wants to choose p optimally.
        // He will choose p to maximize the probability of winning for this specific c0.

        // To do this, he needs to evaluate the outcome for each possible p.
        // For each p, he will see t[p] = s[(k_actual + p) % n].
        // Then he checks how many k' (s.t. s[k'] == c0) also satisfy s[(k' + p) % n] == s[(k_actual + p) % n].
        // If only one such k' exists, he wins.

        int max_wins_for_this_k_actual = 0; // Max number of k' that lead to a win for this k_actual

        // Vasya chooses p. He can choose any p from 1 to n-1.
        // The problem states "open one more letter on some position, which Vasya can choose."
        // This implies p can be any index from 0 to n-1.
        // However, t[0] is already known. So p must be different from 0.
        // Thus, p can be from 1 to n-1.
        for (int p = 1; p < n; ++p) {
            char cp = s[(k_actual + p) % n]; // The character Vasya would see at position p

            int current_wins = 0;
            // Now, Vasya checks all k' such that s[k'] == c0.
            // For each such k', if s[(k' + p) % n] == cp, it's a consistent candidate.
            // We need to count how many such k' exist.

            // We can use a map to count occurrences of (s[k'], s[(k'+p)%n]) pairs.
            // Vasya wins if for the observed (c0, cp), there is only one k' that produces it.

            // Let's count how many k' values (where s[k'] == c0) would produce the same (c0, cp) pair.
            // If this count is 1, then Vasya wins for this (k_actual, p) choice.

            // This is equivalent to: for a fixed p, and fixed c0, cp,
            // count how many k' satisfy s[k'] == c0 AND s[(k'+p)%n] == cp.
            // If this count is 1, then k_actual is uniquely determined among those k' that start with c0.

            // We need to count how many k' (0 to n-1) satisfy:
            // 1. s[k'] == c0
            // 2. s[(k' + p) % n] == cp

            // If this count is 1, then Vasya wins for this (k_actual, p) pair.
            // We want to find the maximum number of wins over all possible p.

            int count_consistent_k_prime = 0;
            for (int k_prime = 0; k_prime < n; ++k_prime) {
                if (s[k_prime] == c0 && s[(k_prime + p) % n] == cp) {
                    count_consistent_k_prime++;
                }
            }

            if (count_consistent_k_prime == 1) {
                current_wins = 1; // Vasya wins if k_actual is uniquely determined
            } else {
                current_wins = 0; // Vasya loses if k_actual is not uniquely determined
            }

            max_wins_for_this_k_actual = std::max(max_wins_for_this_k_actual, current_wins);
        }
        total_prob += max_wins_for_this_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / n << std::endl;

    return 0;
}

