int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive 0s ending at i
    // Calculate R[i]: length of consecutive 0s starting at i
    if (a[0] == 0) L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    if (a[n - 1] == 0) R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int current_k = std::min(L[i], R[i]);
            max_k = std::max(max_k, (current_k + 1) / 2);
        }
    }

    std::vector<int> final_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            if (L[i] >= max_k * 2 + 1 && R[i] >= max_k * 2 + 1) {
                // This 0 is part of a stable block of 0s
                // It will remain 0
            } else {
                // This 0 will eventually become 1
                final_a[i] = 1;
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance (strawberry_count - blueberry_count)
    // For type 1 (strawberry), add 1. For type 2 (blueberry), subtract 1.
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // and suffix sums for the right side (jars n+1 to 2n)
    // The balance for a prefix/suffix is (count of 1s - count of 2s)

    // Map to store the minimum number of jars removed from the left
    // to achieve a certain balance.
    // key: balance, value: number of jars removed
    std::map<int, int> left_balances;
    left_balances[0] = 0; // 0 jars removed from left, balance 0

    int current_balance_left = 0;
    for (int i = n - 1; i >= 0; --i) { // Iterate from jar n down to 1
        if (a[i] == 1) {
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        int jars_removed_left = n - i;
        if (left_balances.find(current_balance_left) == left_balances.end()) {
            left_balances[current_balance_left] = jars_removed_left;
        }
    }

    // Calculate minimum jars to remove
    int min_total_removed = 2 * n; // Max possible jars to remove

    // Case 1: No jars removed from the right side (R=0)
    // We need the remaining balance to be 0.
    // This means initial_balance - current_balance_left = 0
    // So, current_balance_left must be equal to initial_balance.
    if (left_balances.count(initial_balance)) {
        min_total_removed = std::min(min_total_removed, left_balances[initial_balance]);
    }

    // Case 2: Iterate through removing jars from the right side (R > 0)
    int current_balance_right = 0;
    for (int i = n; i < 2 * n; ++i) { // Iterate from jar n+1 up to 2n
        if (a[i] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }
        int jars_removed_right = i - n + 1;

        // The target balance for the left side is such that:
        // initial_balance - current_balance_left - current_balance_right = 0
        // current_balance_left = initial_balance - current_balance_right
        int target_balance_left = initial_balance - current_balance_right;

        if (left_balances.count(target_balance_left)) {
            min_total_removed = std::min(min_total_removed, jars_removed_right + left_balances[target_balance_left]);
        }
    }

    std::cout << min_total_removed << std::endl;
}

