    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

struct Operation {
    char type;
    int value;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // We need to track the state of two specific inputs: 0 and 1023 (all bits set).
    // Let's call them current_val_0 and current_val_1023.
    // Initially, current_val_0 = 0 and current_val_1023 = 1023.
    int current_val_0 = 0;
    int current_val_1023 = 1023; // 2^10 - 1

    for (int i = 0; i < n; ++i) {
        char type;
        int x;
        std::cin >> type >> x;

        if (type == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (type == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else { // type == '^'
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    // Now, current_val_0 is the result of applying all operations to input 0.
    // And current_val_1023 is the result of applying all operations to input 1023.

    // We want to find a sequence of at most 5 operations (AND, OR, XOR)
    // that transforms an input `val` into `(val & mask_and) | mask_or ^ mask_xor`.
    // This is equivalent to:
    // For each bit `b`:
    // If `val_b` is 0, output `0_b`.
    // If `val_b` is 1, output `1023_b`.

    // Let's determine the `mask_and`, `mask_or`, `mask_xor` for each bit.
    // For each bit `b` from 0 to 9:
    // Let `f(0)_b` be the `b`-th bit of `current_val_0`.
    // Let `f(1)_b` be the `b`-th bit of `current_val_1023`.

    // Case 1: `f(0)_b = 0` and `f(1)_b = 0`
    // This means `0 -> 0` and `1 -> 0`. The bit `b` is always 0.
    // This can be achieved by `& 0` for this bit.
    // So, `mask_and_b = 0`, `mask_or_b = 0`, `mask_xor_b = 0`.

    // Case 2: `f(0)_b = 0` and `f(1)_b = 1`
    // This means `0 -> 0` and `1 -> 1`. The bit `b` is unchanged.
    // This can be achieved by `& 1` for this bit.
    // So, `mask_and_b = 1`, `mask_or_b = 0`, `mask_xor_b = 0`.

    // Case 3: `f(0)_b = 1` and `f(1)_b = 0`
    // This means `0 -> 1` and `1 -> 0`. The bit `b` is flipped.
    // This can be achieved by `^ 1` for this bit.
    // So, `mask_and_b = 1`, `mask_or_b = 0`, `mask_xor_b = 1`.

    // Case 4: `f(0)_b = 1` and `f(1)_b = 1`
    // This means `0 -> 1` and `1 -> 1`. The bit `b` is always 1.
    // This can be achieved by `| 1` for this bit.
    // So, `mask_and_b = 1`, `mask_or_b = 1`, `mask_xor_b = 0`.

    // Let's construct the final masks.
    int final_and_mask = 1023; // Initialize to all 1s
    int final_or_mask = 0;     // Initialize to all 0s
    int final_xor_mask = 0;    // Initialize to all 0s

    for (int b = 0; b < 10; ++b) {
        int bit_0_result = (current_val_0 >> b) & 1;
        int bit_1023_result = (current_val_1023 >> b) & 1;

        if (bit_0_result == 0 && bit_1023_result == 0) {
            // Case 1: 0 -> 0, 1 -> 0. Bit b is always 0.
            // Achieved by `& 0` for this bit.
            final_and_mask &= ~(1 << b); // Set b-th bit of final_and_mask to 0
            // final_or_mask and final_xor_mask remain 0 for this bit.
        } else if (bit_0_result == 0 && bit_1023_result == 1) {
            // Case 2: 0 -> 0, 1 -> 1. Bit b is unchanged.
            // Achieved by `& 1` for this bit.
            // final_and_mask remains 1 for this bit.
            // final_or_mask and final_xor_mask remain 0 for this bit.
        } else if (bit_0_result == 1 && bit_1023_result == 0) {
            // Case 3: 0 -> 1, 1 -> 0. Bit b is flipped.
            // Achieved by `^ 1` for this bit.
            // final_and_mask remains 1 for this bit.
            // final_or_mask remains 0 for this bit.
            final_xor_mask |= (1 << b); // Set b-th bit of final_xor_mask to 1
        } else { // bit_0_result == 1 && bit_1023_result == 1
            // Case 4: 0 -> 1, 1 -> 1. Bit b is always 1.
            // Achieved by `| 1` for this bit.
            // final_and_mask remains 1 for this bit.
            final_or_mask |= (1 << b); // Set b-th bit of final_or_mask to 1
            // final_xor_mask remains 0 for this bit.
        }
    }

    std::vector<Operation> result_ops;
    if (final_and_mask != 1023) { // If any bit needs to be forced to 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit needs to be forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit needs to be flipped
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.type << " " << op.value << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute positions of '1's
    std::vector<int> ones_pos;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_pos.push_back(i);
        }
    }

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Case 1: s[l] is '0'
        if (s[l] == '0') {
            // Find the first '1' at or after l.
            // If no '1' exists, all subsequent substrings starting with '0' will have value 0.
            // The only good substring would be "0" if its length is 0, which is impossible.
            // So, if s[l] is '0', we need to find the first '1' to form a non-zero value.
            // If there's no '1' after l, then all substrings starting at l are '0's.
            // Their value is 0. Length is always >= 1. So no good substrings.

            // Find the first '1' at or after index l.
            auto it = std::lower_bound(ones_pos.begin(), ones_pos.end(), l);
            if (it == ones_pos.end()) {
                // No '1' found at or after l. All remaining characters are '0'.
                // Substrings like "0", "00", "000" have value 0. Length is >= 1.
                // So, no good substrings can start with '0' if there are no '1's after it.
                continue; 
            }
            int first_one_idx = *it;

            // The substring must contain this '1' to have a non-zero value.
            // The actual binary value starts from this '1'.
            // The length of the substring is r - l + 1.
            // The value is f(s_l...s_r).
            // If s_l...s_r starts with '0's, these are leading zeros.
            // The effective binary string for value calculation starts at first_one_idx.
            // Let k be the number of leading zeros: k = first_one_idx - l.
            // The value of s_l...s_r is f(s_{first_one_idx}...s_r).
            // We need r - l + 1 = f(s_{first_one_idx}...s_r).
            // This means r - l + 1 = (s_{first_one_idx} - '0')*2^(r - first_one_idx) + ... + (s_r - '0')*2^0.
            // The maximum possible length is N. The maximum value is N.
            // The maximum number of bits for N is around 18 (2^17 < 2e5 < 2^18).
            // So, the effective binary string s_{first_one_idx}...s_r can have at most 18 bits.
            // This means r - first_one_idx + 1 <= 18.
            // So, r <= first_one_idx + 17.

            for (int r = first_one_idx; r < std::min(n, first_one_idx + 18); ++r) {
                long long current_val = 0;
                for (int i = first_one_idx; i <= r; ++i) {
                    current_val = current_val * 2 + (s[i] - '0');
                }
                if (current_val == (long long)(r - l + 1)) {
                    good_substrings_count++;
                }
            }
        } else { // Case 2: s[l] is '1'
            long long current_val = 0;
            // The maximum length of a substring is N.
            // The maximum value is N.
            // The maximum number of bits for N is around 18.
            // So, the effective binary string s_l...s_r can have at most 18 bits.
            // This means r - l + 1 <= 18.
            // So, r <= l + 17.
            for (int r = l; r < std::min(n, l + 18); ++r) {
                current_val = current_val * 2 + (s[r] - '0');
                if (current_val == (long long)(r - l + 1)) {
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2: uncomputed, -1: infinite loop
    std::vector<int> dp_x(n + 1, 0);

    for (int i = 1; i <= n; ++i) {
        if (dp_y[i] != -2) continue;

        std::vector<int> path;
        int current_x = i;

        while (current_x >= 1 && current_x <= n && dp_y[current_x] == -2) {
            path.push_back(current_x);
            dp_y[current_x] = -1; // Mark as visited in current path (potential cycle)

            long long val = a[current_x];
            int next_x_val = current_x - val; // This is the x value after one full step (x+val, y+val, then x-val, y+val)

            dp_x[current_x] = next_x_val;
            current_x = next_x_val;
        }

        if (current_x >= 1 && current_x <= n && dp_y[current_x] == -1) { // Cycle detected
            // All nodes in the current path that lead to this cycle are infinite
            for (int node : path) {
                dp_y[node] = -1;
            }
        } else { // Path terminates or leads to an already computed value
            long long final_y_val;
            if (current_x < 1 || current_x > n) { // Terminates out of bounds
                final_y_val = 0; // Base case for termination
            } else { // Leads to an already computed value
                final_y_val = dp_y[current_x];
            }

            // Propagate results back up the path
            for (int j = path.size() - 1; j >= 0; --j) {
                int node = path[j];
                if (final_y_val == -1) {
                    dp_y[node] = -1;
                } else {
                    dp_y[node] = final_y_val + 2 * a[node];
                    final_y_val = dp_y[node];
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        long long initial_a1 = i;
        long long val = initial_a1;
        int x_after_step1 = 1 + val;
        long long y_after_step1 = val;

        if (x_after_step1 < 1 || x_after_step1 > n) {
            std::cout << y_after_step1 << "\n";
        } else {
            long long result_y = dp_y[x_after_step1];
            if (result_y == -1) {
                std::cout << -1 << "\n";
            } else {
                std::cout << y_after_step1 + result_y << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, 0); // b[i] = a_0[i] - initial_min_val
    std::vector<long long> min_val_at_idx(n, std::numeric_limits<long long>::max());

    // Process operations in reverse to find constraints on b[i]
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If a[j] = b[j] + current_delta[j]
            // and we apply a[j] += d, then b[j] + current_delta[j] + d
            // When going backwards, we effectively subtract d from current_delta[j]
            // So, if min_val_at_idx[j] was set based on a future max operation,
            // it was based on b[j] + current_delta[j].
            // Now, current_delta[j] is effectively current_delta[j] - d.
            // So, b[j] + (current_delta[j] - d) must be <= min_val_at_idx[j] - d.
            // This means the constraint on b[j] becomes min_val_at_idx[j] - d.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (min_val_at_idx[j] != std::numeric_limits<long long>::max()) {
                    min_val_at_idx[j] -= ops[i].val;
                }
            }
        } else { // type == 2
            // max(a[l...r]) = m_i
            // This means for all j in [l,r], a[j] <= m_i
            // So, b[j] + current_delta[j] <= m_i
            // This implies b[j] <= m_i - current_delta[j]
            // We update min_val_at_idx[j] with this new upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_val_at_idx[j] = std::min(min_val_at_idx[j], ops[i].val);
            }
        }
    }

    // Initialize b[i] based on the derived constraints
    for (int i = 0; i < n; ++i) {
        if (min_val_at_idx[i] == std::numeric_limits<long long>::max()) {
            b[i] = 0; // No upper bound, can be anything. Choose 0.
        } else {
            b[i] = min_val_at_idx[i]; // Set b[i] to its tightest upper bound
        }
    }

    // Verify the solution
    std::vector<long long> a = b; // a_0 = b
    std::vector<long long> current_delta(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type == 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, a[j] + current_delta[j]);
